-- MÚSICA - 3º ESO (Renacimiento / Barroco)
-- ============================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('musica', 'eso', '{3}', 'El Madrigal Renacentista', 'El madrigal fue una de las formas vocales más importantes del Renacimiento, especialmente en Italia e Inglaterra durante los siglos XV y XVI. Se trata de una composición polifónica, es decir, para varias voces que cantan simultáneamente líneas melódicas distintas, sobre un texto poético en lengua vulgar (no en latín). Los temas solían ser amorosos, pastoriles o reflexivos.

A diferencia de la música religiosa de la época, el madrigal era un género profano, cultivado en las cortes y en las casas de la burguesía. Cantar madrigales en reuniones era una forma de entretenimiento muy valorada, y quienes no sabían leer música se consideraban poco cultos. Los compositores jugaban con el significado del texto mediante recursos como el madrigalismo: pintar musicalmente las palabras, haciendo subir la melodía al decir cielo o descendiendo al decir tierra.

Entre los grandes madrigalistas destacan los italianos Luca Marenzio y Carlo Gesualdo, este último conocido por sus audaces disonancias. En Inglaterra, Thomas Morley y John Dowland adaptaron el género al gusto inglés, incorporando textos de Shakespeare y otros poetas de la época isabelina.', '[{"pregunta":"¿En qué idioma se cantaba el madrigal?","opciones":["Latín","Lengua vulgar","Griego","Hebreo"],"correcta":1},{"pregunta":"¿Qué significa polifónica?","opciones":["Con una sola voz","Varias voces distintas a la vez","Muy aguda","Sin letra"],"correcta":1},{"pregunta":"¿Qué es el madrigalismo?","opciones":["Un instrumento","Pintar musicalmente el texto","Un tipo de coro","Un compositor"],"correcta":1},{"pregunta":"¿Qué compositor inglés destaca en el género?","opciones":["Palestrina","Gesualdo","Thomas Morley","Monteverdi"],"correcta":2}]'::jsonb),

('musica', 'eso', '{3}', 'Palestrina y la Misa Renacentista', 'Giovanni Pierluigi da Palestrina (1525-1594) es una de las figuras más representativas de la música religiosa del Renacimiento. Trabajó en Roma al servicio de varios papas y dedicó su carrera a componer música sacra: misas, motetes e himnos. Se le considera un maestro absoluto de la polifonía renacentista, caracterizada por el equilibrio, la claridad y la fluidez.

En el Concilio de Trento (1545-1563), la Iglesia Católica debatió la reforma de la música litúrgica. Algunos clérigos pedían eliminar la polifonía porque consideraban que complicaba la comprensión del texto sagrado. Según una leyenda, Palestrina compuso su Misa del Papa Marcelo para demostrar que era posible escribir música polifónica donde las palabras se entendieran con claridad. Fuese cierta o no la historia, la misa se convirtió en modelo para toda la música católica posterior.

Palestrina dejó alrededor de 105 misas y cientos de motetes. Su estilo, llamado "stile antico", fue estudiado durante siglos en los conservatorios como modelo de contrapunto vocal. Incluso hoy los estudiantes de composición analizan sus obras para aprender a escribir polifonía.', '[{"pregunta":"¿Dónde trabajó Palestrina?","opciones":["Venecia","Roma","Florencia","París"],"correcta":1},{"pregunta":"¿Qué Concilio revisó la música religiosa?","opciones":["Nicea","Trento","Vaticano I","Constanza"],"correcta":1},{"pregunta":"¿Qué demostró la Misa del Papa Marcelo?","opciones":["Que se podía ser ateo","Que la polifonía permitía entender el texto","Que la ópera era mejor","Que el latín era innecesario"],"correcta":1},{"pregunta":"¿Qué aprendían los estudiantes estudiando su obra?","opciones":["Ópera","Contrapunto vocal","Improvisación","Piano"],"correcta":1}]'::jsonb),

('musica', 'eso', '{3}', 'La Imprenta y la Difusión Musical', 'La invención de la imprenta por Gutenberg a mediados del siglo XV revolucionó la cultura europea y también la música. Hasta entonces, las partituras se copiaban a mano, un trabajo lento y costoso que limitaba enormemente su circulación. Con la imprenta, primero de tipos móviles y después con técnicas específicas para la notación musical, las obras comenzaron a distribuirse por toda Europa a precios mucho más asequibles.

El impresor italiano Ottaviano Petrucci publicó en 1501 el Odhecaton, considerado el primer libro impreso con música polifónica. Utilizó una técnica de triple impresión: una pasada para las líneas del pentagrama, otra para las notas y otra para el texto. Era complicado pero permitió difundir obras de los principales compositores de la época.

Gracias a la imprenta, un músico de Flandes podía estudiar piezas compuestas en Roma, y una familia acomodada podía comprar madrigales italianos para cantar en casa. La música dejó de ser algo limitado a las cortes y los monasterios para convertirse en un bien cultural accesible. Este cambio impulsó el desarrollo de estilos nuevos y la formación de un público aficionado más amplio.', '[{"pregunta":"¿Quién inventó la imprenta?","opciones":["Petrucci","Gutenberg","Palestrina","Bach"],"correcta":1},{"pregunta":"¿Qué obra fue el primer libro con polifonía impresa?","opciones":["La Misa del Papa Marcelo","El Odhecaton","El Clave bien temperado","Las Vísperas"],"correcta":1},{"pregunta":"¿Cuántas pasadas usaba Petrucci?","opciones":["Una","Dos","Tres","Cuatro"],"correcta":2},{"pregunta":"¿Qué efecto tuvo la imprenta en la música?","opciones":["La encareció","Difundió las partituras por Europa","La limitó a la Iglesia","La hizo desaparecer"],"correcta":1}]'::jsonb),

('musica', 'eso', '{3}', 'Las Danzas del Renacimiento', 'En el Renacimiento, la danza era una parte fundamental de la vida cortesana. Los nobles aprendían a bailar desde niños porque saber moverse con elegancia formaba parte de su educación. Existían tratados con las coreografías y la música de cada baile, como el famoso Orchésographie (1589) de Thoinot Arbeau, que describe con detalle numerosas danzas de la época.

Muchas piezas se bailaban en parejas agrupadas. Entre las más populares estaban la pavana, lenta y solemne; la gallarda, más rápida y animada; la zarabanda, de origen español; y la courante, francesa. A menudo se interpretaban por parejas: primero la pavana, majestuosa, y luego la gallarda, contrastante. De esta práctica nacería la suite barroca, una forma instrumental en la que se encadenan varias danzas.

Los instrumentos usados para acompañar las danzas variaban según el contexto. En fiestas al aire libre sonaban grupos de instrumentos de viento potentes, mientras que en salones íntimos se preferían laúdes, violas o claves. La música de danza renacentista es uno de los testimonios más vivos de cómo se divertían las clases altas de la época.', '[{"pregunta":"¿Qué tratado recoge danzas renacentistas?","opciones":["Orchésographie","Il Saggiatore","El libro del buen amor","La Hispalis"],"correcta":0},{"pregunta":"¿Cómo era la pavana?","opciones":["Rápida","Lenta y solemne","Improvisada","Sin música"],"correcta":1},{"pregunta":"¿De qué forma posterior es origen el emparejamiento de danzas?","opciones":["La ópera","La sinfonía","La suite barroca","El cuarteto"],"correcta":2},{"pregunta":"¿Qué instrumentos se usaban en salones íntimos?","opciones":["Trompetas y tambores","Laúdes, violas o claves","Órganos","Solo la voz"],"correcta":1}]'::jsonb),

('musica', 'eso', '{3}', 'El Nacimiento de la Ópera Barroca', 'La ópera es un espectáculo que combina música, canto, teatro y escenografía. Surgió en Florencia a finales del siglo XVI, cuando un grupo de intelectuales llamado Camerata Fiorentina intentó recuperar el espíritu del teatro griego antiguo. Pensaban que los griegos cantaban sus tragedias, y quisieron inventar una forma moderna de drama cantado. Así nació un nuevo género que transformó la música para siempre.

La primera ópera conservada completa es Euridice, de Jacopo Peri, estrenada en 1600. Pero la obra que consolidó el género fue L''Orfeo de Claudio Monteverdi, representada en 1607 en Mantua. Monteverdi supo aprovechar las posibilidades expresivas de las voces y de la orquesta para contar la historia del mítico Orfeo, que desciende al infierno para rescatar a su esposa. Sus innovaciones fueron decisivas.

Con el paso del siglo XVII, la ópera se extendió por Italia y luego por toda Europa. Se abrieron los primeros teatros públicos en Venecia, lo que permitió que cualquier ciudadano pagase una entrada para asistir. La ópera dejó de ser un entretenimiento exclusivo de las cortes para convertirse en un espectáculo popular.', '[{"pregunta":"¿Dónde surgió la ópera?","opciones":["Venecia","Florencia","Roma","Nápoles"],"correcta":1},{"pregunta":"¿Cómo se llamaba el grupo que inventó la ópera?","opciones":["Scuola Veneziana","Camerata Fiorentina","Gruppo Barocco","Accademia"],"correcta":1},{"pregunta":"¿Qué obra consolidó el género?","opciones":["Euridice","L''Orfeo de Monteverdi","La Traviata","Dido y Eneas"],"correcta":1},{"pregunta":"¿Qué permitió la apertura de teatros en Venecia?","opciones":["Que solo la nobleza asistiera","Que el público pagase entrada","Que las obras fueran gratis","Que desapareciera el género"],"correcta":1}]'::jsonb),

('musica', 'eso', '{3}', 'El Bajo Continuo, Invento del Barroco', 'Uno de los grandes cambios que introdujo la música barroca fue el bajo continuo. Se trata de una técnica de acompañamiento formada por una línea de bajo (tocada por un instrumento grave como el violonchelo o el fagot) sobre la cual un instrumento armónico (como el clave o el órgano) improvisa los acordes. El compositor solo escribía la línea del bajo con unos números debajo que indicaban qué acordes debían sonar.

Este sistema, también llamado basso continuo o bajo cifrado, ofrecía libertad al intérprete, que podía variar el acompañamiento según su criterio. Al mismo tiempo, garantizaba la coherencia armónica del conjunto porque el bajo marcaba claramente el rumbo de las notas graves y los acordes. En cierto sentido, es el antecesor lejano del cifrado que hoy usan los guitarristas de música moderna.

El bajo continuo se convirtió en el sonido característico del Barroco. Aparece en cantatas, sonatas, conciertos y óperas durante más de 150 años, hasta que en el Clasicismo fue sustituido por escrituras más completas en las que el compositor detallaba cada nota del acompañamiento, dejando menos margen a la improvisación.', '[{"pregunta":"¿De qué está formado el bajo continuo?","opciones":["Una sola línea melódica","Línea de bajo y un instrumento armónico","Solo percusión","Voz y piano"],"correcta":1},{"pregunta":"¿Qué indicaban los números bajo el bajo?","opciones":["Los compases","Los acordes","El tempo","La dinámica"],"correcta":1},{"pregunta":"¿Qué instrumento armónico es típico del bajo continuo?","opciones":["La trompeta","El clave","El timbal","La flauta"],"correcta":1},{"pregunta":"¿En qué periodo fue sustituido?","opciones":["Renacimiento","Clasicismo","Romanticismo","Siglo XX"],"correcta":1}]'::jsonb),

('musica', 'eso', '{3}', 'El Concierto Barroco y Vivaldi', 'Una de las formas instrumentales más importantes del Barroco es el concierto. Se trata de una obra en la que un instrumento solista (o un grupo pequeño) dialoga con la orquesta, alternando pasajes de diálogo y oposición. Los conciertos barrocos suelen tener tres movimientos: rápido, lento y rápido. Esta estructura se mantendría durante los siglos siguientes.

El compositor veneciano Antonio Vivaldi (1678-1741) fue uno de los maestros absolutos del concierto. Sacerdote y violinista, trabajó durante años en el Ospedale della Pietà de Venecia, un hospicio femenino donde enseñaba música. Allí escribió cientos de conciertos para sus alumnas, que formaban una orquesta admirada por viajeros de toda Europa.

Su obra más conocida es Las cuatro estaciones, un grupo de cuatro conciertos para violín que describen musicalmente la primavera, el verano, el otoño y el invierno. Vivaldi añadió unos sonetos explicativos que guiaban al oyente: cantos de pájaros, tormentas, cosechas, hielo crujiente. Es uno de los ejemplos más famosos de música programática, es decir, música que cuenta una historia sin palabras.', '[{"pregunta":"¿Cuántos movimientos tiene un concierto barroco tipo?","opciones":["Dos","Tres","Cuatro","Cinco"],"correcta":1},{"pregunta":"¿Dónde trabajaba Vivaldi?","opciones":["Catedral de Milán","Ospedale della Pietà","San Marco","Corte de Viena"],"correcta":1},{"pregunta":"¿Qué describe Las cuatro estaciones?","opciones":["Cuatro ciudades","Los momentos del día","La primavera, verano, otoño e invierno","Cuatro amores"],"correcta":2},{"pregunta":"¿Qué es la música programática?","opciones":["Música repetitiva","Música que cuenta una historia","Música improvisada","Música sin melodía"],"correcta":1}]'::jsonb),

('musica', 'eso', '{3}', 'Handel y el Oratorio', 'Georg Friedrich Handel (1685-1759) es uno de los grandes compositores del Barroco, contemporáneo y admirado rival de Bach. Nacido en Alemania, pasó la mayor parte de su vida en Inglaterra, donde se nacionalizó. Durante años triunfó en Londres con óperas italianas, pero cuando el gusto del público cambió, se dedicó a un género nuevo para él: el oratorio.

El oratorio es una obra vocal de gran envergadura similar a la ópera, pero con tema religioso y sin escenografía: los cantantes no actúan, solo interpretan el texto acompañados de coro y orquesta. Handel encontró en el oratorio en inglés una fórmula que el público londinense adoraba. Sus obras narran episodios bíblicos con un poder expresivo y una grandiosidad impresionantes.

Su oratorio más famoso es el Mesías, estrenado en Dublín en 1742. Incluye el celebrado coro del Aleluya, durante el cual es tradición que el público se ponga en pie, costumbre iniciada supuestamente por el rey Jorge II de Inglaterra. El Mesías sigue siendo una de las obras más interpretadas del mundo, especialmente en Navidad y Semana Santa.', '[{"pregunta":"¿Dónde se nacionalizó Handel?","opciones":["Francia","Inglaterra","Italia","España"],"correcta":1},{"pregunta":"¿Qué diferencia al oratorio de la ópera?","opciones":["Tiene decorados","No se canta","Tema religioso y sin escenografía","Solo usa coro"],"correcta":2},{"pregunta":"¿En qué ciudad se estrenó el Mesías?","opciones":["Londres","Dublín","Viena","Roma"],"correcta":1},{"pregunta":"¿Qué tradición acompaña al coro del Aleluya?","opciones":["El público aplaude","El público se pone en pie","Se apagan las luces","Se hace silencio total"],"correcta":1}]'::jsonb),

('musica', 'eso', '{3}', 'La Fuga: Arte de la Polifonía', 'La fuga es una de las formas más complejas y admiradas de la música barroca. Se basa en un procedimiento llamado contrapunto imitativo: una voz presenta un tema, y las demás voces lo van imitando por turnos. El resultado es un entramado en el que varias melodías independientes se entrelazan sin perder unidad ni coherencia.

Una fuga suele empezar con la voz principal exponiendo el tema, llamado sujeto. A continuación entra otra voz con el mismo tema a otra altura, mientras la primera sigue con una contramelodía llamada contrasujeto. Así van entrando el resto de voces, normalmente tres o cuatro. Después hay desarrollos y variaciones en las que el compositor juega con el tema: lo invierte, lo alarga, lo acorta o lo combina consigo mismo.

Johann Sebastian Bach fue el maestro indiscutible de la fuga. Su obra El arte de la fuga, escrita al final de su vida, explora todas las posibilidades del género. También destacan las fugas de su Clave bien temperado, una colección con preludios y fugas en las veinticuatro tonalidades existentes. Son piezas imprescindibles en la formación de cualquier pianista o compositor.', '[{"pregunta":"¿En qué se basa la fuga?","opciones":["En la armonía vertical","En el contrapunto imitativo","En el ritmo puro","En improvisación"],"correcta":1},{"pregunta":"¿Cómo se llama el tema principal?","opciones":["Motivo","Sujeto","Coda","Refrán"],"correcta":1},{"pregunta":"¿Qué obra de Bach explora la fuga al completo?","opciones":["Mesías","Las cuatro estaciones","El arte de la fuga","Pasión según San Mateo"],"correcta":2},{"pregunta":"¿Cuántas tonalidades recorre El clave bien temperado?","opciones":["Doce","Veinticuatro","Seis","Treinta y seis"],"correcta":1}]'::jsonb),

('musica', 'eso', '{3}', 'La Viola da Gamba', 'La viola da gamba fue uno de los instrumentos más apreciados del Renacimiento y el Barroco. Pertenece a la familia de la cuerda frotada, como el violín, pero se diferencia en varios aspectos importantes: tiene seis o siete cuerdas, trastes en el mástil como los de una guitarra, un cuerpo con hombros caídos y se toca sujeta entre las piernas, de donde viene su nombre italiano (gamba significa pierna).

Existían varios tamaños: soprano, alto, tenor y bajo. Cuando tocaban juntas formaban un consort, una especie de conjunto de cámara muy elegante, muy apreciado en las cortes inglesas y francesas. Su sonido, más suave y nasal que el del violín, era considerado noble y aristocrático. Los aficionados cultos aprendían a tocar la viola da gamba como símbolo de refinamiento.

A mediados del siglo XVIII, el auge del violín y la creciente demanda de un sonido más potente y brillante hicieron caer en desuso la viola da gamba. Afortunadamente, durante el siglo XX el interés por la música antigua llevó a muchos músicos a recuperar el instrumento. Hoy podemos escuchar sus obras gracias a intérpretes especializados como Jordi Savall.', '[{"pregunta":"¿Cuántas cuerdas suele tener la viola da gamba?","opciones":["Cuatro","Cinco","Seis o siete","Ocho"],"correcta":2},{"pregunta":"¿Qué significa gamba?","opciones":["Mano","Pierna","Cuello","Barco"],"correcta":1},{"pregunta":"¿Cómo se llamaba el conjunto de violas?","opciones":["Cuarteto","Consort","Banda","Coro"],"correcta":1},{"pregunta":"¿Quién ha sido clave en su recuperación moderna?","opciones":["Placido Domingo","Jordi Savall","Bach","Pavarotti"],"correcta":1}]'::jsonb);

