-- MÚSICA - 4º ESO (Clasicismo, Romanticismo, siglo XX)
-- ============================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('musica', 'eso', '{4}', 'La Sonata Clásica y su Estructura', 'La forma sonata es una de las estructuras más importantes de la música clásica. Se desarrolló en el siglo XVIII y se convirtió en la base del primer movimiento de sinfonías, sonatas para piano, cuartetos de cuerda y muchos conciertos. Su éxito se debe a su equilibrio entre claridad, contraste y desarrollo dramático.

La forma sonata clásica se organiza en tres grandes secciones. La exposición presenta dos temas contrastantes, el primero en la tonalidad principal y el segundo en una tonalidad relacionada. El desarrollo es la sección central: el compositor toma fragmentos de los temas y los transforma, modulando por distintas tonalidades y creando tensión. Por último, la reexposición devuelve los dos temas al principio, ahora ambos en la tonalidad principal, cerrando el círculo.

Compositores como Haydn, Mozart y Beethoven llevaron la forma sonata a su máximo esplendor. Para el oyente atento, reconocer la estructura sonata añade placer a la escucha, porque permite seguir el viaje musical y apreciar cómo el compositor juega con las expectativas antes de resolverlas.', '[{"pregunta":"¿Cuántas secciones principales tiene la forma sonata?","opciones":["Dos","Tres","Cuatro","Cinco"],"correcta":1},{"pregunta":"¿Qué ocurre en el desarrollo?","opciones":["Se presentan los temas","Se transforman y modulan","Se concluye la obra","Se repite todo igual"],"correcta":1},{"pregunta":"¿En qué tonalidad vuelven los temas en la reexposición?","opciones":["En la inicial","En la dominante","En la menor relativa","En una tonalidad nueva"],"correcta":0},{"pregunta":"¿Qué compositores llevaron la forma sonata al máximo?","opciones":["Bach, Handel, Vivaldi","Haydn, Mozart, Beethoven","Chopin, Liszt, Wagner","Debussy, Ravel, Satie"],"correcta":1}]'::jsonb),

('musica', 'eso', '{4}', 'Mozart: Genio Universal', 'Wolfgang Amadeus Mozart (1756-1791) nació en Salzburgo en el seno de una familia musical. Su padre Leopold, violinista y profesor, descubrió pronto su talento excepcional: a los cinco años componía pequeñas piezas y a los seis ya tocaba el clave ante las cortes europeas. Durante su infancia viajó por Francia, Inglaterra, Italia y los Países Bajos, ganando fama de niño prodigio.

Como adulto, Mozart se estableció en Viena, donde trabajó como compositor independiente, algo poco común en su época. Allí compuso óperas inmortales como Las bodas de Fígaro, Don Giovanni y La flauta mágica, además de sinfonías, conciertos, sonatas y música religiosa. Su música combina elegancia clásica con una profunda sensibilidad emocional.

A pesar de su éxito, Mozart murió joven, con solo 35 años, dejando inacabado su famoso Réquiem. Las causas exactas de su muerte siguen siendo objeto de debate. Su legado es inmenso: más de seiscientas obras en apenas tres décadas de actividad. Mozart representa para muchos la cima del equilibrio clásico, un compositor capaz de expresar alegría y tragedia con la misma naturalidad.', '[{"pregunta":"¿Dónde nació Mozart?","opciones":["Viena","Salzburgo","Praga","Múnich"],"correcta":1},{"pregunta":"¿A qué edad empezó a componer?","opciones":["Tres años","Cinco años","Diez años","Quince años"],"correcta":1},{"pregunta":"¿Qué obra religiosa dejó inacabada?","opciones":["Mesías","Réquiem","Pasión","Gloria"],"correcta":1},{"pregunta":"¿Cuántas obras compuso aproximadamente?","opciones":["Cien","Trescientas","Más de seiscientas","Mil"],"correcta":2}]'::jsonb),

('musica', 'eso', '{4}', 'Beethoven: Del Clasicismo al Romanticismo', 'Ludwig van Beethoven (1770-1827) es considerado la figura bisagra entre el Clasicismo y el Romanticismo. Nacido en Bonn, se trasladó joven a Viena, donde estudió con Haydn y pronto destacó como pianista virtuoso. Sus primeras obras respetan los modelos clásicos, pero con una fuerza y ambición que anuncian una nueva época.

Alrededor de los treinta años comenzó a perder audición, un drama terrible para un músico. Lejos de rendirse, Beethoven siguió componiendo obras cada vez más revolucionarias. Su Sinfonía nº 3 (Heroica), dedicada originalmente a Napoleón, marcó un antes y un después: era más larga, más intensa y más personal que cualquier sinfonía anterior. Su Sinfonía nº 9 introdujo un coro en el último movimiento, algo inédito.

Beethoven creía en la música como lenguaje universal capaz de transmitir ideas y emociones profundas. Sus nueve sinfonías, dieciséis cuartetos de cuerda y treinta y dos sonatas para piano forman un legado que cambió para siempre la historia de la música. El himno de la Unión Europea está basado en el tema de la Oda a la alegría, del último movimiento de su Novena Sinfonía.', '[{"pregunta":"¿Dónde nació Beethoven?","opciones":["Viena","Bonn","Hamburgo","Berlín"],"correcta":1},{"pregunta":"¿Qué dificultad padeció?","opciones":["Sordera progresiva","Ceguera","Parálisis","Amnesia"],"correcta":0},{"pregunta":"¿Qué novedad tiene la Sinfonía nº 9?","opciones":["No tiene violín","Introduce un coro","Solo tiene un movimiento","No tiene final"],"correcta":1},{"pregunta":"¿En qué obra se basa el himno de la UE?","opciones":["Sinfonía Heroica","Oda a la alegría","Fur Elise","Claro de Luna"],"correcta":1}]'::jsonb),

('musica', 'eso', '{4}', 'Chopin y el Piano Romántico', 'Frédéric Chopin (1810-1849) es uno de los mayores compositores del Romanticismo y, probablemente, el mayor poeta del piano. Nacido en Polonia de padre francés, a los veinte años se instaló en París, donde pasó el resto de su corta vida. Aunque componía prácticamente solo para piano, consiguió con él una riqueza expresiva que muchos compositores no lograban con una orquesta entera.

Chopin llevó al piano al terreno del canto. Sus melodías, llenas de sentimiento y matices, imitan la respiración de una voz humana. Inventó o popularizó géneros específicos del piano como el nocturno, la balada, la polonesa y la mazurca. Estos dos últimos están inspirados en danzas polacas, reflejando el amor que sentía por su país natal, del que tuvo que exiliarse por motivos políticos.

Salud frágil, Chopin murió de tuberculosis a los treinta y nueve años. Pidió que a su entierro en París sonase el Réquiem de Mozart, y que su corazón fuese llevado a Polonia, donde hoy reposa en una columna de la iglesia de la Santa Cruz en Varsovia. Su obra es repertorio imprescindible para cualquier pianista profesional.', '[{"pregunta":"¿Para qué instrumento compuso casi exclusivamente?","opciones":["Violín","Piano","Guitarra","Flauta"],"correcta":1},{"pregunta":"¿Qué géneros inspirados en Polonia cultivó?","opciones":["Sonata y sinfonía","Polonesa y mazurca","Vals y marcha","Ópera y oratorio"],"correcta":1},{"pregunta":"¿Dónde se instaló?","opciones":["Londres","Roma","París","Viena"],"correcta":2},{"pregunta":"¿Dónde reposa su corazón?","opciones":["París","Varsovia","Viena","Berlín"],"correcta":1}]'::jsonb),

('musica', 'eso', '{4}', 'Wagner y la Ópera Total', 'Richard Wagner (1813-1883) revolucionó la ópera del siglo XIX. Insatisfecho con las convenciones del género, concibió lo que llamó "obra de arte total" (Gesamtkunstwerk), en la que música, poesía, escenografía y actuación formasen una unidad al servicio del drama. Para lograrlo escribió él mismo los libretos de sus óperas, basándose en leyendas germánicas y mitos medievales.

Su obra más ambiciosa es el Anillo del Nibelungo, un ciclo de cuatro óperas (El oro del Rin, La Walkiria, Sigfrido y El ocaso de los dioses) que dura aproximadamente quince horas en total. Wagner tardó veintiséis años en completarlo. Para interpretarlo construyó su propio teatro en Bayreuth, donde desde 1876 se celebra un festival anual dedicado a su obra.

Musicalmente, Wagner desarrolló el leitmotiv: pequeñas ideas musicales asociadas a personajes, objetos o sentimientos, que reaparecen y se transforman a lo largo de la ópera. Esta técnica influyó enormemente en la música posterior, incluyendo las bandas sonoras de cine. John Williams, autor de la música de Star Wars, ha reconocido la influencia directa de Wagner en sus composiciones.', '[{"pregunta":"¿Qué significa Gesamtkunstwerk?","opciones":["Drama divino","Obra de arte total","Gran música","Acción escénica"],"correcta":1},{"pregunta":"¿Cuántas óperas forman el Anillo del Nibelungo?","opciones":["Dos","Tres","Cuatro","Cinco"],"correcta":2},{"pregunta":"¿Qué es un leitmotiv?","opciones":["Un tipo de escenario","Idea musical asociada a algo","Una clave nueva","Un instrumento"],"correcta":1},{"pregunta":"¿Dónde construyó su teatro?","opciones":["Múnich","Leipzig","Bayreuth","Dresde"],"correcta":2}]'::jsonb),

('musica', 'eso', '{4}', 'El Impresionismo de Debussy', 'A finales del siglo XIX y principios del XX, el compositor francés Claude Debussy (1862-1918) inició una corriente conocida como impresionismo musical, emparentada con la pintura impresionista de Monet o Renoir. En lugar de escribir melodías extensas y dramas intensos como los románticos, Debussy buscaba crear atmósferas, sensaciones, colores sonoros que evocaran paisajes, luces, reflejos en el agua.

Para conseguir este efecto, Debussy experimentó con escalas poco habituales, como la pentatónica o la de tonos enteros, y con acordes que no seguían las reglas tradicionales de la armonía. Sus armonías flotan, se suceden sin resolución, creando ambientes ensoñadores. La orquesta la utilizaba como una paleta de pintor, combinando instrumentos con gran delicadeza.

Obras como Preludio a la siesta de un fauno, La mer o Clair de lune muestran este nuevo lenguaje. Debussy nunca aceptó el término impresionismo, al que consideraba limitado, pero la etiqueta se mantuvo. Su influencia en la música del siglo XX fue enorme, abriendo la puerta a nuevas formas de organizar los sonidos y cuestionando las reglas heredadas del Clasicismo y el Romanticismo.', '[{"pregunta":"¿Con qué movimiento pictórico se relaciona Debussy?","opciones":["Cubismo","Impresionismo","Surrealismo","Expresionismo"],"correcta":1},{"pregunta":"¿Qué busca crear en su música?","opciones":["Melodías largas","Atmósferas y colores sonoros","Ritmos marcados","Coros religiosos"],"correcta":1},{"pregunta":"¿Qué escalas utilizó?","opciones":["Solo mayor","Pentatónica y de tonos enteros","Cromática","Menor armónica"],"correcta":1},{"pregunta":"¿Cuál NO es una obra suya?","opciones":["La mer","Clair de lune","Preludio a la siesta de un fauno","El Mesías"],"correcta":3}]'::jsonb),

('musica', 'eso', '{4}', 'Stravinski y La Consagración de la Primavera', 'El 29 de mayo de 1913, el Teatro de los Campos Elíseos de París acogió el estreno de un ballet que revolucionó la música del siglo XX: La consagración de la primavera, del compositor ruso Ígor Stravinski (1882-1971). La obra, con coreografía de Nijinski, retrataba un antiguo ritual pagano eslavo en el que una joven era sacrificada para asegurar buenas cosechas.

La música era profundamente disruptiva: ritmos violentos, acordes disonantes, compases irregulares y una orquestación brutal. El público no estaba preparado para algo tan radical. Durante el estreno estallaron abucheos, gritos e incluso peleas entre espectadores. La policía tuvo que intervenir. La noche pasó a la historia como uno de los mayores escándalos musicales jamás ocurridos.

Con el tiempo, La consagración de la primavera fue reconocida como una obra maestra y un punto de inflexión en la música del siglo XX. Su uso del ritmo como elemento principal, su libertad tonal y su fuerza salvaje influyeron en generaciones enteras de compositores. Hoy se interpreta con frecuencia en salas de concierto, donde ya nadie la encuentra escandalosa, sino admirable.', '[{"pregunta":"¿En qué año se estrenó la obra?","opciones":["1903","1913","1923","1933"],"correcta":1},{"pregunta":"¿En qué ciudad?","opciones":["San Petersburgo","Viena","París","Berlín"],"correcta":2},{"pregunta":"¿Qué reacción provocó?","opciones":["Aplausos unánimes","Escándalo y peleas","Silencio total","Risas"],"correcta":1},{"pregunta":"¿Qué elemento musical destaca sobre todo?","opciones":["La melodía lenta","El ritmo","La armonía clásica","El canto"],"correcta":1}]'::jsonb),

('musica', 'eso', '{4}', 'El Dodecafonismo de Schoenberg', 'Arnold Schoenberg (1874-1951) fue un compositor austríaco que buscó romper con la tonalidad, el sistema que había guiado la música occidental durante siglos. Pensaba que después de Wagner y Mahler la armonía tradicional había llegado a su límite y que era necesario un nuevo método. En los años veinte desarrolló el dodecafonismo o música de doce sonidos.

El método consiste en utilizar las doce notas del sistema temperado de forma igualitaria, sin que ninguna sea más importante que las otras. Para cada obra, el compositor organiza las doce notas en un orden concreto, llamado serie, y la obra se construye a partir de esa serie y sus variaciones (inversión, retrogradación, transposición). Así se evita la sensación de un centro tonal dominante.

El dodecafonismo fue recibido con desconcierto por el público, acostumbrado a las melodías tradicionales. Sin embargo, tuvo enorme influencia en la música del siglo XX. Los alumnos de Schoenberg, Alban Berg y Anton Webern, formaron con él la Segunda Escuela de Viena, un grupo fundamental en la llamada música de vanguardia. Hoy el dodecafonismo es parte esencial de la historia del siglo XX.', '[{"pregunta":"¿Cuántas notas usa el dodecafonismo?","opciones":["Siete","Ocho","Doce","Veinticuatro"],"correcta":2},{"pregunta":"¿Cómo se llama el orden elegido de notas?","opciones":["Escala","Serie","Modo","Acorde"],"correcta":1},{"pregunta":"¿A qué sistema buscaba sustituir?","opciones":["Al ritmo","Al tonal","Al modal","Al rítmico"],"correcta":1},{"pregunta":"¿Quiénes formaban la Segunda Escuela de Viena?","opciones":["Bach, Handel, Vivaldi","Schoenberg, Berg, Webern","Mozart, Haydn, Beethoven","Mahler, Strauss, Bruckner"],"correcta":1}]'::jsonb),

('musica', 'eso', '{4}', 'El Minimalismo Americano', 'Durante los años sesenta del siglo XX surgió en Estados Unidos una corriente llamada minimalismo musical. Como reacción a la complejidad extrema de las vanguardias europeas (dodecafonismo, serialismo), los compositores minimalistas propusieron volver a una música basada en pocos elementos repetidos y transformados lentamente. Buscaban crear un efecto hipnótico, meditativo.

Los pioneros fueron Steve Reich, Philip Glass, Terry Riley y La Monte Young. Steve Reich experimentó con desfases de cintas magnéticas que reproducían el mismo fragmento a velocidades ligeramente distintas. Philip Glass desarrolló un lenguaje basado en arpegios repetitivos con variaciones sutiles, aplicado con gran éxito a óperas como Einstein on the Beach y bandas sonoras de cine.

El minimalismo ha tenido enorme influencia más allá de la música clásica. Muchos artistas de pop, rock electrónico y música de cine han tomado prestadas sus ideas. El fenómeno explica por qué muchos escuchamos hoy música repetitiva sin considerarla aburrida: el minimalismo nos enseñó que la repetición bien construida puede producir intensas experiencias estéticas.', '[{"pregunta":"¿De dónde surge el minimalismo musical?","opciones":["Francia","Alemania","Estados Unidos","Japón"],"correcta":2},{"pregunta":"¿Qué busca crear este estilo?","opciones":["Caos rítmico","Efecto hipnótico con repetición","Armonías disonantes","Melodías largas"],"correcta":1},{"pregunta":"¿Quién compuso Einstein on the Beach?","opciones":["Steve Reich","Philip Glass","Terry Riley","Cage"],"correcta":1},{"pregunta":"¿A qué estilo reaccionaba?","opciones":["Al minimalismo","A las vanguardias europeas","Al romanticismo","Al clasicismo"],"correcta":1}]'::jsonb),

('musica', 'eso', '{4}', 'Los Ritmos Latinos: Clave y Tumbao', 'La música latina moderna (salsa, mambo, cha-cha-chá, son) comparte una base rítmica fundamental: la clave, un patrón de cinco golpes repartidos en dos compases. Este patrón, de origen afrocubano, organiza toda la música alrededor suyo: los instrumentos de percusión, el bajo y las voces se acomodan a la clave. Si un músico no la siente, pierde la referencia.

El bajo en estos estilos sigue un patrón característico llamado tumbao, que no toca el primer tiempo fuerte de cada compás sino que anticipa o atrasa sus notas para generar síncopa. Esta sensación de tropiezo controlado es lo que da al ritmo latino su fuerza bailable. Los timbales, las congas y los bongós completan el tejido rítmico junto al bajo.

En los años cuarenta y cincuenta, músicos como Tito Puente, Machito o Pérez Prado llevaron estos ritmos de Cuba y Puerto Rico a Nueva York, donde se mezclaron con el jazz. El resultado fue un estilo nuevo y explosivo que hoy conocemos como salsa. Desde entonces, la música latina ha influido en prácticamente todos los géneros populares del mundo.', '[{"pregunta":"¿Qué es la clave en música latina?","opciones":["Un instrumento","Un patrón de cinco golpes","Una escala","Un baile"],"correcta":1},{"pregunta":"¿Qué característica tiene el tumbao?","opciones":["No toca el primer tiempo fuerte","Siempre lo toca","Es muy lento","No tiene ritmo"],"correcta":0},{"pregunta":"¿Dónde se mezclaron los ritmos latinos con el jazz?","opciones":["La Habana","Nueva York","Miami","Ciudad de México"],"correcta":1},{"pregunta":"¿Cuál es un músico clave del mambo?","opciones":["Louis Armstrong","Pérez Prado","Chopin","Stravinski"],"correcta":1}]'::jsonb);

