-- PLÁSTICA - 2º ESO (técnicas)
-- ============================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('plastica', 'eso', '{2}', 'La Mediatriz de un Segmento', 'La mediatriz de un segmento es la recta perpendicular que pasa por su punto medio. Todos los puntos de la mediatriz están a la misma distancia de los extremos del segmento, una propiedad muy útil en construcciones geométricas. Para trazarla con regla y compás se coloca la punta del compás en cada extremo del segmento y se dibujan dos arcos del mismo radio que se crucen. La recta que une los dos puntos de cruce es la mediatriz.

Esta construcción es uno de los primeros trazados que se aprenden en dibujo técnico, porque aparece continuamente en ejercicios más complejos. Por ejemplo, se usa para hallar el centro de una circunferencia que pasa por tres puntos dados, o para construir polígonos regulares. Además, dividir un segmento en dos partes iguales es una tarea constante en arquitectura y diseño.

La mediatriz tiene aplicaciones prácticas más allá del dibujo. En ingeniería, por ejemplo, si queremos colocar una antena que dé servicio a dos ciudades equidistantes, su ubicación debe estar sobre la mediatriz del segmento que las une. En matemáticas se estudia su generalización en tres dimensiones: el plano mediatriz.', '[{"pregunta":"¿Qué propiedad tiene todo punto de la mediatriz?","opciones":["Pertenece al segmento","Está a igual distancia de los extremos","Es perpendicular a todo","Es el centro del segmento"],"correcta":1},{"pregunta":"¿Qué instrumentos se usan para trazarla?","opciones":["Solo regla","Solo compás","Regla y compás","Transportador"],"correcta":2},{"pregunta":"¿Para qué se usa en ingeniería?","opciones":["Para colorear","Colocar antenas equidistantes","Medir pesos","Diseñar ropas"],"correcta":1},{"pregunta":"¿Qué pasa con una circunferencia que cruza 3 puntos?","opciones":["No existe","Su centro se halla con mediatrices","Es imposible","Es siempre recta"],"correcta":1}]'::jsonb),

('plastica', 'eso', '{2}', 'El Triángulo y sus Tipos', 'El triángulo es el polígono más simple, formado por tres lados y tres ángulos. A pesar de su sencillez, es una figura fundamental en geometría, arquitectura e ingeniería porque resulta extremadamente estable: a diferencia de los cuadrados o pentágonos, un triángulo de lados fijos no puede deformarse. Por eso las cerchas de los tejados y las estructuras metálicas utilizan sistemáticamente triángulos.

Los triángulos se clasifican de dos maneras. Según sus lados, pueden ser equiláteros (tres lados iguales), isósceles (dos lados iguales) o escalenos (ningún lado igual). Según sus ángulos, se dividen en acutángulos (tres ángulos agudos), rectángulos (un ángulo de 90°) u obtusángulos (un ángulo mayor de 90°). Las combinaciones posibles permiten nombres compuestos como triángulo rectángulo isósceles.

La suma de los ángulos de un triángulo es siempre 180°, una propiedad descubierta por los matemáticos griegos. Esta regla permite calcular un ángulo si conocemos los otros dos. Además, el triángulo rectángulo tiene una propiedad famosa descrita por el teorema de Pitágoras: el cuadrado de la hipotenusa es igual a la suma de los cuadrados de los catetos.', '[{"pregunta":"¿Cuántos grados suman los ángulos de un triángulo?","opciones":["90°","180°","270°","360°"],"correcta":1},{"pregunta":"¿Qué triángulo tiene tres lados iguales?","opciones":["Isósceles","Escaleno","Equilátero","Rectángulo"],"correcta":2},{"pregunta":"¿Por qué son estables los triángulos?","opciones":["Son planos","No pueden deformarse con lados fijos","Son pequeños","Son blancos"],"correcta":1},{"pregunta":"¿Qué teorema se aplica al triángulo rectángulo?","opciones":["De Tales","De Pitágoras","De Euclides","De Euler"],"correcta":1}]'::jsonb),

('plastica', 'eso', '{2}', 'La Escala en el Dibujo Técnico', 'La escala es la relación entre las medidas del dibujo y las medidas reales del objeto representado. Gracias a ella podemos dibujar en un papel objetos enormes, como un edificio, o minúsculos, como un circuito electrónico, conservando sus proporciones. La escala se indica como una fracción o como una razón, por ejemplo 1:100, que significa que un centímetro del dibujo equivale a cien centímetros (un metro) de la realidad.

Existen tres tipos principales de escalas. La escala natural, 1:1, dibuja el objeto al tamaño real; se usa para piezas pequeñas. La escala de reducción, como 1:50 o 1:100, representa el objeto más pequeño que en la realidad y se utiliza para planos de edificios, mapas y urbanismo. La escala de ampliación, como 2:1 o 10:1, agranda el objeto, útil para componentes electrónicos o piezas de relojería.

Para calcular medidas reales a partir de un plano, multiplicamos la medida del dibujo por el denominador de la escala. Por ejemplo, si una pared en un plano 1:50 mide 4 centímetros, en la realidad mide 4×50 = 200 cm, o sea dos metros. Comprender las escalas es fundamental para leer mapas, planos arquitectónicos y maquetas.', '[{"pregunta":"¿Qué significa la escala 1:100?","opciones":["100 veces más grande","1 cm dibujo equivale a 100 cm reales","1 mm vale 100 m","Nada"],"correcta":1},{"pregunta":"¿Qué escala es natural?","opciones":["1:1","1:2","2:1","1:100"],"correcta":0},{"pregunta":"¿Cuándo se usa una escala de ampliación?","opciones":["Para edificios","Para mapas","Para objetos pequeños","Nunca"],"correcta":2},{"pregunta":"Si el dibujo mide 3 cm en 1:50, la realidad mide:","opciones":["50 cm","100 cm","150 cm","300 cm"],"correcta":2}]'::jsonb),

('plastica', 'eso', '{2}', 'El Claroscuro y el Volumen', 'El claroscuro es una técnica artística que consiste en utilizar fuertes contrastes entre luz y sombra para crear sensación de volumen y profundidad en una representación plana. Con solo graduar los tonos, el artista puede transformar un dibujo lineal en una imagen tridimensional que parece salirse del papel. El dominio del claroscuro es una de las habilidades más valoradas del dibujo académico.

Para aplicar el claroscuro se identifica primero la dirección de la luz principal. A partir de ella se distinguen varias zonas: la zona iluminada, donde la luz incide directamente; la zona de sombra propia, en la cara opuesta; la sombra arrojada, proyectada por el objeto sobre el suelo o sobre otros elementos; y la zona de penumbra, transición entre luz y sombra. Cada zona tiene su valor tonal propio.

El claroscuro alcanzó su máximo esplendor en el Barroco, con artistas como Caravaggio o Rembrandt, que utilizaron contrastes extremos para dar dramatismo a sus pinturas. En el estudio del dibujo actual se practica representando objetos simples como esferas, cubos o cilindros bajo una luz focal. Esta práctica entrena la percepción y prepara para enfrentarse a composiciones más complejas.', '[{"pregunta":"¿Qué crea el claroscuro en una imagen plana?","opciones":["Color","Sensación de volumen","Movimiento","Sonido"],"correcta":1},{"pregunta":"¿Cuál es la primera cosa a identificar?","opciones":["El tamaño","La dirección de la luz","El color","El papel"],"correcta":1},{"pregunta":"¿Qué pintor barroco destacó en claroscuro?","opciones":["Van Gogh","Caravaggio","Mondrian","Picasso"],"correcta":1},{"pregunta":"¿Qué es la sombra propia?","opciones":["La del fondo","La de la cara iluminada","La de la cara opuesta a la luz","La del artista"],"correcta":2}]'::jsonb),

('plastica', 'eso', '{2}', 'El Punto de Vista y el Encuadre', 'Cuando observamos o representamos una imagen, la elección del punto de vista y del encuadre determina completamente el mensaje que transmite. El punto de vista es la posición desde la que se mira al sujeto: frontal, lateral, picado (desde arriba) o contrapicado (desde abajo). El encuadre, por su parte, define qué parte del sujeto entra dentro del marco: plano general, plano medio, primer plano, plano detalle.

Cada combinación produce un efecto distinto. Un contrapicado hace que un personaje parezca poderoso y dominante, porque el espectador mira hacia arriba. Un picado, en cambio, lo empequeñece y lo hace parecer vulnerable. Un primer plano acerca al espectador al rostro, generando intimidad, mientras que un plano general sitúa al personaje en un contexto amplio.

En fotografía, cine y cómic, estas decisiones son fundamentales para narrar una historia. Los directores estudian minuciosamente dónde colocar la cámara y qué plano usar en cada escena. Lo mismo ocurre en el dibujo y la pintura: el artista decide qué mostrar, qué ocultar, desde qué ángulo y a qué distancia, porque de ello depende el impacto emocional y narrativo de la obra.', '[{"pregunta":"¿Qué efecto provoca el contrapicado?","opciones":["Empequeñece al personaje","Lo hace parecer poderoso","Lo borra","No afecta"],"correcta":1},{"pregunta":"¿Qué muestra un plano detalle?","opciones":["Todo el cuerpo","El rostro entero","Una parte muy concreta","El paisaje"],"correcta":2},{"pregunta":"¿Qué plano sitúa al personaje en su contexto?","opciones":["Primer plano","Plano detalle","Plano general","Contrapicado"],"correcta":2},{"pregunta":"¿Qué disciplinas usan estos conceptos?","opciones":["Solo pintura","Fotografía, cine y cómic","Solo escultura","Solo música"],"correcta":1}]'::jsonb),

('plastica', 'eso', '{2}', 'La Xilografía: Grabado en Madera', 'La xilografía es una técnica de grabado que consiste en tallar un dibujo sobre una plancha de madera. Las zonas que no deben imprimirse se retiran con una gubia, dejando en relieve las partes que formarán la imagen. Después se entinta la superficie y se presiona contra un papel, transfiriendo la tinta. El resultado puede repetirse varias veces para obtener múltiples copias idénticas.

La xilografía es una de las técnicas de reproducción de imágenes más antiguas: apareció en China hacia el siglo VI y llegó a Europa en el siglo XV, justo antes de la invención de la imprenta. De hecho, los primeros libros impresos incluían ilustraciones xilográficas. Artistas como Alberto Durero llevaron la xilografía a un altísimo nivel durante el Renacimiento, con obras extremadamente detalladas.

En Japón, la xilografía alcanzó una personalidad única con el ukiyo-e, las estampas del mundo flotante que retrataban paisajes, actores y escenas de la vida cotidiana. Artistas como Hokusai y Hiroshige crearon obras inolvidables que, cuando llegaron a Europa en el siglo XIX, influyeron enormemente en los impresionistas y en Van Gogh.', '[{"pregunta":"¿En qué se talla la xilografía?","opciones":["Metal","Madera","Piedra","Vidrio"],"correcta":1},{"pregunta":"¿Dónde se inventó?","opciones":["Europa","Egipto","China","India"],"correcta":2},{"pregunta":"¿Quién elevó la xilografía en el Renacimiento?","opciones":["Durero","Rembrandt","Goya","Rubens"],"correcta":0},{"pregunta":"¿Cómo se llamaba la xilografía japonesa?","opciones":["Manga","Haiku","Ukiyo-e","Kabuki"],"correcta":2}]'::jsonb),

('plastica', 'eso', '{2}', 'La Cerámica y el Modelado', 'La cerámica es una de las técnicas artísticas más antiguas. Consiste en modelar arcilla con las manos o con herramientas y, después, cocerla en un horno a altas temperaturas para endurecerla. La cocción transforma la arcilla blanda en un material duro y resistente. Esta técnica se utiliza desde hace más de veinte mil años y ha sido esencial en todas las civilizaciones.

Existen varios métodos de modelado. El pellizco consiste en partir de una bola de barro y crear una cavidad apretando con los dedos. La técnica del churro utiliza rollos de arcilla apilados para construir piezas de paredes altas. La placa parte de láminas de arcilla aplanadas con un rodillo. Y el torno alfarero permite crear piezas simétricas haciendo girar la arcilla mientras las manos la moldean.

Una vez modelada y seca, la pieza pasa a una primera cocción llamada bizcochado. Después se puede decorar con esmaltes, que son baños vidriados de distintos colores, y se cuece una segunda vez para fijar el esmalte. La cerámica artística y utilitaria es fundamental en la tradición mediterránea; en España destacan regiones como Talavera, Manises o Úbeda por su larga tradición alfarera.', '[{"pregunta":"¿Qué endurece la arcilla?","opciones":["El sol","El agua","La cocción en horno","El frío"],"correcta":2},{"pregunta":"¿Qué método usa rollos de arcilla apilados?","opciones":["Pellizco","Churro","Placa","Torno"],"correcta":1},{"pregunta":"¿Cómo se llama la primera cocción?","opciones":["Esmalte","Bizcochado","Horneado","Endurecido"],"correcta":1},{"pregunta":"¿Qué región española es famosa por cerámica?","opciones":["Galicia","Talavera","Asturias","Navarra"],"correcta":1}]'::jsonb),

('plastica', 'eso', '{2}', 'El Mosaico: Arte de Piezas Pequeñas', 'Un mosaico es una obra compuesta por pequeñas piezas de colores (llamadas teselas) que se colocan una a una sobre una superficie para formar una imagen o un diseño geométrico. Las teselas pueden ser de piedra, cerámica, vidrio o incluso de materiales reciclados. El conjunto funciona como una pintura hecha de fragmentos.

El mosaico fue especialmente cultivado por griegos, romanos y bizantinos. Los romanos decoraban los suelos de sus villas con escenas mitológicas, cacerías y motivos decorativos. Con la caída del imperio, la tradición pasó a Bizancio, donde los mosaicos cubrieron las cúpulas y muros de iglesias como Santa Sofía o San Vital de Rávena, usando fondos dorados que brillaban con la luz de las velas.

En la España medieval destacó el arte mudéjar, con mosaicos geométricos de colores vivos, y en la Barcelona modernista Antoni Gaudí revolucionó la técnica con el trencadís, que utilizaba fragmentos irregulares de cerámica rota. El Parque Güell es uno de los ejemplos más famosos de esta técnica innovadora. Hoy el mosaico sigue usándose tanto en arte como en decoración arquitectónica.', '[{"pregunta":"¿Cómo se llaman las piezas de un mosaico?","opciones":["Baldosas","Teselas","Ladrillos","Fichas"],"correcta":1},{"pregunta":"¿Qué técnica popularizó Gaudí?","opciones":["El fresco","El trencadís","El bajorrelieve","El grabado"],"correcta":1},{"pregunta":"¿En qué iglesia destacan los mosaicos bizantinos?","opciones":["San Pedro","Santa Sofía","Notre Dame","Westminster"],"correcta":1},{"pregunta":"¿Qué usaban los romanos para los suelos?","opciones":["Pintura mural","Mosaicos","Tapices","Alfombras"],"correcta":1}]'::jsonb),

('plastica', 'eso', '{2}', 'El Dibujo Isométrico', 'El dibujo isométrico es un sistema de representación que permite dibujar objetos tridimensionales sobre un plano mostrando tres caras al mismo tiempo: la superior, la frontal y la lateral. Las líneas que representan los ejes X, Y y Z forman ángulos de 120° entre sí, por lo que la vista queda girada y el objeto se ve como desde una esquina elevada.

A diferencia de la perspectiva cónica, el dibujo isométrico no tiene punto de fuga: las líneas paralelas en la realidad siguen siendo paralelas en el dibujo. Esto lo convierte en una representación más técnica que realista, pero muy útil porque permite medir directamente las dimensiones sobre el papel. Por eso se utiliza mucho en ingeniería, diseño industrial y planos de montaje.

El dibujo isométrico también se ha popularizado en videojuegos y en ilustración. Muchos juegos de estrategia como Civilization o Age of Empires usan vistas isométricas porque permiten mostrar mapas amplios con objetos tridimensionales identificables. En ilustraciones infográficas también es habitual porque combina claridad técnica con atractivo visual. Aprender a dibujar en isométrico desarrolla mucho la visión espacial.', '[{"pregunta":"¿Qué ángulo forman los ejes en isométrico?","opciones":["90°","120°","180°","60°"],"correcta":1},{"pregunta":"¿Tiene punto de fuga el isométrico?","opciones":["Sí, uno","Sí, dos","No tiene","Sí, tres"],"correcta":2},{"pregunta":"¿Dónde se usa mucho?","opciones":["Solo pintura","Ingeniería y videojuegos","Solo cine","Solo escultura"],"correcta":1},{"pregunta":"¿Qué ventaja tiene?","opciones":["Permite medir directamente","Es siempre más bonito","Es gratis","No hay que pensar"],"correcta":0}]'::jsonb),

('plastica', 'eso', '{2}', 'Los Tipos de Línea en Dibujo Técnico', 'En dibujo técnico cada tipo de línea tiene un significado preciso y normalizado. Esta codificación es fundamental para que cualquier ingeniero o arquitecto pueda leer un plano en cualquier parte del mundo sin confusiones. Las normas están recogidas en estándares internacionales como las UNE e ISO.

Las líneas gruesas y continuas se utilizan para representar las aristas y los contornos visibles del objeto: son las líneas más evidentes del dibujo. Las líneas discontinuas, formadas por trazos cortos separados, indican las aristas que quedan ocultas detrás de la vista, por ejemplo el borde interno de un agujero. Las líneas finas continuas se usan para trazos auxiliares como líneas de referencia, rayados y cotas.

Las líneas mixtas, que alternan trazos largos y cortos, representan ejes de simetría y ejes de rotación de piezas circulares. Otras líneas especiales, como la de trazo y punto doble, marcan posiciones alternativas o límites de corte. Aprender a reconocer e interpretar estos tipos de línea es una parte esencial de la lectura de planos, y su dominio se practica desde los primeros cursos de dibujo técnico.', '[{"pregunta":"¿Para qué se usa la línea continua gruesa?","opciones":["Aristas ocultas","Aristas visibles","Ejes","Cotas"],"correcta":1},{"pregunta":"¿Qué representan las líneas discontinuas?","opciones":["Lo visible","Aristas ocultas","Los ejes","El color"],"correcta":1},{"pregunta":"¿Qué indican las líneas mixtas?","opciones":["Relleno","Ejes de simetría","Tolerancias","Materiales"],"correcta":1},{"pregunta":"¿Qué normas regulan los tipos de línea?","opciones":["Solo locales","UNE e ISO","Solo UNESCO","Solo nacionales"],"correcta":1}]'::jsonb);

