-- ED. FÍSICA - 1º ESO (calentamiento / deportes)
-- ============================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('ed-fisica', 'eso', '{1}', 'Las Fases del Calentamiento', 'El calentamiento es la preparación del cuerpo antes de realizar un esfuerzo físico importante. Su objetivo es aumentar la temperatura muscular, mejorar la oxigenación, activar el sistema cardiovascular y reducir el riesgo de lesiones. Un calentamiento completo suele durar entre diez y quince minutos y se divide en tres fases claramente diferenciadas.

La primera fase es la activación general. Consiste en realizar una carrera suave o trote de unos cinco minutos, que sirve para aumentar progresivamente el pulso y la temperatura corporal. Durante esta fase también se hacen movimientos articulares de cuello, hombros, caderas, rodillas y tobillos, buscando movilizar todas las articulaciones que participarán en la actividad.

La segunda fase son los estiramientos suaves, que preparan los músculos principales. Se deben mantener cada postura unos quince segundos, sin rebotes ni dolor. Finalmente, la tercera fase es la activación específica: ejercicios que simulan los movimientos del deporte que vamos a practicar. Por ejemplo, antes de jugar un partido de baloncesto haremos botes y lanzamientos suaves, y antes de correr, ejercicios de técnica de carrera. Esta estructura ayuda a que el cuerpo esté listo para el esfuerzo.', '[{"pregunta":"¿Cuánto dura un calentamiento completo?","opciones":["2 minutos","5 minutos","10-15 minutos","30 minutos"],"correcta":2},{"pregunta":"¿Cuál es la primera fase?","opciones":["Estiramientos","Activación general","Específica","Enfriamiento"],"correcta":1},{"pregunta":"¿Cuánto se mantiene un estiramiento suave?","opciones":["2 segundos","15 segundos","1 minuto","5 minutos"],"correcta":1},{"pregunta":"¿Qué sería activación específica antes de baloncesto?","opciones":["Nadar","Botes y lanzamientos suaves","Levantar pesas","Gritar"],"correcta":1}]'::jsonb),

('ed-fisica', 'eso', '{1}', 'El Fútbol: Deporte Global', 'El fútbol es el deporte más popular del mundo. Se juega en prácticamente todos los países y su competición más importante, la Copa del Mundo, reúne cada cuatro años a miles de millones de espectadores. Los orígenes del fútbol moderno se remontan a Inglaterra en el siglo XIX, cuando se codificaron las primeras reglas en 1863 con la fundación de la Football Association en Londres.

Un partido se disputa entre dos equipos de once jugadores, incluyendo al portero. Se juega en un campo rectangular con dos porterías, una en cada extremo. Los jugadores intentan introducir el balón en la portería contraria utilizando principalmente los pies, la cabeza, el pecho y las rodillas; solo el portero puede usar las manos dentro de su área. El partido dura noventa minutos divididos en dos tiempos de cuarenta y cinco.

Las principales posiciones son el portero (defiende la portería), los defensas (protegen su campo), los centrocampistas (controlan el juego) y los delanteros (intentan marcar goles). Además de la técnica individual, el fútbol exige tácticas de equipo: presionar al rival, hacer pases precisos, moverse sin balón para crear espacios. Es un deporte completo que desarrolla resistencia, coordinación y trabajo en equipo.', '[{"pregunta":"¿Cuándo se codificaron las reglas modernas?","opciones":["1800","1863","1900","1950"],"correcta":1},{"pregunta":"¿Cuántos jugadores hay por equipo?","opciones":["Diez","Once","Doce","Trece"],"correcta":1},{"pregunta":"¿Quién puede usar las manos dentro del área?","opciones":["Nadie","El defensa","El portero","El capitán"],"correcta":2},{"pregunta":"¿Cuánto dura cada tiempo?","opciones":["30 minutos","40 minutos","45 minutos","60 minutos"],"correcta":2}]'::jsonb),

('ed-fisica', 'eso', '{1}', 'Los Juegos de Cooperación', 'Los juegos de cooperación son actividades en las que el éxito depende del trabajo conjunto de todos los participantes. A diferencia de los juegos competitivos, donde hay ganadores y perdedores, en los cooperativos el grupo alcanza el objetivo o fracasa unido. Esto los convierte en una herramienta ideal para fomentar valores como la comunicación, el respeto, la empatía y la ayuda mutua.

Existen numerosos ejemplos de juegos cooperativos. El paracaídas grande, donde todos agarran el borde de una tela para hacer ondular y mover objetos colocados encima, es muy popular en primaria y primero de secundaria. Otro clásico es el pañuelo imposible, donde dos equipos deben coordinarse para traspasar un pañuelo sin ser vistos. También están los juegos de confianza, como el trust fall, en el que una persona se deja caer confiando en que sus compañeros la sujetarán.

Los profesores de Educación Física utilizan estas actividades al principio de curso para construir grupo, y también al final de una unidad competitiva para equilibrar el ambiente. Investigaciones pedagógicas han demostrado que los juegos cooperativos mejoran el clima del aula, reducen los conflictos y ayudan a integrar a los alumnos menos hábiles deportivamente, que muchas veces son marginados en los deportes tradicionales.', '[{"pregunta":"¿Qué caracteriza a un juego cooperativo?","opciones":["Competición individual","El grupo gana o pierde unido","Hay un solo ganador","No tiene reglas"],"correcta":1},{"pregunta":"¿Qué valores fomentan estos juegos?","opciones":["Solo velocidad","Comunicación, respeto, empatía","Competitividad","Fuerza"],"correcta":1},{"pregunta":"¿Qué juego usa un paracaídas grande?","opciones":["Trust fall","Pañuelo imposible","Paracaídas grande","Stop"],"correcta":2},{"pregunta":"¿Qué han demostrado las investigaciones?","opciones":["No sirven","Mejoran el clima del aula","Son peligrosos","Son aburridos"],"correcta":1}]'::jsonb),

('ed-fisica', 'eso', '{1}', 'Las Habilidades Motrices Básicas', 'Las habilidades motrices básicas son los movimientos fundamentales que permiten al ser humano desplazarse y manipular objetos. Se desarrollan desde la primera infancia y se clasifican en tres grandes grupos: desplazamientos, saltos y giros; manipulaciones (lanzar, recibir, botar, golpear); y habilidades de equilibrio. El dominio de todas ellas es la base para aprender después cualquier deporte o actividad física más compleja.

Los desplazamientos incluyen caminar, correr, reptar, trepar, gatear o cuadrupedia. Cada uno tiene su utilidad: caminar es el más natural, correr aumenta la velocidad, trepar desarrolla fuerza en brazos y tronco, y reptar mejora la coordinación global. Los saltos se subdividen en verticales (para alcanzar altura) y horizontales (para cubrir distancia), y los giros pueden hacerse sobre los tres ejes del cuerpo.

Las habilidades manipulativas son esenciales para muchos deportes. Lanzar con precisión, recibir con suavidad, botar un balón con una mano o con ambas, o golpear un objeto con el pie o con una raqueta, son acciones que parecen simples pero requieren gran coordinación ojo-mano u ojo-pie. Durante los primeros cursos de la ESO se refuerzan todas estas habilidades a través de juegos variados, porque su dominio se olvida si no se practica regularmente.', '[{"pregunta":"¿Cuántos grupos hay de habilidades básicas?","opciones":["Dos","Tres","Cuatro","Cinco"],"correcta":1},{"pregunta":"¿Qué desarrolla trepar?","opciones":["Velocidad","Fuerza en brazos y tronco","Olfato","Memoria"],"correcta":1},{"pregunta":"¿Qué tipo de salto cubre distancia?","opciones":["Vertical","Horizontal","Rotacional","Lateral"],"correcta":1},{"pregunta":"¿Qué coordinación exigen las manipulaciones?","opciones":["Oído-mano","Ojo-mano u ojo-pie","Olfato-pie","Tacto-oreja"],"correcta":1}]'::jsonb),

('ed-fisica', 'eso', '{1}', 'El Baloncesto: Técnica Básica', 'El baloncesto fue inventado en 1891 por el profesor canadiense James Naismith, que buscaba un deporte para practicar en interior durante los meses fríos de Massachusetts. Utilizó dos cestas de melocotones colgadas a tres metros del suelo, y de ahí viene el nombre del deporte. Hoy el baloncesto se practica en todo el mundo y es el segundo deporte más popular en muchos países.

Las técnicas básicas que aprende un principiante son el bote, el pase y el tiro. El bote consiste en hacer botar el balón con una mano mientras se desplaza; no se puede sujetar y volver a botar (eso se llama dobles) ni dar pasos sin botar (pasos). El pase transfiere el balón entre compañeros, de pecho, picado o por encima de la cabeza. El tiro busca introducir el balón en la canasta; los lanzamientos desde más de 6,75 metros valen tres puntos.

Un partido se juega entre dos equipos de cinco jugadores. Cada partido dura cuatro cuartos de diez minutos (o doce en la NBA). El baloncesto exige resistencia, agilidad, saltos, precisión y capacidad táctica. Al ser un deporte muy dinámico, con cambios frecuentes de posesión, desarrolla también la concentración y las reacciones rápidas. Es un deporte ideal para la Educación Física escolar.', '[{"pregunta":"¿Quién inventó el baloncesto?","opciones":["Naismith","Jordan","Bryant","Abdul-Jabbar"],"correcta":0},{"pregunta":"¿Qué usó como canastas?","opciones":["Aros de hierro","Cestas de melocotones","Cajas","Cubos"],"correcta":1},{"pregunta":"¿Cuántos jugadores por equipo?","opciones":["Cinco","Seis","Siete","Once"],"correcta":0},{"pregunta":"¿A qué distancia vale tres puntos?","opciones":["Más de 4 metros","Más de 6,75 metros","Más de 10 metros","Cualquiera"],"correcta":1}]'::jsonb),

('ed-fisica', 'eso', '{1}', 'Higiene Deportiva Básica', 'La higiene deportiva es el conjunto de hábitos que permiten practicar actividad física de forma segura y saludable. Incluye aspectos como la alimentación adecuada antes y después del ejercicio, la hidratación, el descanso suficiente, la ropa apropiada y la limpieza corporal después de la práctica. Son normas sencillas pero cuyo cumplimiento marca una gran diferencia para la salud.

Antes de hacer deporte, conviene comer entre una y dos horas antes, para que el cuerpo tenga energía pero no esté haciendo la digestión. Durante la actividad, es importante beber agua con frecuencia, incluso sin sentir sed intensa, porque cuando aparece la sed ya llevamos cierto grado de deshidratación. Para actividades superiores a una hora se recomiendan bebidas isotónicas que repongan sales.

Tras el ejercicio, una ducha rápida elimina el sudor y evita problemas cutáneos, además de ayudar a relajar los músculos. La ropa debe ser cómoda, transpirable y adaptada al clima: camisetas técnicas que dejan escapar el sudor, zapatillas apropiadas al deporte que se practica. Conviene cambiarse de ropa inmediatamente después de la ducha. Estos gestos, que parecen pequeños, forman parte de una actitud responsable hacia el propio cuerpo.', '[{"pregunta":"¿Cuánto antes se debe comer antes del ejercicio?","opciones":["Justo antes","Una o dos horas","Cinco horas","No comer"],"correcta":1},{"pregunta":"¿Cuándo aparece la sed?","opciones":["Antes de deshidratarse","Cuando ya hay deshidratación","Nunca","Después del ejercicio"],"correcta":1},{"pregunta":"¿Qué se recomienda para actividades de más de una hora?","opciones":["Solo agua","Bebidas isotónicas","Zumo de fruta","Refrescos"],"correcta":1},{"pregunta":"¿Qué ventaja tienen las camisetas técnicas?","opciones":["Son más baratas","Dejan escapar el sudor","Son más pesadas","Dan calor"],"correcta":1}]'::jsonb),

('ed-fisica', 'eso', '{1}', 'El Vóleibol: Reglas Básicas', 'El voleibol, o vóley, fue inventado en 1895 por William G. Morgan en Estados Unidos como un deporte menos agotador que el baloncesto. Consiste en pasar un balón por encima de una red para que caiga en el campo rival sin que el otro equipo pueda devolverlo correctamente. Se disputa entre dos equipos de seis jugadores cada uno.

Un equipo dispone de tres toques como máximo para pasar el balón al otro lado de la red. Normalmente estos tres toques forman la secuencia clásica: recepción, colocación y remate. Ningún jugador puede tocar el balón dos veces seguidas (salvo el caso del bloqueo). El balón no puede caer al suelo dentro del campo propio, ni tocar un jugador por debajo de la cintura.

El sistema de puntuación es por rally-point: cada jugada da un punto, independientemente de qué equipo haya sacado. Los sets se juegan a 25 puntos (con diferencia mínima de 2) y el partido se gana al mejor de cinco sets. Las posiciones se rotan cada vez que un equipo recupera el saque. El voleibol es muy valorado en Educación Física porque no hay contacto físico entre jugadores y exige una excelente coordinación de equipo.', '[{"pregunta":"¿En qué año se inventó el voleibol?","opciones":["1895","1900","1920","1950"],"correcta":0},{"pregunta":"¿Cuántos toques por equipo como máximo?","opciones":["Dos","Tres","Cuatro","Cinco"],"correcta":1},{"pregunta":"¿A cuántos puntos se juegan los sets?","opciones":["15","21","25","30"],"correcta":2},{"pregunta":"¿Qué caracteriza al voleibol respecto al baloncesto?","opciones":["Más contacto físico","Sin contacto físico","Más jugadores","Sin red"],"correcta":1}]'::jsonb),

('ed-fisica', 'eso', '{1}', 'Juegos Populares Españoles', 'Los juegos populares son aquellos que se transmiten de generación en generación y forman parte del patrimonio cultural de un pueblo. En España hay cientos de variantes tradicionales, algunas con siglos de historia. Aunque con la llegada de los videojuegos y la vida digital algunos se han olvidado, las escuelas los recuperan como actividades de Educación Física por su valor educativo y cultural.

La comba es uno de los juegos más universales. Consiste en saltar una cuerda que dos personas hacen girar. Existen canciones tradicionales para cada modalidad: a pata coja, con saltos dobles, con obstáculos. El elástico, muy popular entre las niñas en los años ochenta y noventa, utilizaba un cordón elástico alrededor de las piernas de dos compañeras sobre el que había que saltar creando figuras cada vez más complejas.

Otros juegos populares son la rayuela, el escondite, las canicas, la chueca o el pañuelito. Cada región tiene además sus propias variantes: en Galicia se juega a los bolos, en el País Vasco a la pelota, en Canarias al salto del pastor. Estos juegos no requieren apenas material, fomentan el contacto personal y desarrollan muchas capacidades físicas y sociales. Por eso conservarlos es importante.', '[{"pregunta":"¿Qué son los juegos populares?","opciones":["Juegos nuevos","Juegos tradicionales transmitidos generacionalmente","Videojuegos","Deportes olímpicos"],"correcta":1},{"pregunta":"¿Qué juego típico se usa con un cordón alrededor de las piernas?","opciones":["Rayuela","Comba","Elástico","Canicas"],"correcta":2},{"pregunta":"¿Qué juego popular tiene Canarias?","opciones":["Pelota vasca","Salto del pastor","Bolos","Petanca"],"correcta":1},{"pregunta":"¿Por qué se recuperan en la escuela?","opciones":["Son gratis","Su valor educativo y cultural","Son aburridos","Nadie los conoce"],"correcta":1}]'::jsonb),

('ed-fisica', 'eso', '{1}', 'Los Estiramientos Generales', 'Los estiramientos son movimientos que alargan los músculos y mejoran la flexibilidad. Forman parte de cualquier sesión de ejercicio completa, tanto al principio (calentamiento) como al final (vuelta a la calma). Mantener los músculos flexibles previene lesiones, reduce la tensión muscular tras el esfuerzo y mejora el rango de movimiento de las articulaciones.

Existen varios tipos de estiramiento. El más común en las clases es el estático pasivo: se adopta una postura que estira el músculo y se mantiene entre 15 y 30 segundos sin moverse. No se debe llegar al dolor, solo sentir una tensión suave. Los estiramientos dinámicos, en cambio, utilizan movimientos controlados y son ideales para el calentamiento, porque activan el músculo sin reducir su potencia.

Hay estiramientos específicos para cada grupo muscular. Para los isquiotibiales (músculos posteriores del muslo) podemos sentarnos y tratar de tocarnos los pies; para los cuádriceps, tirar del talón hacia el glúteo estando de pie; para los gemelos, apoyar las manos en una pared manteniendo una pierna estirada detrás. Es importante respirar con calma durante cada ejercicio, sin contener la respiración, porque eso aumenta la tensión y reduce el beneficio.', '[{"pregunta":"¿Qué mejora la flexibilidad prevenir?","opciones":["Solo nada","Lesiones y tensión muscular","El aburrimiento","La velocidad"],"correcta":1},{"pregunta":"¿Cuánto dura un estiramiento estático?","opciones":["2 segundos","15-30 segundos","2 minutos","1 hora"],"correcta":1},{"pregunta":"¿Cuándo es ideal el estiramiento dinámico?","opciones":["Vuelta a la calma","Calentamiento","Al dormir","Al comer"],"correcta":1},{"pregunta":"¿Se debe contener la respiración?","opciones":["Sí","No, hay que respirar con calma","Depende","Solo al inicio"],"correcta":1}]'::jsonb),

('ed-fisica', 'eso', '{1}', 'El Atletismo: Saltos y Lanzamientos', 'El atletismo es un deporte que agrupa pruebas muy diversas, todas relacionadas con la carrera, el salto o el lanzamiento. Se considera el deporte más antiguo del mundo, porque las primeras competiciones documentadas son las de los Juegos Olímpicos de la antigua Grecia, celebrados en Olimpia desde el año 776 a.C. Hoy el atletismo sigue siendo uno de los deportes estrella en los Juegos modernos.

Dentro del salto, destacan cuatro pruebas. El salto de longitud consiste en recorrer la mayor distancia posible después de una carrera de impulso. El salto de altura busca superar un listón a la mayor altura; los atletas utilizan la técnica del estilo Fosbury, que consiste en pasar de espaldas sobre el listón. Existen también el triple salto (tres fases: hop, step y jump) y el salto con pértiga, que usa una vara flexible para impulsarse.

Los lanzamientos incluyen el peso (una bola metálica), el disco, la jabalina (como una lanza) y el martillo (una bola unida a un cable). Cada prueba exige una técnica específica para conseguir máxima distancia. Son disciplinas que combinan fuerza, potencia, coordinación y precisión. Muchos institutos organizan jornadas atléticas para que los alumnos prueben varias de estas modalidades.', '[{"pregunta":"¿Desde qué año hay Juegos Olímpicos antiguos?","opciones":["500 a.C.","776 a.C.","1 d.C.","100 d.C."],"correcta":1},{"pregunta":"¿Qué técnica usa el salto de altura?","opciones":["Estilo tijera","Fosbury","Rodillo ventral","Kip"],"correcta":1},{"pregunta":"¿Cuál NO es un lanzamiento?","opciones":["Peso","Disco","Jabalina","Pértiga"],"correcta":3},{"pregunta":"¿Cuántas fases tiene el triple salto?","opciones":["Dos","Tres","Cuatro","Cinco"],"correcta":1}]'::jsonb);

-- ============================================================
-- ED. FÍSICA - 2º ESO (capacidades físicas)
-- ============================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('ed-fisica', 'eso', '{2}', 'La Resistencia Aeróbica', 'La resistencia aeróbica es la capacidad del organismo para mantener un esfuerzo prolongado de intensidad moderada, utilizando oxígeno como fuente principal de energía. Cuando corremos suavemente durante varios minutos, nuestro corazón y pulmones trabajan para llevar oxígeno a los músculos, y la energía se produce a partir de reacciones que consumen ese oxígeno. Es un tipo de resistencia muy beneficioso para la salud general.

Las actividades típicas que mejoran la resistencia aeróbica son correr a ritmo suave, nadar, montar en bicicleta, patinar o bailar. Lo importante es mantener el esfuerzo durante al menos veinte minutos seguidos a una intensidad media: el pulso se eleva, pero se puede mantener una conversación entrecortada. Si el esfuerzo es tan grande que no podemos hablar, ya no estamos en zona aeróbica.

Mejorar la resistencia aeróbica tiene muchos beneficios: fortalece el corazón, reduce la tensión arterial, ayuda a controlar el peso, mejora el estado de ánimo y aumenta la esperanza de vida. Por eso la Organización Mundial de la Salud recomienda que los adolescentes hagan al menos 60 minutos diarios de actividad física aeróbica. Ese hábito, si se mantiene en la edad adulta, reduce considerablemente el riesgo de enfermedades cardiovasculares.', '[{"pregunta":"¿Qué usa la resistencia aeróbica como fuente de energía?","opciones":["Azúcar directo","Oxígeno","Ácido láctico","Hidrógeno"],"correcta":1},{"pregunta":"¿Cuánto tiempo mínimo para mejorarla?","opciones":["2 minutos","5 minutos","20 minutos","2 horas"],"correcta":2},{"pregunta":"¿Qué recomienda la OMS para adolescentes?","opciones":["10 min/día","30 min/día","60 min/día","2 horas/día"],"correcta":2},{"pregunta":"¿Qué beneficio NO aporta?","opciones":["Fortalece corazón","Reduce esperanza de vida","Mejora ánimo","Controla peso"],"correcta":1}]'::jsonb),

('ed-fisica', 'eso', '{2}', 'La Fuerza: Tipos y Desarrollo', 'La fuerza es la capacidad de los músculos para vencer una resistencia externa. Dependiendo de cómo se manifieste, hablamos de distintos tipos: la fuerza máxima es la carga más grande que un músculo puede mover una sola vez; la fuerza resistencia es la capacidad de realizar esfuerzos de fuerza durante tiempo prolongado; la fuerza explosiva es capacidad de mover resistencias a máxima velocidad, como ocurre en un salto o un lanzamiento.

En adolescentes, el entrenamiento de fuerza debe adaptarse al desarrollo físico. No se recomiendan cargas pesadas con pesas porque los huesos aún están creciendo. En cambio, se entrena con el propio peso corporal mediante ejercicios como flexiones, sentadillas, dominadas, abdominales o saltos. Estos ejercicios fortalecen los músculos sin riesgo para la columna ni las articulaciones.

El trabajo de fuerza bien planificado tiene muchos beneficios: mejora la postura, previene lesiones, aumenta el rendimiento deportivo y contribuye al desarrollo óseo. Tanto chicos como chicas pueden y deben entrenar fuerza, aunque algunos mitos afirmen lo contrario. No hay ningún motivo para que las chicas eviten este trabajo; al contrario, les aporta los mismos beneficios de salud y bienestar que a los chicos.', '[{"pregunta":"¿Qué tipo de fuerza mueve una carga máxima una sola vez?","opciones":["Fuerza máxima","Fuerza resistencia","Fuerza explosiva","Fuerza relativa"],"correcta":0},{"pregunta":"¿Qué se recomienda evitar en adolescentes?","opciones":["Flexiones","Sentadillas","Cargas pesadas con pesas","Saltos"],"correcta":2},{"pregunta":"¿Las chicas deben entrenar fuerza?","opciones":["No","Solo después de los 18","Sí, igual que los chicos","Solo si quieren competir"],"correcta":2},{"pregunta":"¿Qué tipo de fuerza usa un salto?","opciones":["Resistencia","Máxima","Explosiva","Estática"],"correcta":2}]'::jsonb),

('ed-fisica', 'eso', '{2}', 'La Velocidad y sus Tipos', 'La velocidad es la capacidad de realizar movimientos en el menor tiempo posible. No es una capacidad única: se divide en varios tipos según el contexto en que aparezca. La velocidad de reacción es el tiempo que tardamos en responder a un estímulo, como salir de los tacos al oír el disparo de salida. La velocidad gestual es la rapidez de un movimiento concreto, como un golpe de tenis. Y la velocidad de desplazamiento es la rapidez con que recorremos una distancia.

La velocidad depende principalmente del sistema nervioso y del tipo de fibras musculares. Existen fibras rápidas (tipo II) que permiten contracciones veloces y potentes, y fibras lentas (tipo I) más adecuadas para esfuerzos largos. La proporción entre unas y otras está determinada en gran medida por la genética, aunque el entrenamiento puede mejorar el rendimiento.

La velocidad se entrena mediante salidas y sprints cortos, ejercicios de reacción con señales visuales o auditivas, y juegos que exijan cambios rápidos de dirección. A diferencia de la resistencia, que mejora con mucha práctica, la velocidad progresa lentamente y tiene un techo genético marcado. Por eso los grandes velocistas son atletas excepcionales: combinan dotes naturales y años de entrenamiento específico.', '[{"pregunta":"¿Cuántos tipos de velocidad cita el texto?","opciones":["Dos","Tres","Cuatro","Cinco"],"correcta":1},{"pregunta":"¿Qué fibras permiten contracciones rápidas?","opciones":["Tipo I (lentas)","Tipo II (rápidas)","Tipo III","Blanco"],"correcta":1},{"pregunta":"¿De qué depende principalmente la velocidad?","opciones":["Del corazón","Del sistema nervioso y las fibras","Del estómago","De la piel"],"correcta":1},{"pregunta":"¿Cuál es la velocidad de reacción?","opciones":["La final","Tiempo en responder a un estímulo","Un sprint largo","La media"],"correcta":1}]'::jsonb),

('ed-fisica', 'eso', '{2}', 'La Flexibilidad Corporal', 'La flexibilidad es la capacidad de realizar movimientos con la máxima amplitud articular posible. A diferencia de otras capacidades como la fuerza o la resistencia, que pueden mejorarse durante toda la vida, la flexibilidad tiende a disminuir con la edad si no se trabaja específicamente. Por eso es muy importante conservarla desde jóvenes mediante estiramientos y ejercicios adecuados.

La flexibilidad depende de dos factores principales: la movilidad articular (cuánto se pueden mover las articulaciones) y la elasticidad muscular (cuánto se pueden alargar los músculos, tendones y ligamentos). Ambas se combinan para permitirnos hacer gestos amplios como abrirse de piernas, tocarse los pies con las manos o rotar la cintura.

Existen tres métodos principales para mejorar la flexibilidad. El estiramiento estático consiste en mantener una postura que estira el músculo durante 20-30 segundos. El estiramiento dinámico utiliza movimientos activos con rangos amplios. El método PNF (facilitación neuromuscular propioceptiva) alterna contracciones y relajaciones, y es el más eficaz para ganar flexibilidad a largo plazo. La flexibilidad es especialmente importante en deportes como la gimnasia, la danza o las artes marciales.', '[{"pregunta":"¿Qué ocurre con la flexibilidad con la edad?","opciones":["Aumenta","Tiende a disminuir si no se entrena","Queda igual","Se multiplica"],"correcta":1},{"pregunta":"¿Qué factores forman la flexibilidad?","opciones":["Fuerza y velocidad","Movilidad articular y elasticidad muscular","Resistencia","Equilibrio"],"correcta":1},{"pregunta":"¿Qué método es más eficaz?","opciones":["Estático","Dinámico","PNF","Ninguno"],"correcta":2},{"pregunta":"¿Cuánto dura un estiramiento estático?","opciones":["5 seg","20-30 seg","2 minutos","5 minutos"],"correcta":1}]'::jsonb),

('ed-fisica', 'eso', '{2}', 'El Tabaco y el Rendimiento', 'El tabaco es una de las drogas más perjudiciales para la salud y el rendimiento deportivo. Contiene más de cuatro mil sustancias químicas, muchas de ellas tóxicas, entre las que destaca la nicotina (responsable de la adicción), el monóxido de carbono (que dificulta el transporte de oxígeno) y el alquitrán (causante de cáncer de pulmón). Fumar afecta prácticamente a todos los órganos del cuerpo.

Para un deportista, las consecuencias son especialmente graves. El monóxido de carbono se une a la hemoglobina de la sangre ocupando el lugar del oxígeno, con lo que los músculos reciben menos oxígeno y la resistencia disminuye. El humo daña los alvéolos pulmonares, reduciendo la capacidad respiratoria. Además, fumar aumenta la frecuencia cardiaca en reposo, haciendo que el corazón trabaje más aunque no estemos haciendo ejercicio.

Los estudios demuestran que los adolescentes que fuman rinden un 10-15% por debajo de los que no fuman en pruebas de resistencia. A largo plazo, el tabaco multiplica por veinte el riesgo de cáncer de pulmón y causa enfermedades cardiacas, enfisema y bronquitis crónica. Afortunadamente, dejar de fumar permite que el organismo recupere la mayoría de sus capacidades, aunque el proceso puede llevar varios años.', '[{"pregunta":"¿Qué dificulta el transporte de oxígeno?","opciones":["La nicotina","El monóxido de carbono","El alquitrán","El aire"],"correcta":1},{"pregunta":"¿Cuánto por debajo rinden los fumadores jóvenes?","opciones":["1%","5%","10-15%","50%"],"correcta":2},{"pregunta":"¿Por cuánto multiplica el riesgo de cáncer de pulmón?","opciones":["Dos","Cinco","Diez","Veinte"],"correcta":3},{"pregunta":"¿Qué ocurre al dejar de fumar?","opciones":["Nada mejora","El cuerpo recupera capacidades","Se empeora","Duele siempre"],"correcta":1}]'::jsonb),

('ed-fisica', 'eso', '{2}', 'El Baloncesto: Posiciones Tácticas', 'En baloncesto, los cinco jugadores de un equipo se distribuyen en posiciones tácticas específicas, cada una con funciones y responsabilidades distintas. Aunque en el baloncesto moderno estas posiciones son cada vez más flexibles, tradicionalmente se numeran del 1 al 5 y sirven como guía de juego.

El base (posición 1) es el cerebro del equipo. Normalmente es el jugador más bajo pero el más hábil en el manejo del balón; su misión es organizar el juego, pasar a los compañeros mejor situados y tomar las decisiones tácticas. El escolta (posición 2) es un gran anotador desde posiciones exteriores, especializado en tiros a media y larga distancia.

El alero (posición 3) combina altura y agilidad; puede anotar desde fuera y acercarse a la canasta. El ala-pívot (posición 4) es alto y potente, juega cerca de la canasta y domina el rebote. Finalmente, el pívot (posición 5) es el más alto del equipo; su territorio es la zona cercana al aro, donde anota a corta distancia, captura rebotes defensivos y bloquea tiros. Las estrellas modernas como LeBron James han difuminado estos roles jugando en varias posiciones a la vez.', '[{"pregunta":"¿Quién organiza el juego?","opciones":["El base","El escolta","El alero","El pívot"],"correcta":0},{"pregunta":"¿Qué posición es el número 5?","opciones":["Alero","Ala-pívot","Pívot","Base"],"correcta":2},{"pregunta":"¿Quién suele ser el más alto?","opciones":["Base","Escolta","Alero","Pívot"],"correcta":3},{"pregunta":"¿Qué hace el escolta?","opciones":["Organiza","Anota desde media y larga distancia","Rebotea","Bloquea tiros"],"correcta":1}]'::jsonb),

('ed-fisica', 'eso', '{2}', 'El Circuito Físico en Clase', 'Un circuito físico es una forma de entrenar que combina varios ejercicios distintos en distintas estaciones, por las que los alumnos van pasando en orden. Cada estación trabaja una capacidad o grupo muscular concreto, y los alumnos pasan de una a otra tras un tiempo determinado (por ejemplo, 30 segundos de trabajo y 15 de descanso) o tras completar un número de repeticiones.

Los circuitos son muy populares en Educación Física porque permiten trabajar a muchos alumnos al mismo tiempo con poco material, y porque combinan eficientemente fuerza, resistencia, coordinación y velocidad en una sola sesión. Además, se pueden adaptar fácilmente al nivel de cada alumno, porque cada uno puede ajustar la intensidad sin parar toda la clase.

Un circuito típico podría incluir estaciones como: flexiones, saltos a la comba, burpees, abdominales, sentadillas, planchas, carrera suave y saltos laterales. El docente controla los tiempos con un silbato o una música programada. Los circuitos pueden repetirse dos o tres vueltas completas para aumentar el volumen total de trabajo. Son una herramienta versátil y muy efectiva para mejorar la condición física general de forma dinámica y motivadora.', '[{"pregunta":"¿Qué es un circuito físico?","opciones":["Un recorrido de coches","Varias estaciones con ejercicios","Un deporte concreto","Una carrera larga"],"correcta":1},{"pregunta":"¿Qué ventaja tiene en clase?","opciones":["Requiere mucho material","Permite trabajar a muchos alumnos a la vez","Es solo para adultos","Es aburrido"],"correcta":1},{"pregunta":"¿Cómo se controla el tiempo?","opciones":["Con ordenador","Con silbato o música","Nadie lo controla","Con calculadora"],"correcta":1},{"pregunta":"¿Se adapta al nivel de cada alumno?","opciones":["No","Sí, ajustando intensidad","Solo a los mejores","Solo a los peores"],"correcta":1}]'::jsonb),

('ed-fisica', 'eso', '{2}', 'Tenis de Mesa: Un Deporte de Precisión', 'El tenis de mesa, también conocido como ping-pong, es un deporte olímpico que se juega sobre una mesa rectangular dividida por una red baja. Los jugadores golpean una pelota pequeña y ligera con raquetas especiales, recubiertas de goma, intentando que el rival no pueda devolverla correctamente al otro lado de la mesa.

Aunque pueda parecer un deporte sencillo, el tenis de mesa exige extraordinaria velocidad de reacción y una coordinación ojo-mano muy fina. La pelota puede alcanzar velocidades superiores a los cien kilómetros por hora y gira intensamente por efecto del caucho de las raquetas. Los jugadores de élite deben anticipar la trayectoria y elegir el golpe adecuado en fracciones de segundo.

Se originó en Inglaterra a finales del siglo XIX como un pasatiempo entre la aristocracia, que jugaba con libros y tapones de corcho tras la cena. Hoy es uno de los deportes más practicados del mundo, con especial popularidad en China, que domina las competiciones internacionales. En el ámbito escolar, el tenis de mesa es ideal porque requiere poco espacio, es seguro, fomenta la coordinación y puede practicarse de forma individual o por parejas (dobles).', '[{"pregunta":"¿Cuánta velocidad puede alcanzar la pelota?","opciones":["10 km/h","50 km/h","Más de 100 km/h","500 km/h"],"correcta":2},{"pregunta":"¿Dónde se originó?","opciones":["China","Inglaterra","Japón","Estados Unidos"],"correcta":1},{"pregunta":"¿Qué país domina hoy las competiciones?","opciones":["Inglaterra","Japón","China","España"],"correcta":2},{"pregunta":"¿Qué capacidad física exige especialmente?","opciones":["Fuerza máxima","Velocidad de reacción","Flexibilidad","Resistencia aeróbica"],"correcta":1}]'::jsonb),

('ed-fisica', 'eso', '{2}', 'Expresión Corporal y Mímica', 'La expresión corporal es la forma de comunicar ideas, emociones o historias utilizando el cuerpo como único medio. A diferencia del deporte, donde el objetivo es competir o mejorar el rendimiento, en la expresión corporal lo importante es comunicar. Incluye disciplinas como la danza, el teatro gestual, la mímica y las coreografías acrobáticas. En Educación Física se trabaja porque desarrolla la creatividad, la confianza y el conocimiento del propio cuerpo.

La mímica es una rama de la expresión corporal que consiste en representar acciones, objetos o emociones sin usar palabras ni apoyo de objetos reales. El mimo ha sido cultivado desde la antigüedad, pero alcanzó su máximo reconocimiento en el siglo XX con figuras como Marcel Marceau, quien inventó personajes inolvidables como Bip el clown. Sus actuaciones, sin una sola palabra, emocionaban a los espectadores de todo el mundo.

En clase, la expresión corporal se trabaja con ejercicios de calentamiento corporal, desinhibición, escucha del grupo, improvisación y montaje de pequeñas coreografías. Al principio puede dar vergüenza, pero los alumnos suelen descubrir que es muy divertido y les ayuda a conocerse mejor. Es una de las áreas de la Educación Física más valoradas por los alumnos que no se sienten cómodos con los deportes de competición tradicionales.', '[{"pregunta":"¿Qué se comunica en la expresión corporal?","opciones":["Solo información","Ideas, emociones e historias","Solo números","Nada"],"correcta":1},{"pregunta":"¿Quién fue un gran mimo del siglo XX?","opciones":["Chaplin","Marcel Marceau","Fellini","Astaire"],"correcta":1},{"pregunta":"¿Usa palabras la mímica?","opciones":["Sí, muchas","No, ninguna","Solo al final","Una sola"],"correcta":1},{"pregunta":"¿Qué valor aporta a los alumnos?","opciones":["Competitividad","Creatividad y confianza","Fuerza máxima","Velocidad"],"correcta":1}]'::jsonb),

('ed-fisica', 'eso', '{2}', 'La Agilidad y la Coordinación', 'La agilidad y la coordinación son dos capacidades físicas que, a diferencia de las llamadas básicas (resistencia, fuerza, velocidad, flexibilidad), se consideran capacidades coordinativas. No miden cuánto puede uno aguantar o cuánto levanta, sino la calidad con que se mueve. Son esenciales para aprender cualquier gesto deportivo y se desarrollan especialmente bien en la infancia y la adolescencia.

La agilidad es la capacidad de cambiar rápidamente de dirección y postura mientras estamos en movimiento, sin perder el equilibrio ni el control. Un ejemplo claro es el jugador de fútbol que regatea, cambiando de lado una y otra vez. La coordinación, por su parte, es la capacidad de combinar distintos movimientos de manera armónica y eficaz: usar brazos y piernas a la vez, sincronizar el cuerpo con un objeto (como una pelota) o con otros compañeros.

Se entrenan con juegos, carreras con cambios de dirección, saltos, ejercicios con conos y pelotas, y actividades rítmicas. En una sesión de Educación Física pueden trabajarse con circuitos que obliguen a pasar por zig-zag, saltar obstáculos, girar y seguir. Tener buena coordinación y agilidad es la base para dominar después cualquier deporte, desde el baloncesto hasta la gimnasia. Por eso su entrenamiento nunca es un lujo, sino una inversión para el futuro deportivo.', '[{"pregunta":"¿Qué tipo de capacidades son agilidad y coordinación?","opciones":["Básicas","Coordinativas","Psicológicas","Sociales"],"correcta":1},{"pregunta":"¿Qué es la agilidad?","opciones":["Levantar mucho peso","Cambiar de dirección rápido sin perder equilibrio","Correr lejos","Saltar alto"],"correcta":1},{"pregunta":"¿Cuándo se desarrollan especialmente bien?","opciones":["Solo en adultos","Infancia y adolescencia","Solo en ancianos","Nunca"],"correcta":1},{"pregunta":"¿Qué actividad las entrena?","opciones":["Dormir","Circuitos con zig-zag y obstáculos","Leer","Ver TV"],"correcta":1}]'::jsonb);

