-- ED. FÍSICA - 3º ESO (salud / nutrición)
-- ============================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('ed-fisica', 'eso', '{3}', 'La Pirámide Alimenticia', 'La pirámide alimenticia es una representación gráfica que muestra cómo debe distribuirse la alimentación diaria según los distintos grupos de alimentos. En su base se sitúan los alimentos que debemos consumir en mayor cantidad, y en la cúspide los que debemos tomar con moderación. Es una herramienta sencilla pero eficaz para educar en hábitos nutricionales saludables.

En la base están los cereales integrales, los tubérculos y la pasta: son los que aportan hidratos de carbono, la principal fuente de energía del organismo. En el siguiente nivel encontramos las frutas y las verduras, ricas en vitaminas, minerales y fibra. Se recomienda tomar al menos cinco raciones diarias entre las dos categorías. Un poco más arriba están las legumbres, los frutos secos, los lácteos, el pescado, la carne blanca y los huevos, que aportan proteínas y grasas saludables.

En la cúspide aparecen las carnes rojas, los embutidos, los dulces, las grasas saturadas y los ultraprocesados. Estos alimentos no están prohibidos, pero deben consumirse con poca frecuencia. La pirámide moderna también incluye el agua en la base (ocho vasos al día) y recomienda hacer ejercicio físico diario, reconociendo que la alimentación sola no basta para una vida saludable.', '[{"pregunta":"¿Qué está en la base de la pirámide?","opciones":["Dulces","Cereales integrales y tubérculos","Carne roja","Alcohol"],"correcta":1},{"pregunta":"¿Cuántas raciones de fruta y verdura al día?","opciones":["Una","Dos","Al menos cinco","Diez"],"correcta":2},{"pregunta":"¿Dónde están los dulces?","opciones":["Base","Medio","Cúspide","Fuera"],"correcta":2},{"pregunta":"¿Qué incluye hoy la pirámide en la base?","opciones":["Café","Agua","Refrescos","Vino"],"correcta":1}]'::jsonb),

('ed-fisica', 'eso', '{3}', 'Los Macronutrientes', 'Los macronutrientes son los componentes principales de los alimentos y proporcionan la mayor parte de la energía que necesita nuestro cuerpo. Se dividen en tres grandes grupos: hidratos de carbono, proteínas y grasas. Cada uno cumple funciones específicas y debe consumirse en las proporciones adecuadas para mantener la salud y el rendimiento físico.

Los hidratos de carbono son la principal fuente de energía. Aportan 4 kilocalorías por gramo y se almacenan en el hígado y los músculos en forma de glucógeno. Los hay simples (azúcares) y complejos (almidones). Los complejos son preferibles porque liberan energía de forma gradual. Las proteínas, también con 4 kcal/g, están formadas por aminoácidos y sirven para construir y reparar tejidos, especialmente los musculares. Se encuentran en la carne, el pescado, los huevos, los lácteos y las legumbres.

Las grasas son el macronutriente más energético: aportan 9 kcal/g. Son esenciales para absorber las vitaminas liposolubles (A, D, E, K) y para muchas funciones metabólicas. Existen grasas saludables (insaturadas, presentes en el aceite de oliva, los frutos secos y el pescado azul) y grasas perjudiciales (saturadas y trans, abundantes en bollería industrial y ultraprocesados). La proporción recomendada es aproximadamente 55% hidratos, 15% proteínas y 30% grasas.', '[{"pregunta":"¿Cuántas kcal aporta un gramo de grasa?","opciones":["4","7","9","12"],"correcta":2},{"pregunta":"¿Cómo se almacenan los hidratos?","opciones":["Como grasa","Como glucógeno","Como proteínas","No se almacenan"],"correcta":1},{"pregunta":"¿Qué función principal tienen las proteínas?","opciones":["Dar energía","Construir y reparar tejidos","Aislar","Digerir"],"correcta":1},{"pregunta":"¿Qué porcentaje aproximado de hidratos se recomienda?","opciones":["15%","30%","55%","70%"],"correcta":2}]'::jsonb),

('ed-fisica', 'eso', '{3}', 'La Hidratación y el Deporte', 'El agua representa entre el 60 y el 70% del peso corporal en adultos, y un porcentaje aún mayor en niños y adolescentes. Es imprescindible para el funcionamiento de prácticamente todas las células del cuerpo y, muy especialmente, para el rendimiento deportivo. Durante la actividad física perdemos agua a través del sudor, que el cuerpo genera para regular la temperatura interna.

Una pérdida de agua equivalente al 2% del peso corporal ya produce una reducción del rendimiento físico. Si la deshidratación es del 5%, aparecen síntomas como mareos, dolor de cabeza, calambres musculares y descenso drástico de la capacidad de concentración. Por encima del 10%, las consecuencias pueden ser muy graves, incluyendo golpes de calor potencialmente mortales.

La recomendación para los deportistas es beber antes de tener sed. Conviene ingerir unos 200-300 ml de agua unos 15 minutos antes de empezar el ejercicio, y pequeñas cantidades cada 15-20 minutos durante la actividad. Si el ejercicio dura más de una hora o se realiza con mucho calor, las bebidas isotónicas ayudan a reponer sales minerales (sodio, potasio, magnesio) perdidas en el sudor. Después del ejercicio, conviene continuar bebiendo hasta recuperar el peso corporal previo.', '[{"pregunta":"¿Qué porcentaje del peso es agua?","opciones":["20-30%","40-50%","60-70%","90%"],"correcta":2},{"pregunta":"¿Con qué porcentaje de pérdida ya baja el rendimiento?","opciones":["1%","2%","5%","10%"],"correcta":1},{"pregunta":"¿Cuándo son útiles las bebidas isotónicas?","opciones":["Siempre","Ejercicios muy cortos","Ejercicios de más de una hora","Solo en reposo"],"correcta":2},{"pregunta":"¿Cuándo beber?","opciones":["Solo con sed","Antes de tener sed","Después","Nunca"],"correcta":1}]'::jsonb),

('ed-fisica', 'eso', '{3}', 'El Descanso y la Recuperación', 'El descanso es una parte fundamental del entrenamiento deportivo, aunque muchos lo descuiden. Durante el ejercicio se producen microrroturas en las fibras musculares y se gastan reservas de energía. Es durante el descanso, y especialmente durante el sueño, cuando el cuerpo repara estos daños y adapta los músculos para soportar esfuerzos mayores. Sin descanso adecuado, no hay progreso.

El sueño es la fase más importante de recuperación. En adolescentes, se recomiendan entre ocho y diez horas diarias de sueño de calidad. Durante el sueño profundo se liberan hormonas anabólicas como la hormona del crecimiento, esenciales para la reparación muscular y el desarrollo corporal. Dormir poco reduce el rendimiento, empeora la concentración, aumenta el riesgo de lesión y deteriora el estado de ánimo.

Además del sueño, la recuperación incluye días de descanso activo (caminar, estirar, bicicleta suave) entre sesiones intensas, una nutrición adecuada, una buena hidratación y técnicas como los masajes o los baños fríos. Los deportistas profesionales dedican tanto cuidado al descanso como al entrenamiento. En clase, conviene explicar a los alumnos que entrenar en exceso sin recuperar puede ser contraproducente y provocar lesiones por sobrecarga.', '[{"pregunta":"¿Cuántas horas de sueño se recomiendan para adolescentes?","opciones":["4-5","6-7","8-10","12"],"correcta":2},{"pregunta":"¿Qué se libera durante el sueño profundo?","opciones":["Adrenalina","Hormona del crecimiento","Insulina","Cortisol"],"correcta":1},{"pregunta":"¿Qué ocurre sin descanso adecuado?","opciones":["Se avanza más","No hay progreso","Se gana fuerza","Nada"],"correcta":1},{"pregunta":"¿Qué es descanso activo?","opciones":["Estar sentado","Actividades suaves como caminar o estirar","Dormir","No comer"],"correcta":1}]'::jsonb),

('ed-fisica', 'eso', '{3}', 'Los Grupos Musculares Principales', 'El cuerpo humano tiene más de seiscientos músculos esqueléticos, pero en el ámbito deportivo solemos referirnos a grupos musculares grandes que trabajan juntos. En el tren superior están los pectorales (pecho), los deltoides (hombros), los bíceps (parte anterior del brazo), los tríceps (parte posterior), el dorsal ancho (espalda media) y los trapecios (espalda alta).

En la zona central, o core, están los músculos abdominales (recto, oblicuos, transverso) y los lumbares (parte baja de la espalda). El core es fundamental porque estabiliza el cuerpo durante prácticamente cualquier movimiento. Un core fuerte previene dolores de espalda, mejora la postura y aumenta el rendimiento en todos los deportes.

El tren inferior incluye los glúteos (cadera), los cuádriceps (parte anterior del muslo), los isquiotibiales (parte posterior), los aductores (cara interna) y los gemelos/sóleo (pantorrilla). Son los músculos más potentes del cuerpo, porque sostienen nuestro peso y nos permiten caminar, correr, saltar y empujar. Conocer los grupos musculares ayuda a entender qué ejercicio trabaja cada zona y a diseñar rutinas equilibradas que no descuiden ninguna parte del cuerpo.', '[{"pregunta":"¿Cuántos músculos esqueléticos tiene el cuerpo?","opciones":["Menos de 100","Más de 600","Más de 2000","Solo 20"],"correcta":1},{"pregunta":"¿Qué es el core?","opciones":["La pierna","La zona central (abdominales y lumbares)","El brazo","El cuello"],"correcta":1},{"pregunta":"¿Qué músculo está en el pecho?","opciones":["Dorsal","Pectoral","Trapecio","Bíceps"],"correcta":1},{"pregunta":"¿Qué músculo está en la pantorrilla?","opciones":["Cuádriceps","Gemelos","Aductores","Glúteos"],"correcta":1}]'::jsonb),

('ed-fisica', 'eso', '{3}', 'Balonmano: Juego Rápido', 'El balonmano es un deporte de equipo inventado en los países nórdicos y Alemania a principios del siglo XX. Combina elementos del fútbol, el baloncesto y el rugby: se juega con las manos, pero hay contacto físico, posiciones tácticas y una portería que defender. Se disputa entre dos equipos de siete jugadores (seis de campo y un portero) en una pista rectangular de 40 por 20 metros.

El objetivo es meter gol lanzando el balón a la portería contraria. Los jugadores pueden desplazarse botando el balón (como en baloncesto) o dando máximo tres pasos sin botar. No se puede entrar en el área del portero, una zona semicircular a seis metros de la portería. Las faltas, los pasivos y los lanzamientos de penalti son las principales acciones a dominio del árbitro.

Un partido dura 60 minutos divididos en dos tiempos de 30. El balonmano exige una enorme combinación de capacidades: velocidad, agilidad, fuerza explosiva en los lanzamientos, resistencia y precisión. En España ha habido grandes generaciones de jugadores; la selección masculina ha ganado dos campeonatos del mundo. A nivel escolar es muy educativo porque fomenta trabajo en equipo, técnica individual y juego limpio.', '[{"pregunta":"¿Cuántos jugadores por equipo en balonmano?","opciones":["Cinco","Seis","Siete","Once"],"correcta":2},{"pregunta":"¿Cuántos pasos máximo sin botar?","opciones":["Dos","Tres","Cuatro","Cinco"],"correcta":1},{"pregunta":"¿A qué distancia está el área del portero?","opciones":["Cuatro metros","Seis metros","Nueve metros","Doce metros"],"correcta":1},{"pregunta":"¿Cuánto dura un partido?","opciones":["40 min","50 min","60 min","90 min"],"correcta":2}]'::jsonb),

('ed-fisica', 'eso', '{3}', 'La Postura Corporal Correcta', 'Una buena postura corporal es aquella en la que el cuerpo se mantiene alineado de manera que los músculos y las articulaciones trabajen de forma equilibrada, sin tensiones excesivas. Vista de perfil, la postura ideal pasa por la oreja, el hombro, la cadera, la rodilla y el tobillo en una línea vertical imaginaria. Desviaciones de esta alineación pueden causar dolores crónicos y lesiones.

En la adolescencia es especialmente importante cuidar la postura porque el cuerpo está creciendo y formando hábitos que pueden durar toda la vida. Los malos hábitos más comunes son cargar mochilas demasiado pesadas, sentarse encorvado durante horas ante un ordenador o el móvil, y dormir en colchones inadecuados. El resultado puede ser cifosis (espalda redondeada), escoliosis (desviación lateral de la columna) o dolor lumbar.

Para mejorar la postura conviene reforzar el core (abdominales y lumbares), estirar los músculos que tienden a acortarse (pectorales y caderas), y prestar atención consciente a la posición al caminar, sentarse y estar de pie. Un ejercicio simple: imagínate un hilo que te tira desde la coronilla hacia el techo. Esto alinea automáticamente la cabeza y relaja los hombros, mejorando la postura global sin esfuerzo.', '[{"pregunta":"¿Qué puntos deben alinearse en la postura ideal?","opciones":["Solo cabeza y pies","Oreja, hombro, cadera, rodilla, tobillo","Solo espalda","Solo brazos"],"correcta":1},{"pregunta":"¿Qué es la escoliosis?","opciones":["Espalda redondeada","Desviación lateral de la columna","Pérdida de peso","Calambre muscular"],"correcta":1},{"pregunta":"¿Qué ejercicio mejora la postura?","opciones":["Correr","Reforzar core y estirar pectorales","Saltar","Dormir más"],"correcta":1},{"pregunta":"¿Qué problema causan las mochilas pesadas?","opciones":["Nada","Malos hábitos posturales","Solo cansancio","Frío"],"correcta":1}]'::jsonb),

('ed-fisica', 'eso', '{3}', 'Deportes Alternativos', 'Los deportes alternativos son actividades que se salen de los deportes tradicionales de la Educación Física (fútbol, baloncesto, voleibol, balonmano, atletismo) y ofrecen experiencias nuevas. Incluyen disciplinas como el ultimate frisbee, el floorball (hockey de interior), la kin-ball, el kin-ball, el tchoukball, el colpbol o el indiaka. Muchos surgieron en la segunda mitad del siglo XX en distintos países del mundo.

Su incorporación a la Educación Física tiene varias ventajas. En primer lugar, al ser desconocidos para la mayoría, todos los alumnos parten del mismo nivel, lo que favorece a quienes no han practicado deportes federados. En segundo lugar, suelen tener reglas diseñadas para fomentar la cooperación y reducir el contacto físico agresivo. Y en tercer lugar, rompen con los estereotipos de género: muchos no tienen una tradición masculina o femenina marcada.

El ultimate frisbee, por ejemplo, se juega con un disco volador y se rige por el "espíritu del juego": no hay árbitros, los jugadores se autoarbitran y resuelven las dudas dialogando. El tchoukball prohíbe el contacto físico y se centra en los lanzamientos contra una red elástica. Estas disciplinas enseñan valores como la autonomía, la honestidad y el respeto, difíciles de transmitir en deportes más competitivos y tradicionales.', '[{"pregunta":"¿Qué ventaja tienen los deportes alternativos?","opciones":["Son muy caros","Todos parten del mismo nivel","Son imposibles","Son muy difíciles"],"correcta":1},{"pregunta":"¿Quién arbitra en el ultimate frisbee?","opciones":["Árbitros profesionales","Los propios jugadores","El profesor","Un juez"],"correcta":1},{"pregunta":"¿Qué rige el ultimate frisbee?","opciones":["El contacto","El espíritu del juego","La velocidad","La fuerza bruta"],"correcta":1},{"pregunta":"¿Qué prohíbe el tchoukball?","opciones":["Saltar","Gritar","El contacto físico","Correr"],"correcta":2}]'::jsonb),

('ed-fisica', 'eso', '{3}', 'Las Lesiones Más Comunes', 'En el deporte escolar y de base, las lesiones más frecuentes son relativamente leves pero pueden afectar a la práctica durante semanas. Conocer los tipos principales ayuda a prevenirlas y a reaccionar correctamente si aparecen. Las tres grandes categorías son contusiones, esguinces y distensiones musculares.

Las contusiones son golpes directos sobre una zona del cuerpo que causan dolor, hinchazón y moratones, pero no dañan ligamentos ni huesos. Se tratan aplicando frío durante las primeras 24 horas, elevando la zona afectada y descansando. Los esguinces son lesiones de los ligamentos que unen los huesos, sobre todo en el tobillo y la rodilla. Se producen por torsión brusca y, según la gravedad, van desde estiramientos leves hasta roturas completas que requieren inmovilización.

Las distensiones musculares afectan al tejido muscular, cuando las fibras se estiran más allá de su capacidad o se rompen parcialmente. Son muy comunes en los isquiotibiales y los gemelos. La prevención se basa en calentar bien antes del ejercicio, mantener la flexibilidad, usar calzado adecuado y no sobrecargar el cuerpo con esfuerzos desmedidos. Si aparece una lesión, hay que aplicar el protocolo RICE: Reposo, Hielo, Compresión y Elevación.', '[{"pregunta":"¿Qué son las contusiones?","opciones":["Roturas óseas","Golpes directos con dolor e hinchazón","Hematomas internos","Fracturas"],"correcta":1},{"pregunta":"¿Qué significa RICE?","opciones":["Reposo, Hielo, Compresión, Elevación","Correr mucho","Sólo hielo","Rotura"],"correcta":0},{"pregunta":"¿Dónde son frecuentes los esguinces?","opciones":["Tobillo y rodilla","Codo","Columna","Cuello"],"correcta":0},{"pregunta":"¿Cómo se previenen las distensiones?","opciones":["No calentando","Calentando y manteniendo flexibilidad","Corriendo sin parar","Comiendo mucho"],"correcta":1}]'::jsonb),

('ed-fisica', 'eso', '{3}', 'La Orientación Deportiva', 'La orientación es un deporte en el que los participantes recorren un terreno desconocido con ayuda de un mapa detallado y una brújula, intentando visitar una serie de puntos de control en el menor tiempo posible. Nació en Escandinavia a finales del siglo XIX como entrenamiento militar y hoy es un deporte olímpico popular en muchos países. Combina actividad física intensa con pensamiento estratégico.

Los mapas de orientación usan simbología específica, muy detallada: representan curvas de nivel, tipos de vegetación, caminos, rocas, vallas, edificios. El deportista debe saber interpretarlos rápidamente. La brújula ayuda a orientar el mapa correctamente respecto al norte y a tomar rumbos precisos en zonas sin referencias visibles. Los puntos de control están señalados con balizas en las que hay que registrar el paso con una tarjeta.

En Educación Física, la orientación se enseña como actividad en el medio natural, aunque también puede practicarse en espacios urbanos o incluso en el patio del instituto. Desarrolla capacidades cognitivas (atención, toma de decisiones), físicas (resistencia, agilidad) y emocionales (autonomía, gestión del estrés). Además, fomenta el respeto al entorno natural y la capacidad de moverse con seguridad en espacios desconocidos.', '[{"pregunta":"¿Qué instrumentos se usan?","opciones":["Solo brújula","Mapa y brújula","GPS","Solo mapa"],"correcta":1},{"pregunta":"¿Dónde nació la orientación?","opciones":["Italia","Escandinavia","Francia","Reino Unido"],"correcta":1},{"pregunta":"¿Qué se registra en las balizas?","opciones":["El tiempo","El paso con una tarjeta","Las fotos","Los compañeros"],"correcta":1},{"pregunta":"¿Qué capacidades desarrolla?","opciones":["Solo físicas","Cognitivas, físicas y emocionales","Solo sociales","Ninguna"],"correcta":1}]'::jsonb);

