-- ED. FÍSICA - 4º ESO (primeros auxilios)
-- ============================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('ed-fisica', 'eso', '{4}', 'El Protocolo PAS', 'En una emergencia, los primeros minutos son decisivos. El protocolo PAS es un conjunto de tres acciones básicas que cualquier persona debe poder realizar para actuar correctamente mientras llega la ayuda profesional. Las siglas significan Proteger, Avisar y Socorrer, y el orden es fundamental: primero proteger, luego avisar, y solo después socorrer.

Proteger significa asegurar la zona para que no haya más víctimas, incluida nuestra propia seguridad. Si hay riesgo de tráfico, señalizamos la zona; si hay peligro eléctrico, cortamos la corriente; si hay fuego o humo, nos alejamos a un lugar seguro. Jamás debemos precipitarnos a ayudar si nuestra vida corre peligro, porque una segunda víctima solo empeora la situación.

Avisar es llamar al 112, el número de emergencias europeo, y proporcionar información clara: qué ha ocurrido, cuántas personas están afectadas, dónde estamos exactamente y si hay riesgos adicionales. El operador del 112 nos dará instrucciones mientras envía los servicios necesarios. Finalmente, socorrer consiste en prestar los primeros auxilios a la víctima según nuestra formación: comprobar la consciencia, la respiración, y aplicar maniobras básicas si es necesario. El protocolo PAS se enseña en todas las formaciones de primeros auxilios del mundo.', '[{"pregunta":"¿Qué significa PAS?","opciones":["Primero Ayudar Salir","Proteger, Avisar, Socorrer","Pregunta Ahora Socorro","Pulsa Alerta Servicio"],"correcta":1},{"pregunta":"¿Cuál es el primer paso?","opciones":["Socorrer","Llamar","Proteger","Tocar a la víctima"],"correcta":2},{"pregunta":"¿Cuál es el número europeo de emergencias?","opciones":["091","112","061","911"],"correcta":1},{"pregunta":"¿Qué información debemos dar al operador?","opciones":["Nuestro nombre","Qué ha pasado, cuántas víctimas, dónde","Nada","Solo el lugar"],"correcta":1}]'::jsonb),

('ed-fisica', 'eso', '{4}', 'La Reanimación Cardiopulmonar (RCP)', 'La reanimación cardiopulmonar, conocida como RCP, es un procedimiento de emergencia que combina compresiones torácicas y ventilaciones para mantener la circulación y la oxigenación en una persona que ha sufrido una parada cardíaca. La RCP no reinicia el corazón por sí sola, pero mantiene con vida al paciente hasta que llega la ayuda profesional con un desfibrilador. Cada minuto sin RCP reduce las posibilidades de supervivencia en un 10%.

Para realizar RCP básica en un adulto, primero hay que asegurarse de que la víctima no responde y no respira con normalidad. Se la coloca boca arriba sobre una superficie dura, con las piernas estiradas. Se coloca una mano sobre la otra en el centro del pecho (línea de los pezones) y se comprimen cinco o seis centímetros a un ritmo de 100-120 veces por minuto. Tras 30 compresiones, se pueden dar 2 ventilaciones boca a boca si se está formado.

Las compresiones no deben interrumpirse salvo para las ventilaciones o para usar un desfibrilador. En adolescentes y adultos, el ritmo 30:2 se mantiene hasta que llegan los servicios de emergencia o la víctima recupera signos vitales. La RCP es una técnica que puede salvar vidas, y por eso cada vez más institutos incluyen formación básica como parte de la Educación Física.', '[{"pregunta":"¿Cuánto se reducen las posibilidades por minuto sin RCP?","opciones":["1%","5%","10%","25%"],"correcta":2},{"pregunta":"¿A qué ritmo se comprime?","opciones":["50 por minuto","100-120 por minuto","200 por minuto","40 por minuto"],"correcta":1},{"pregunta":"¿Qué profundidad de compresión?","opciones":["1-2 cm","3-4 cm","5-6 cm","10 cm"],"correcta":2},{"pregunta":"¿Cuál es la secuencia en adultos?","opciones":["15:2","30:2","10:1","100:1"],"correcta":1}]'::jsonb),

('ed-fisica', 'eso', '{4}', 'La Maniobra de Heimlich', 'La maniobra de Heimlich es una técnica de primeros auxilios para desobstruir las vías respiratorias de una persona que se está atragantando con un cuerpo extraño, generalmente un trozo de comida. Fue descrita en 1974 por el doctor estadounidense Henry Heimlich, a quien debe su nombre. Desde entonces se calcula que ha salvado cientos de miles de vidas en todo el mundo.

Primero hay que distinguir si la obstrucción es parcial (la persona tose, habla o respira con dificultad) o completa (no puede toser ni hablar y se lleva las manos al cuello, el gesto universal del atragantamiento). Si es parcial, hay que animarla a toser con fuerza para que expulse el objeto por sí misma. No hay que intervenir con maniobras mientras la persona pueda toser efectivamente, porque podríamos empeorar la situación.

Si la obstrucción es completa, nos colocamos detrás de la víctima, abrazándola por la cintura. Cerramos un puño y lo colocamos entre el ombligo y la punta del esternón. Con la otra mano agarramos el puño y realizamos cinco empujes secos hacia adentro y hacia arriba. Alternamos con cinco palmadas entre los omóplatos. Repetimos hasta que el objeto salga o la persona pierda la consciencia. En niños pequeños y embarazadas hay que adaptar la técnica.', '[{"pregunta":"¿Para qué sirve la maniobra de Heimlich?","opciones":["Reanimar","Desobstruir vías respiratorias","Tratar heridas","Bajar la fiebre"],"correcta":1},{"pregunta":"¿Quién la describió?","opciones":["Pasteur","Heimlich","Fleming","Salk"],"correcta":1},{"pregunta":"¿Qué se hace si la obstrucción es parcial?","opciones":["Empujar","Animar a toser con fuerza","Golpes en el cuello","RCP"],"correcta":1},{"pregunta":"¿Cuántos empujes se dan?","opciones":["Uno","Tres","Cinco","Diez"],"correcta":2}]'::jsonb),

('ed-fisica', 'eso', '{4}', 'El Entrenamiento por Intervalos', 'El entrenamiento interválico, también conocido como HIIT (High Intensity Interval Training), consiste en alternar periodos cortos de esfuerzo muy intenso con periodos de descanso o baja intensidad. Por ejemplo, 30 segundos de sprint al máximo seguidos de 60 segundos de trote suave, repetidos varias veces. Se ha popularizado mucho en los últimos años por su eficiencia.

Los estudios han demostrado que 20-30 minutos de HIIT pueden mejorar la capacidad cardiovascular tanto o más que una hora de entrenamiento continuo moderado. Además, el HIIT aumenta el consumo energético durante las horas posteriores al ejercicio (lo que se llama efecto EPOC: consumo de oxígeno elevado tras el ejercicio), ayudando a quemar grasa de forma más eficiente.

El HIIT puede adaptarse a cualquier nivel de forma física. Un principiante puede empezar con intervalos más cortos e intensidades moderadas, aumentándolos progresivamente. No conviene hacerlo todos los días, porque exige una recuperación más larga: dos o tres sesiones semanales son suficientes. Además, requiere un buen calentamiento previo porque los picos de intensidad aumentan el riesgo de lesión si el cuerpo no está preparado. Para adolescentes, el HIIT bien supervisado es seguro y eficaz.', '[{"pregunta":"¿Qué significa HIIT?","opciones":["High Intensity Interval Training","Hard Intense Time","High Impact Technique","Hill Interval Training"],"correcta":0},{"pregunta":"¿Cuánto puede durar una sesión eficaz?","opciones":["5 minutos","20-30 minutos","2 horas","5 horas"],"correcta":1},{"pregunta":"¿Cuántas sesiones por semana son suficientes?","opciones":["Todos los días","Dos o tres","Una al mes","Cinco o seis"],"correcta":1},{"pregunta":"¿Qué es el efecto EPOC?","opciones":["Ninguna idea","Consumo de oxígeno elevado tras el ejercicio","Un deporte","Una dieta"],"correcta":1}]'::jsonb),

('ed-fisica', 'eso', '{4}', 'La Planificación del Entrenamiento', 'Un buen entrenamiento no consiste en hacer ejercicio al azar, sino en seguir una planificación que tenga en cuenta objetivos, tiempo disponible, nivel inicial y descanso. La planificación profesional divide el tiempo en tres grandes etapas: periodo preparatorio (se construye la base física), periodo competitivo (se mantiene y perfecciona la forma) y periodo de transición (se descansa activamente).

Existen varios principios fundamentales del entrenamiento. El principio de sobrecarga dice que, para mejorar, el esfuerzo debe ser mayor al que el cuerpo está acostumbrado. El principio de progresión indica que los aumentos deben ser graduales, nunca bruscos. El principio de especificidad señala que cada tipo de entrenamiento produce adaptaciones específicas: si quieres correr más rápido, entrena corriendo; si quieres nadar mejor, nada.

Finalmente, el principio de individualidad recuerda que cada persona responde distinto al entrenamiento según su genética, su edad, su nivel previo y su capacidad de recuperación. Por eso las rutinas estandarizadas rara vez funcionan igual para todos. Los entrenadores profesionales diseñan programas personalizados y los ajustan según los resultados observados. En el contexto escolar, el profesor busca un equilibrio entre trabajar con el grupo y atender las diferencias individuales.', '[{"pregunta":"¿Cuál es el primer periodo?","opciones":["Competitivo","Preparatorio","Transición","De descanso"],"correcta":1},{"pregunta":"¿Qué dice el principio de sobrecarga?","opciones":["Descansar mucho","El esfuerzo debe superar al habitual","Entrenar suave","No cambiar"],"correcta":1},{"pregunta":"¿Qué significa especificidad?","opciones":["Nada especial","Cada ejercicio da adaptaciones específicas","Solo para atletas","Un tipo de peso"],"correcta":1},{"pregunta":"¿Por qué importa la individualidad?","opciones":["Cada persona responde distinto","Todos somos iguales","No importa","Solo para expertos"],"correcta":0}]'::jsonb),

('ed-fisica', 'eso', '{4}', 'El Golpe de Calor', 'El golpe de calor es una emergencia médica que ocurre cuando el cuerpo no puede regular su temperatura y esta supera los 40°C. Se produce sobre todo en días calurosos, haciendo ejercicio al sol sin suficiente hidratación, o en espacios cerrados sin ventilación. Los niños, los ancianos y los deportistas son especialmente vulnerables, y sin atención rápida puede ser mortal.

Los síntomas aparecen de forma progresiva. Al principio, la víctima suda profusamente, siente sed intensa, debilidad y calambres musculares. Si el proceso avanza, puede dejar de sudar, presentar piel caliente y seca, confusión, mareo, dolor de cabeza intenso y, en casos graves, pérdida de consciencia o convulsiones. Este último estadio se llama shock térmico y requiere atención médica inmediata.

Para actuar, hay que trasladar a la víctima a un lugar fresco y con sombra, quitarle el exceso de ropa, aplicar paños húmedos en cuello, axilas e ingles, y darle a beber pequeños sorbos de agua fresca si está consciente. No se debe dar agua helada de golpe ni medicamentos. La prevención se basa en hidratarse antes y durante la actividad, usar ropa ligera y transpirable, evitar las horas de más calor y llevar gorra o protección solar.', '[{"pregunta":"¿A partir de qué temperatura se considera grave?","opciones":["36°C","38°C","40°C","45°C"],"correcta":2},{"pregunta":"¿Qué síntoma aparece al avanzar?","opciones":["Más sudor","Piel caliente y seca","Hipotermia","Frío"],"correcta":1},{"pregunta":"¿Qué NO se debe hacer?","opciones":["Dar sombra","Agua helada de golpe","Paños húmedos","Quitar ropa"],"correcta":1},{"pregunta":"¿Cómo se previene?","opciones":["Más ropa","Hidratación, sombra, evitar calor","Hacer más ejercicio","Ninguna"],"correcta":1}]'::jsonb),

('ed-fisica', 'eso', '{4}', 'Los Pilates y su Origen', 'El método Pilates es un sistema de ejercicio desarrollado a principios del siglo XX por el alemán Joseph Pilates. Nacido frágil, investigó distintas disciplinas (yoga, gimnasia, artes marciales) para mejorar su propia salud. Durante la Primera Guerra Mundial, trabajando en un campo de internamiento, empezó a diseñar ejercicios para ayudar a los heridos, utilizando incluso muelles de las camas como resistencia.

El método Pilates se basa en seis principios fundamentales: concentración, control, centralización (trabajar desde el core), fluidez, precisión y respiración. Los ejercicios se realizan con movimientos lentos y controlados, prestando atención constante a la alineación y a la respiración. Se puede practicar en colchoneta o en máquinas específicas como el Reformer, el Cadillac o la Silla.

Sus beneficios son variados: fortalece el core, mejora la postura, aumenta la flexibilidad, alivia dolores de espalda y ayuda a recuperarse de lesiones. Por ello es muy usado por bailarines, deportistas profesionales y personas con problemas posturales. En la Educación Física se pueden incluir ejercicios básicos de Pilates como parte del trabajo de flexibilidad y control corporal, especialmente en sesiones de relajación o vuelta a la calma.', '[{"pregunta":"¿Quién creó el método Pilates?","opciones":["Joseph Pilates","Heimlich","Cooper","Cristofori"],"correcta":0},{"pregunta":"¿Dónde empezó a diseñar ejercicios?","opciones":["Nueva York","Campo de internamiento en la 1ª Guerra Mundial","Olimpia","Moscú"],"correcta":1},{"pregunta":"¿Cuántos principios tiene?","opciones":["Tres","Cuatro","Seis","Diez"],"correcta":2},{"pregunta":"¿Qué aparato se usa en Pilates?","opciones":["Reformer","Batería","Piano","Remo"],"correcta":0}]'::jsonb),

('ed-fisica', 'eso', '{4}', 'El Deporte Adaptado', 'El deporte adaptado es aquel pensado para que puedan practicarlo personas con discapacidad física, sensorial o intelectual. Modifica las reglas, los materiales o los espacios del deporte convencional para hacerlo accesible. Lejos de ser actividades menores, los deportes adaptados exigen un altísimo nivel técnico y físico, como se comprueba en los Juegos Paralímpicos, que se celebran tras cada edición de los Juegos Olímpicos desde 1960.

Existen muchas variantes. El baloncesto en silla de ruedas usa prácticamente las mismas reglas que el baloncesto convencional, adaptándolas al uso de la silla. El goalball es un deporte específico para personas ciegas: se juega con un balón sonoro que los jugadores deben lanzar hacia la portería rival, defendiendo con el cuerpo. El fútbol 5 también se disputa con personas invidentes, guiadas por las voces de los compañeros y el sonido del balón.

En Educación Física, el deporte adaptado permite trabajar la empatía y la inclusión. Ejercicios como jugar al baloncesto con los ojos cerrados o con las piernas atadas ayudan a los alumnos a ponerse en la situación de otros cuerpos. Muchos centros también incluyen actividades de deporte adaptado para promover valores, y cada vez más institutos tienen equipos mixtos donde juegan alumnos con y sin discapacidad.', '[{"pregunta":"¿Desde cuándo se celebran los Juegos Paralímpicos?","opciones":["1920","1960","1980","2000"],"correcta":1},{"pregunta":"¿Cómo es el balón del goalball?","opciones":["Normal","Sonoro","Eléctrico","Pintado"],"correcta":1},{"pregunta":"¿Con qué se juega al fútbol 5 para invidentes?","opciones":["Con balón sonoro","Con silla","Con guante","Con gafas"],"correcta":0},{"pregunta":"¿Qué valores fomenta en clase?","opciones":["Competitividad","Empatía e inclusión","Individualismo","Velocidad"],"correcta":1}]'::jsonb),

('ed-fisica', 'eso', '{4}', 'El Dopaje en el Deporte', 'El dopaje es el uso de sustancias prohibidas o métodos ilícitos para mejorar el rendimiento deportivo. Constituye una de las mayores amenazas para la integridad del deporte moderno porque rompe la igualdad de condiciones entre competidores y pone en grave riesgo la salud. La Agencia Mundial Antidopaje (AMA) publica cada año una lista de sustancias y métodos prohibidos que se revisa continuamente.

Las sustancias dopantes más conocidas son los esteroides anabolizantes, que favorecen el aumento de masa muscular; la eritropoyetina o EPO, que incrementa los glóbulos rojos y, con ellos, la capacidad de transportar oxígeno; los estimulantes, que mejoran la concentración y enmascaran la fatiga; y los diuréticos, usados para ocultar otras sustancias o perder peso rápidamente. Todas tienen efectos secundarios graves, desde problemas cardiovasculares hasta trastornos hormonales e incluso la muerte.

Los controles antidopaje se realizan tanto en competición como fuera de ella, con análisis de orina y sangre. Si un deportista da positivo, puede ser sancionado con suspensiones largas o definitivas, pérdida de medallas y exclusión de torneos futuros. El dopaje ha sido protagonista de grandes escándalos, como el caso Armstrong o el dopaje sistemático ruso. La educación, el control y las sanciones ejemplares son las herramientas principales contra esta práctica.', '[{"pregunta":"¿Qué es la AMA?","opciones":["Una federación","La Agencia Mundial Antidopaje","Un club","Un atleta"],"correcta":1},{"pregunta":"¿Qué hace la EPO?","opciones":["Aumenta músculos","Incrementa glóbulos rojos","Baja peso","Da energía instantánea"],"correcta":1},{"pregunta":"¿Qué sustancia aumenta masa muscular?","opciones":["EPO","Diuréticos","Esteroides anabolizantes","Estimulantes"],"correcta":2},{"pregunta":"¿Cómo se detecta el dopaje?","opciones":["A ojo","Análisis de orina y sangre","Foto","Encuesta"],"correcta":1}]'::jsonb),

('ed-fisica', 'eso', '{4}', 'La Relajación y la Respiración', 'La relajación es el proceso mediante el cual el cuerpo y la mente reducen su nivel de activación. Es una habilidad que se puede aprender y entrenar, y tiene importantes beneficios para la salud: disminuye el estrés, mejora el sueño, reduce la tensión muscular, favorece la concentración y ayuda a gestionar mejor las emociones. En el deporte se usa para recuperarse tras el esfuerzo y para afrontar competiciones con serenidad.

Existen numerosas técnicas de relajación. La relajación muscular progresiva de Jacobson consiste en tensar y relajar alternativamente los distintos grupos musculares, lo que enseña al cuerpo la diferencia entre tensión y reposo. El entrenamiento autógeno de Schultz utiliza autosugestión con frases como "mi brazo derecho pesa mucho" para inducir sensaciones de peso y calor. La meditación mindfulness propone observar la respiración y los pensamientos sin juzgarlos.

La respiración es la herramienta más importante. Aprender a respirar lenta y profundamente con el diafragma (no solo con el pecho) activa el sistema nervioso parasimpático, que es el responsable de la calma. Una técnica eficaz es la respiración cuadrada: inspirar en cuatro segundos, retener cuatro, espirar cuatro y retener cuatro. Se repite varias veces y calma rápidamente. En Educación Física se usa al final de la sesión como vuelta a la calma.', '[{"pregunta":"¿Qué técnica tensa y relaja músculos?","opciones":["Autógeno","Jacobson","Mindfulness","Tai chi"],"correcta":1},{"pregunta":"¿Qué sistema activa la respiración lenta?","opciones":["Simpático","Parasimpático","Digestivo","Endocrino"],"correcta":1},{"pregunta":"¿En qué consiste la respiración cuadrada?","opciones":["Inspirar 4, retener 4, espirar 4, retener 4","Respirar fuerte","Solo inspirar","Contar hasta cien"],"correcta":0},{"pregunta":"¿Cuándo se usa en EF?","opciones":["Al principio","Vuelta a la calma","En mitad","Nunca"],"correcta":1}]'::jsonb);

-- ============================================================
-- PROGRAMACIÓN - 1º ESO (Scratch)
-- ============================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('programacion', 'eso', '{1}', 'Scratch: El Gato Programador', 'Scratch es un entorno de programación visual desarrollado por el MIT Media Lab en 2007, pensado especialmente para enseñar a programar a niños y adolescentes. Su característica principal es que no se escribe código en texto, sino que los programas se construyen encajando bloques de colores como si fueran piezas de Lego. Cada bloque representa una instrucción, y al unirlos formamos una secuencia que el ordenador ejecuta.

La mascota de Scratch es un simpático gato naranja llamado Scratchy, que aparece por defecto al abrir el programa. Con él aprendemos los primeros pasos: hacerlo moverse, girar, cambiar de disfraz, hablar mediante bocadillos y reproducir sonidos. A partir de ahí podemos crear historias interactivas, videojuegos simples, animaciones y simulaciones, añadiendo nuestros propios personajes (llamados objetos o sprites) y escenarios.

Scratch está disponible gratuitamente en la web scratch.mit.edu y tiene una gran comunidad mundial donde los usuarios comparten sus proyectos y remezclan los de otros. Esta forma de aprender programando y explorando código ajeno resulta muy motivadora. Aunque Scratch es la puerta de entrada al mundo de la programación, sus conceptos básicos (bucles, condicionales, variables, eventos) son los mismos que se usan en cualquier lenguaje de programación profesional.', '[{"pregunta":"¿Quién creó Scratch?","opciones":["Microsoft","MIT Media Lab","Google","Apple"],"correcta":1},{"pregunta":"¿Cómo se programa en Scratch?","opciones":["Escribiendo código","Encajando bloques visuales","Hablando","Dibujando"],"correcta":1},{"pregunta":"¿Cómo se llaman los personajes?","opciones":["Actores","Sprites u objetos","Agentes","Robots"],"correcta":1},{"pregunta":"¿En qué año se lanzó Scratch?","opciones":["1990","2000","2007","2020"],"correcta":2}]'::jsonb),

('programacion', 'eso', '{1}', 'Los Eventos en Scratch', 'En Scratch, los eventos son aquellos sucesos que ponen en marcha un programa o una parte de él. Sin eventos, los bloques no se ejecutarían porque no habría un momento concreto para empezar. Los eventos más comunes son: al hacer clic en la bandera verde, al pulsar una tecla, al hacer clic sobre un objeto, al recibir un mensaje o al cambiar el fondo.

El bloque "al presionar bandera verde" es el más utilizado, porque inicia todo el programa cuando el usuario pulsa el icono de play. Otros eventos muy útiles son "al presionar tecla espacio" para que el personaje salte, o "al hacer clic en este objeto" para que reaccione al clic del ratón. Varios objetos pueden reaccionar al mismo evento al mismo tiempo, lo que permite coordinar acciones paralelas.

Los eventos también sirven para que los objetos se comuniquen entre sí mediante mensajes. Un objeto puede "enviar un mensaje" a todos los demás, y otros objetos pueden reaccionar con "al recibir mensaje". Esto es muy útil, por ejemplo, cuando un personaje dispara y otro debe recibir el disparo. Los eventos son la forma de escuchar lo que sucede en el programa y reaccionar en consecuencia, un concepto que se usa también en cualquier lenguaje profesional.', '[{"pregunta":"¿Qué hace un evento?","opciones":["Nada","Pone en marcha un programa","Elimina bloques","Cambia colores"],"correcta":1},{"pregunta":"¿Cuál es el evento más usado?","opciones":["Tecla espacio","Bandera verde","Clic objeto","Sonido"],"correcta":1},{"pregunta":"¿Para qué sirven los mensajes?","opciones":["Nada","Comunicar objetos entre sí","Dibujar","Pintar"],"correcta":1},{"pregunta":"¿Qué ocurre al pulsar la bandera?","opciones":["Se borra todo","Se inicia el programa","Se cierra","No hace nada"],"correcta":1}]'::jsonb),

('programacion', 'eso', '{1}', 'Coordenadas en Scratch', 'En Scratch, el escenario es un espacio rectangular donde se mueven los personajes. Para posicionarlos se utiliza un sistema de coordenadas cartesianas, parecido al que aprendemos en matemáticas. El centro del escenario es el punto (0, 0), llamado origen. A partir de ahí, el eje X se extiende horizontalmente y el eje Y verticalmente.

El escenario mide 480 píxeles de ancho por 360 de alto. Por eso los valores de X van desde -240 (extremo izquierdo) hasta +240 (extremo derecho), y los de Y desde -180 (abajo) hasta +180 (arriba). Si queremos colocar un personaje en la esquina superior derecha, usaremos coordenadas cercanas a (240, 180). Si lo queremos en el centro, usaremos (0, 0).

Los bloques de movimiento aprovechan estas coordenadas. "Ir a x: y:" teletransporta al personaje a un punto; "cambiar x por" lo mueve horizontalmente sumando o restando valores; "deslizar a x: y: en n segundos" crea un movimiento animado. Entender las coordenadas permite crear juegos mucho más interesantes, porque podemos calcular distancias, hacer trayectorias y detectar colisiones entre objetos. Es también una excelente forma de practicar matemáticas sin darse cuenta.', '[{"pregunta":"¿Dónde está el origen (0,0)?","opciones":["Esquina","Centro del escenario","Arriba","Abajo"],"correcta":1},{"pregunta":"¿Cuánto mide el escenario de alto?","opciones":["180","240","360","480"],"correcta":2},{"pregunta":"¿Qué valor X tiene el extremo derecho?","opciones":["0","120","240","480"],"correcta":2},{"pregunta":"¿Qué bloque teletransporta?","opciones":["Deslizar","Ir a x: y:","Cambiar x","Rotar"],"correcta":1}]'::jsonb),

('programacion', 'eso', '{1}', 'Pensamiento Computacional', 'El pensamiento computacional es una forma de analizar y resolver problemas basada en los principios que utilizan los informáticos. No es exclusivo de la programación: se puede aplicar a cualquier situación de la vida cotidiana. Sus cuatro pilares son la descomposición, el reconocimiento de patrones, la abstracción y los algoritmos.

La descomposición consiste en dividir un problema grande en partes más pequeñas y manejables. En lugar de afrontar todo de golpe, nos centramos en cada subproblema por separado. El reconocimiento de patrones nos ayuda a identificar semejanzas entre problemas para aplicar soluciones que ya conocemos. La abstracción implica centrarse en lo importante, ignorando los detalles que no aportan. Y los algoritmos son las secuencias ordenadas de pasos que resuelven el problema.

Imagina, por ejemplo, que quieres preparar un desayuno completo. Primero descompones la tarea: hacer café, tostar el pan, servir leche, cortar fruta. Reconoces patrones (el café se hace igual cada mañana), abstraes lo importante (cantidades, tiempos) y sigues un algoritmo concreto (qué hacer primero, qué después). Lo mismo ocurre al programar: descomponemos el programa en funciones, reconocemos estructuras que se repiten, abstraemos lo esencial y escribimos algoritmos claros.', '[{"pregunta":"¿Cuántos pilares tiene el pensamiento computacional?","opciones":["Dos","Tres","Cuatro","Cinco"],"correcta":2},{"pregunta":"¿Qué es la descomposición?","opciones":["Borrar código","Dividir problemas grandes en pequeños","Escribir menos","Eliminar partes"],"correcta":1},{"pregunta":"¿Qué es un algoritmo?","opciones":["Un bloque","Secuencia ordenada de pasos","Un color","Una variable"],"correcta":1},{"pregunta":"¿Se usa solo en programación?","opciones":["Sí","No, se aplica a cualquier problema","Solo en matemáticas","Solo en física"],"correcta":1}]'::jsonb),

('programacion', 'eso', '{1}', 'Los Bloques de Apariencia', 'Scratch dispone de bloques agrupados por categorías. Los de apariencia son los que nos permiten cambiar el aspecto visual de los personajes y del escenario. Son esenciales para crear animaciones, historias y videojuegos con un aspecto dinámico e interactivo, porque transforman los objetos ante los ojos del jugador.

Entre los bloques de apariencia más utilizados están "decir" y "pensar", que muestran bocadillos sobre el personaje, como los de los cómics. "Siguiente disfraz" cambia al siguiente dibujo del objeto: si dibujamos varias posturas, al alternarlas rápidamente creamos la ilusión de movimiento. "Cambiar tamaño por" amplía o reduce el objeto, "ocultar" y "mostrar" lo hacen invisible o visible, y "cambiar efecto color" modifica su apariencia con efectos gráficos.

Los bloques de fondo también pertenecen a esta categoría. Podemos cambiar el escenario con "cambiar fondo a" o alternarlos con "siguiente fondo", lo que resulta útil para cambiar de escena en una historia o de pantalla en un juego. Combinando todos estos bloques con bucles y eventos, podemos crear experiencias visuales sorprendentes, aunque trabajemos solo con los pocos elementos que Scratch proporciona por defecto.', '[{"pregunta":"¿Qué hacen los bloques de apariencia?","opciones":["Mueven","Cambian aspecto visual","Suenan","Calculan"],"correcta":1},{"pregunta":"¿Qué hace siguiente disfraz?","opciones":["Pinta","Cambia al siguiente dibujo del objeto","Elimina","Duplica"],"correcta":1},{"pregunta":"¿Qué bloque muestra un bocadillo?","opciones":["Decir","Mover","Rotar","Sonar"],"correcta":0},{"pregunta":"¿Qué se puede cambiar además del objeto?","opciones":["Nada","El fondo del escenario","Solo el tamaño","Solo el color"],"correcta":1}]'::jsonb),

('programacion', 'eso', '{1}', 'Los Bucles Simples en Scratch', 'Un bucle es una estructura que repite una serie de instrucciones varias veces. En Scratch los bucles se representan como bloques con forma de C que abrazan las instrucciones a repetir. El bucle más básico es "por siempre", que ejecuta los bloques que contiene de manera indefinida hasta que el programa se detenga. Es ideal para acciones continuas como el movimiento automático de un personaje.

Otro bucle frecuente es "repetir n veces", que ejecuta las instrucciones una cantidad concreta de veces. Por ejemplo, repetir 10 veces "mover 20 pasos" hará que el personaje se mueva 200 pasos en total, en diez etapas. Este tipo de bucle es útil cuando sabemos exactamente cuántas repeticiones queremos, como al dibujar un polígono con n lados.

El tercer tipo es "repetir hasta que", que sigue repitiendo hasta que se cumple una condición. Por ejemplo, "repetir hasta que tocando el borde" hará que el personaje se mueva hasta chocar con el borde. Estos tres bucles cubren casi todas las necesidades de repetición en un programa. Sin bucles, tendríamos que copiar las mismas instrucciones muchas veces, haciendo el código larguísimo e imposible de mantener. Los bucles hacen nuestros programas mucho más cortos y eficaces.', '[{"pregunta":"¿Qué hace el bucle por siempre?","opciones":["Se ejecuta una vez","Repite indefinidamente","No hace nada","Borra bloques"],"correcta":1},{"pregunta":"¿Cuándo usar repetir n veces?","opciones":["Nunca","Cuando sabemos exactamente cuántas veces","Al azar","Solo si falla"],"correcta":1},{"pregunta":"¿Qué forma tienen los bloques de bucle?","opciones":["Cuadrada","De C","Triangular","Circular"],"correcta":1},{"pregunta":"¿Qué hace repetir hasta que?","opciones":["Repite mientras no se cumpla una condición","Repite una vez","Borra","Crea"],"correcta":0}]'::jsonb),

('programacion', 'eso', '{1}', 'Introducción a los Condicionales', 'Los condicionales son estructuras que permiten a nuestro programa tomar decisiones. Sin ellos, el código ejecutaría siempre lo mismo; con ellos, puede comportarse de manera diferente según las circunstancias. Un condicional comprueba si una condición es verdadera y, en función del resultado, ejecuta unas instrucciones u otras. Es uno de los pilares básicos de cualquier lenguaje de programación.

En Scratch, el condicional más simple es el bloque "si... entonces...", que ejecuta los bloques interiores solo si la condición se cumple. Por ejemplo: si el personaje está tocando el borde, rebotar. Si la condición no se cumple, el programa simplemente sigue adelante sin hacer nada. Este tipo de condicional se llama condicional simple o "if" en lenguajes como Python.

Un condicional más completo es "si... entonces... si no...", que ejecuta un bloque si la condición es verdadera y otro bloque distinto si es falsa. Por ejemplo: si tocando el color rojo, decir "peligro"; si no, decir "seguro". Con este recurso podemos dar a nuestros programas mucha más variedad. Los condicionales se pueden anidar, poniendo unos dentro de otros, para gestionar situaciones más complejas con varias ramas de decisión.', '[{"pregunta":"¿Para qué sirven los condicionales?","opciones":["Para borrar","Tomar decisiones según condiciones","Para sumar","Para pintar"],"correcta":1},{"pregunta":"¿Qué hace si...entonces...si no?","opciones":["Solo una acción","Una acción si es verdad, otra si es falso","Nada","Repetir"],"correcta":1},{"pregunta":"¿Se pueden anidar condicionales?","opciones":["No","Sí, unos dentro de otros","Solo tres","Nunca"],"correcta":1},{"pregunta":"¿Cómo se llama en Python el condicional simple?","opciones":["while","for","if","return"],"correcta":2}]'::jsonb),

('programacion', 'eso', '{1}', 'Creando un Juego de Atrapar', 'Un proyecto típico para iniciarse en Scratch es el clásico juego de atrapar objetos. Consiste en que un personaje, controlado por el jugador, debe coger objetos que caen desde la parte superior de la pantalla antes de que toquen el suelo. Cada objeto atrapado suma puntos y el juego dura hasta que perdemos tres vidas o hasta un tiempo límite.

Para construirlo necesitamos varios elementos. Primero, un personaje (por ejemplo una cesta) que se mueve de izquierda a derecha con las flechas del teclado. Programamos las teclas: "al presionar flecha izquierda, cambiar x por -10". Después, creamos un objeto que va a caer (por ejemplo una manzana) y le damos un movimiento: aparece en la parte superior con una x aleatoria, y cae bajando la y en cada frame.

Añadimos la lógica de captura: si la manzana toca la cesta, suma un punto a una variable "puntos" y vuelve a aparecer arriba en una posición aleatoria. Si toca el suelo, restamos una vida. Cuando las vidas lleguen a cero, mostramos un mensaje de "Game Over". Con estos pocos ingredientes (eventos, bucles, variables, condicionales y aleatoriedad) ya tenemos un juego completo que enseña los conceptos fundamentales de la programación.', '[{"pregunta":"¿Qué controla el jugador?","opciones":["Las manzanas","El personaje de cesta","El fondo","Nada"],"correcta":1},{"pregunta":"¿Qué variable guarda los puntos?","opciones":["Nombre","Puntos","Vidas","Tiempo"],"correcta":1},{"pregunta":"¿Qué ocurre al tocar el suelo?","opciones":["Suma un punto","Resta una vida","Nada","Cambia el fondo"],"correcta":1},{"pregunta":"¿Qué elementos usa el juego?","opciones":["Solo eventos","Eventos, bucles, variables y condicionales","Solo sonido","Solo pintura"],"correcta":1}]'::jsonb),

('programacion', 'eso', '{1}', 'El Editor de Sprites', 'En Scratch, los personajes y objetos se llaman sprites. Aunque el programa ofrece una amplia biblioteca de sprites listos para usar, muchas veces queremos crear nuestros propios personajes o modificar los existentes. Para eso contamos con el editor de sprites, una herramienta de dibujo integrada en Scratch que permite pintar, importar imágenes y diseñar animaciones.

El editor tiene dos modos: mapa de bits y vectorial. El modo mapa de bits trabaja con píxeles, como en Paint: las imágenes están compuestas por puntos de colores y al ampliarlas pierden calidad. El modo vectorial usa formas geométricas definidas por fórmulas matemáticas, lo que permite redimensionar el dibujo sin que se pixele. Para la mayoría de proyectos conviene el modo vectorial, porque da mejores resultados.

Dentro del editor encontramos las herramientas típicas de un programa de dibujo: lápiz, pincel, cubo de pintura, borrador, formas (círculo, rectángulo), selección y texto. Cada sprite puede tener varios "disfraces", que son distintas imágenes del mismo objeto. Alternando los disfraces con "siguiente disfraz" creamos animaciones fluidas, como un personaje caminando al mover alternativamente sus piernas. Dibujar nuestros propios sprites hace que los proyectos sean únicos.', '[{"pregunta":"¿Cómo se llaman los personajes en Scratch?","opciones":["Actores","Sprites","Robots","Agentes"],"correcta":1},{"pregunta":"¿Qué ventaja tiene el modo vectorial?","opciones":["Pierde calidad","No pierde calidad al redimensionar","Es más rápido","Usa menos colores"],"correcta":1},{"pregunta":"¿Qué son los disfraces?","opciones":["Vestidos","Distintas imágenes del mismo sprite","Fondos","Sonidos"],"correcta":1},{"pregunta":"¿Con qué bloque se crea una animación?","opciones":["Siguiente disfraz","Mover","Girar","Sonar"],"correcta":0}]'::jsonb),

('programacion', 'eso', '{1}', 'Las Variables en Programación', 'Una variable es un contenedor con nombre donde guardamos un dato que puede cambiar durante la ejecución del programa. Podemos imaginarla como una caja etiquetada: la etiqueta es el nombre (por ejemplo, "puntos"), y el contenido es el valor que guarda (por ejemplo, 10). A lo largo del programa podemos leer el contenido para usarlo, o sustituirlo por un valor nuevo.

Las variables son esenciales porque permiten que el programa recuerde información. En un juego, una variable "puntos" guarda la puntuación actual y la va aumentando cada vez que acertamos. Una variable "vidas" lleva la cuenta de las vidas restantes. Sin variables no podríamos hacer programas que reaccionen al pasado: cada vez empezarían desde cero, sin saber lo que ha ocurrido antes.

En Scratch, las variables se crean en la categoría Variables. Al crear una, aparecen bloques para "dar valor a" (asignar un valor inicial), "cambiar por" (sumar o restar un valor) y mostrarla en pantalla. Podemos decidir si una variable es para todos los objetos o solo para uno. Las variables son un concepto universal: en cualquier lenguaje de programación del mundo (Python, Java, JavaScript...) existen y funcionan con la misma idea básica.', '[{"pregunta":"¿Qué es una variable?","opciones":["Un dibujo","Un contenedor con nombre donde guardamos un dato","Un bloque","Un sonido"],"correcta":1},{"pregunta":"¿Para qué sirven en un juego?","opciones":["Decorar","Guardar puntos, vidas, tiempo","Cambiar colores","Pintar"],"correcta":1},{"pregunta":"¿Qué bloque asigna un valor inicial?","opciones":["Cambiar por","Dar valor a","Mover","Decir"],"correcta":1},{"pregunta":"¿Existen variables en Python?","opciones":["No","Sí, igual que en cualquier lenguaje","Solo en Scratch","Solo en Java"],"correcta":1}]'::jsonb);

-- ============================================================
-- PROGRAMACIÓN - 2º ESO (variables y bucles)
-- ============================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('programacion', 'eso', '{2}', 'Tipos de Datos: Enteros y Decimales', 'Todas las variables de un programa contienen datos, pero no todos los datos son iguales. Los lenguajes de programación distinguen entre diferentes tipos de datos según su naturaleza y el uso que les daremos. Los dos tipos numéricos fundamentales son los enteros (integers) y los decimales (floats).

Los enteros son números sin parte decimal: -3, 0, 7, 125. Se utilizan para contar elementos discretos, como el número de vidas en un juego, la puntuación acumulada o el número de jugadores conectados. Son más rápidos de procesar por el ordenador y ocupan menos memoria que los decimales. En Python se escriben directamente como 10, 50, -4.

Los decimales, también llamados números de punto flotante, sirven para representar valores con parte fraccionaria: 3.14, -0.5, 100.0. Son imprescindibles cuando necesitamos precisión en medidas físicas, porcentajes o cálculos matemáticos que no dan resultados enteros. Hay que tener cuidado: los decimales en ordenadores no siempre son totalmente exactos debido a la representación binaria interna. Por ejemplo, 0.1 + 0.2 puede dar como resultado 0.30000000000000004 en muchos lenguajes. Por eso, cuando se trabaja con dinero, se suelen usar tipos especiales en lugar de decimales normales.', '[{"pregunta":"¿Qué son los enteros?","opciones":["Con decimales","Sin parte decimal","Solo positivos","Solo negativos"],"correcta":1},{"pregunta":"¿Qué uso típico tienen los enteros?","opciones":["Contar vidas o puntos","Calcular mareas","Dibujar","Sonido"],"correcta":0},{"pregunta":"¿Cómo se llaman los decimales también?","opciones":["Binarios","De punto flotante","Complejos","Irracionales"],"correcta":1},{"pregunta":"¿Son siempre exactos los decimales en ordenador?","opciones":["Sí","No, por la representación binaria","A veces","Solo en Python"],"correcta":1}]'::jsonb),

('programacion', 'eso', '{2}', 'Cadenas de Texto (Strings)', 'Una cadena de texto, conocida en inglés como string, es un tipo de dato que guarda una secuencia de caracteres. Sirve para representar palabras, frases, nombres, mensajes... Cualquier información textual del programa se guarda como una cadena. Para el ordenador, una cadena es realmente una lista ordenada de caracteres, cada uno con su propia posición.

En la mayoría de lenguajes las cadenas se escriben entre comillas, simples o dobles. Por ejemplo: "Hola mundo" o ''Scratch''. Las comillas indican al ordenador dónde empieza y termina el texto. Si olvidamos cerrar las comillas, el programa dará un error porque no sabrá dónde acaba la cadena.

Las cadenas admiten muchas operaciones útiles. Podemos concatenarlas (unirlas) con el símbolo +, convirtiendo "Hola " + "mundo" en "Hola mundo". Podemos obtener su longitud para saber cuántos caracteres tiene, acceder a un carácter concreto por su posición, convertir a mayúsculas o minúsculas, buscar una palabra dentro de la cadena, reemplazar fragmentos, y mucho más. El manejo de cadenas es una de las tareas más frecuentes en programación, porque prácticamente todos los programas leen, procesan y muestran texto en algún momento.', '[{"pregunta":"¿Qué es un string?","opciones":["Un número","Una secuencia de caracteres","Un bucle","Un bloque"],"correcta":1},{"pregunta":"¿Cómo se escriben las cadenas?","opciones":["Sin nada","Entre comillas","Entre paréntesis","Entre corchetes"],"correcta":1},{"pregunta":"¿Qué hace el símbolo + en cadenas?","opciones":["Suma","Concatena","Resta","Divide"],"correcta":1},{"pregunta":"¿Qué ocurre si olvidas cerrar comillas?","opciones":["Nada","Error de programa","Funciona igual","Se corrige solo"],"correcta":1}]'::jsonb),

('programacion', 'eso', '{2}', 'Los Booleanos y la Lógica', 'Un booleano es un tipo de dato muy sencillo pero extremadamente útil: solo puede tener dos valores, verdadero (true) o falso (false). Los booleanos son la base de las decisiones en un programa, porque todo condicional se reduce finalmente a comprobar un valor booleano. El nombre viene del matemático inglés George Boole, creador del álgebra que lleva su nombre.

Los booleanos surgen al comparar valores con operadores relacionales. Por ejemplo, la expresión 5 > 3 devuelve verdadero, mientras que 5 == 2 devuelve falso. Los operadores principales son "mayor que" (>), "menor que" (<), "igual a" (==, con dos signos de igual), "distinto de" (!=), "mayor o igual" (>=) y "menor o igual" (<=). Con ellos podemos construir cualquier comparación numérica.

Los booleanos también admiten operadores lógicos como AND (y), OR (o) y NOT (no), que permiten combinar varias condiciones. Por ejemplo, (edad >= 13 AND edad <= 18) devuelve verdadero si la edad está entre 13 y 18. Estos operadores son fundamentales para crear filtros complejos, validaciones de formularios y lógica de juegos. Sin booleanos, ningún programa podría reaccionar ante diferentes situaciones.', '[{"pregunta":"¿Cuántos valores tiene un booleano?","opciones":["Uno","Dos","Tres","Infinitos"],"correcta":1},{"pregunta":"¿De quién viene el nombre booleano?","opciones":["Lovelace","Boole","Turing","Von Neumann"],"correcta":1},{"pregunta":"¿Qué devuelve 5 > 3?","opciones":["Falso","Verdadero","Cinco","Nada"],"correcta":1},{"pregunta":"¿Qué hace el operador AND?","opciones":["Suma","Requiere que ambas condiciones sean verdaderas","Niega","Divide"],"correcta":1}]'::jsonb),

('programacion', 'eso', '{2}', 'Bucles For y While', 'Los lenguajes de programación profesionales disponen de dos grandes tipos de bucles: el bucle "for" y el bucle "while". Ambos sirven para repetir instrucciones, pero tienen usos distintos y conviene elegir el adecuado en cada caso. Su dominio es fundamental para escribir código eficiente.

El bucle "for" se usa cuando sabemos de antemano cuántas veces queremos repetir. Es el equivalente al bloque "repetir n veces" de Scratch. En Python se escribe así: "for i in range(10)", que significa "repetir 10 veces, con i tomando los valores de 0 a 9". La variable "i" se puede usar dentro del bucle, permitiendo hacer cosas diferentes en cada iteración. Es ideal para recorrer listas y contar elementos.

El bucle "while" se usa cuando no sabemos exactamente cuántas iteraciones se harán, sino que queremos repetir mientras se cumpla una condición. Por ejemplo, "while vida > 0" repetirá el código mientras el jugador tenga vidas. En cada iteración, la condición se vuelve a comprobar. Cuidado: si la condición nunca se vuelve falsa, el bucle se convierte en infinito y el programa se cuelga. Por eso es imprescindible asegurarse de que la condición cambie dentro del bucle.', '[{"pregunta":"¿Cuándo usar for?","opciones":["Siempre","Cuando sabemos cuántas veces","Para sumar","Para borrar"],"correcta":1},{"pregunta":"¿Cuándo usar while?","opciones":["Nunca","Mientras se cumpla una condición","Solo 10 veces","Para dibujar"],"correcta":1},{"pregunta":"¿Qué es un bucle infinito?","opciones":["Un bucle que se detiene","Uno cuya condición nunca se hace falsa","Uno que dura 10 segundos","Uno vacío"],"correcta":1},{"pregunta":"¿Qué hace range(10)?","opciones":["Da 10 como resultado","Genera valores de 0 a 9","Dibuja 10","Nada"],"correcta":1}]'::jsonb),

('programacion', 'eso', '{2}', 'Arrays y Listas', 'Una lista, también llamada array, es una estructura de datos que guarda varios elementos en una sola variable. En lugar de crear diez variables distintas para guardar diez nombres, creamos una lista con los diez nombres y accedemos a ellos por su posición, llamada índice. La primera posición suele ser la 0 (no la 1), una convención heredada del lenguaje C que puede confundir al principio.

Las listas son tremendamente útiles. Podemos recorrerlas con un bucle for, agregar elementos al final, eliminar uno concreto, buscar si un elemento está dentro, ordenar todos sus valores, obtener la longitud o partirla en trozos. En Python una lista se escribe entre corchetes: [10, 20, 30, 40]. Para acceder al segundo elemento usamos lista[1], porque los índices empiezan en 0.

Las listas pueden almacenar datos de cualquier tipo e incluso combinar tipos: ["Ana", 15, True] es una lista válida con un string, un entero y un booleano. También pueden contener otras listas dentro, formando estructuras llamadas listas anidadas o matrices, útiles para representar cuadrículas, tableros de juego o imágenes píxel a píxel. Las listas son el primer paso hacia estructuras de datos más complejas que se estudian en cursos superiores.', '[{"pregunta":"¿Desde qué número empiezan los índices?","opciones":["1","0","-1","10"],"correcta":1},{"pregunta":"¿Cómo se escribe una lista en Python?","opciones":["Con comillas","Entre corchetes [ ]","Entre llaves","Entre paréntesis"],"correcta":1},{"pregunta":"¿Se pueden mezclar tipos en una lista?","opciones":["No","Sí","Solo strings","Solo números"],"correcta":1},{"pregunta":"¿Qué son las listas anidadas?","opciones":["Vacías","Listas dentro de listas","Listas rotas","Listas escondidas"],"correcta":1}]'::jsonb),

('programacion', 'eso', '{2}', 'Las Funciones como Herramientas', 'Una función es un bloque de código con nombre propio que realiza una tarea concreta y puede reutilizarse cuantas veces queramos. Son la forma principal de organizar el código y evitar repeticiones. En lugar de escribir las mismas instrucciones cinco veces, escribimos una función y la llamamos cinco veces. El programa queda más corto, más claro y más fácil de mantener.

Una función puede recibir datos de entrada, llamados parámetros, y devolver un resultado. Por ejemplo, una función "sumar" puede recibir dos números y devolver la suma: sumar(3, 5) devuelve 8. Los parámetros permiten que la misma función se comporte de manera diferente según los datos que recibe. Si los cambiamos, cambia el resultado.

En Python las funciones se definen con la palabra "def": "def sumar(a, b): return a + b". Una vez definida, la función se puede usar en cualquier parte del programa con sumar(2, 3), sumar(100, 200), etc. Las funciones son uno de los pilares de la programación. Nos ayudan a dividir un problema grande en subproblemas pequeños, cada uno resuelto por una función. Esta técnica se llama programación modular y es la base de todo el desarrollo de software profesional.', '[{"pregunta":"¿Qué es una función?","opciones":["Un color","Un bloque de código reutilizable con nombre","Un bucle","Un dibujo"],"correcta":1},{"pregunta":"¿Qué son los parámetros?","opciones":["Nombres","Datos de entrada de la función","Variables globales","Resultados"],"correcta":1},{"pregunta":"¿Con qué palabra se define una función en Python?","opciones":["func","def","function","define"],"correcta":1},{"pregunta":"¿Qué ventajas tienen las funciones?","opciones":["Ninguna","Evitan repeticiones y organizan el código","Son más lentas","Ocupan más"],"correcta":1}]'::jsonb),

('programacion', 'eso', '{2}', 'Depuración y Errores', 'La depuración, en inglés debugging, es el proceso de buscar y corregir errores en un programa. Su nombre viene de una anécdota famosa: en 1947, la informática Grace Hopper encontró una polilla atascada en un relé de uno de los primeros ordenadores, causando un mal funcionamiento. Desde entonces, a los errores de software se les llama "bugs" (bichos) y al proceso de arreglarlos, "debugging".

Existen tres grandes tipos de errores. Los errores de sintaxis ocurren cuando escribimos algo que el lenguaje no entiende, por ejemplo, olvidar cerrar un paréntesis. Los detecta el compilador o intérprete antes de ejecutar. Los errores en tiempo de ejecución ocurren mientras el programa corre: por ejemplo, dividir entre cero o intentar leer un archivo que no existe. Los errores lógicos son los más traicioneros: el programa funciona y no se queja, pero el resultado no es el esperado porque hay un fallo en el razonamiento.

Para depurar usamos técnicas como imprimir variables en puntos clave para ver sus valores, ejecutar el programa paso a paso con un depurador, leer los mensajes de error con atención, y pensar en qué parte del código se produce el problema. La depuración es una habilidad que se aprende con la práctica, y puede llevar más tiempo que escribir el programa original.', '[{"pregunta":"¿De dónde viene la palabra bug?","opciones":["Del inglés moderno","De una polilla en un relé","De Grace Hopper","De un insecto del código"],"correcta":1},{"pregunta":"¿Qué son los errores de sintaxis?","opciones":["Lógicos","Cuando escribimos algo que el lenguaje no entiende","Al ejecutar","Sin error"],"correcta":1},{"pregunta":"¿Cuáles son los más difíciles?","opciones":["Sintaxis","Tiempo de ejecución","Lógicos","Todos iguales"],"correcta":2},{"pregunta":"¿Qué técnica ayuda a depurar?","opciones":["Borrar todo","Imprimir variables en puntos clave","Cerrar programa","No tocar"],"correcta":1}]'::jsonb),

('programacion', 'eso', '{2}', 'Comentarios en el Código', 'Los comentarios son notas que los programadores añaden al código para explicar qué hace una parte concreta o por qué se ha tomado una decisión. El ordenador los ignora completamente al ejecutar el programa, pero son muy útiles para las personas que leen el código, incluyendo al propio autor cuando vuelve a él meses después. Un código bien comentado vale tanto como un código bien escrito.

Cada lenguaje tiene su sintaxis para los comentarios. En Python se usa el símbolo almohadilla (#) al principio de una línea: # esto es un comentario. En JavaScript, C y Java se usa // para comentarios de una línea y /* ... */ para comentarios de varias líneas. En HTML se usan <!-- ... --> y en CSS /* ... */.

Escribir buenos comentarios es un arte. Un comentario no debe repetir lo que ya dice el código ("i = i + 1; # incrementa i en 1" es un mal comentario) sino explicar el porqué, no el qué. Es mejor comentar por qué estamos haciendo algo de una determinada manera ("# usamos +1 porque los usuarios empiezan a contar desde 1"). Los comentarios deben mantenerse actualizados: si cambiamos el código, hay que revisar si los comentarios siguen siendo ciertos, porque un comentario mentiroso es peor que ninguno.', '[{"pregunta":"¿Qué son los comentarios?","opciones":["Instrucciones","Notas que el ordenador ignora al ejecutar","Errores","Variables"],"correcta":1},{"pregunta":"¿Qué símbolo usa Python?","opciones":["//","#","/* */","--"],"correcta":1},{"pregunta":"¿Qué deben explicar los buenos comentarios?","opciones":["El qué","El porqué","Los errores","Los nombres"],"correcta":1},{"pregunta":"¿Qué es peor que no tener comentario?","opciones":["Un comentario mentiroso","Uno corto","Uno largo","Uno en inglés"],"correcta":0}]'::jsonb),

('programacion', 'eso', '{2}', 'Variables Locales y Globales', 'Dentro de un programa, las variables pueden tener distinto alcance o ámbito: algunas son accesibles desde cualquier parte (globales) y otras solo desde la función donde se han creado (locales). Esta distinción, que al principio puede confundir, es clave para escribir programas ordenados y evitar errores.

Una variable global se declara fuera de todas las funciones y puede leerse y modificarse desde cualquier lugar del programa. Las globales son útiles para datos que deben estar disponibles en todas partes, como la puntuación de un juego o la configuración del usuario. Sin embargo, usarlas en exceso es una mala práctica porque hace que el código sea difícil de entender: cualquier función puede cambiar una variable global sin que se note.

Las variables locales se crean dentro de una función y solo existen mientras esa función se está ejecutando. Cuando la función termina, la variable desaparece. Esto es bueno, porque evita que las funciones interfieran entre sí. Cada función trabaja con sus propios datos locales sin molestar a las demás. La regla práctica es: usa siempre variables locales salvo que tengas una buena razón para usar globales. Esta disciplina hace los programas más predecibles y mantenibles.', '[{"pregunta":"¿Dónde se declara una variable global?","opciones":["Dentro de una función","Fuera de todas las funciones","Al final","En un bucle"],"correcta":1},{"pregunta":"¿Hasta cuándo existe una variable local?","opciones":["Siempre","Mientras la función se ejecuta","Diez segundos","Hasta reiniciar"],"correcta":1},{"pregunta":"¿Qué es mala práctica?","opciones":["Usar locales","Abusar de las globales","Usar funciones","Comentar"],"correcta":1},{"pregunta":"¿Qué ventaja tienen las locales?","opciones":["Son más lentas","Evitan interferencias entre funciones","Usan menos memoria","Son visibles"],"correcta":1}]'::jsonb),

('programacion', 'eso', '{2}', 'La Entrada y Salida en Programas', 'Todo programa útil interactúa con el mundo exterior recibiendo datos (entrada) y mostrando resultados (salida). La forma más básica es mediante el teclado y la pantalla. En Python, la función input() pide al usuario que escriba algo y devuelve la cadena que ha introducido. La función print() muestra un mensaje en la pantalla. Con estas dos funciones básicas ya podemos hacer programas interactivos sencillos.

La entrada puede venir de muchas fuentes distintas: el teclado, el ratón, un archivo, una base de datos, una cámara, un sensor, una página web... Dependiendo del tipo de programa, los datos entrarán por un canal u otro. Lo importante es validar siempre la entrada antes de usarla: si esperamos un número y el usuario escribe letras, el programa debe detectarlo y pedir otro dato en lugar de bloquearse.

La salida también puede dirigirse a lugares muy variados: pantalla, altavoces, impresora, archivos, red. Los programas modernos combinan múltiples fuentes y destinos. Una aplicación de videollamada, por ejemplo, recibe entrada de la cámara y el micrófono, y envía salida al servidor remoto, que la reenvía a los participantes. Comprender el flujo de datos entrada-proceso-salida ayuda a diseñar cualquier programa: ¿qué datos entran, cómo los proceso, qué resultados muestro?', '[{"pregunta":"¿Qué hace input() en Python?","opciones":["Muestra un mensaje","Pide al usuario que escriba","Calcula","Borra"],"correcta":1},{"pregunta":"¿Qué hace print()?","opciones":["Pide datos","Muestra mensajes en pantalla","Suma","Rota"],"correcta":1},{"pregunta":"¿Por qué validar la entrada?","opciones":["No hace falta","Para evitar bloqueos si el dato es inválido","Por diversión","Porque lo dice Python"],"correcta":1},{"pregunta":"¿Qué esquema siguen los programas?","opciones":["Entrada-proceso-salida","Salida-proceso","Solo proceso","Solo entrada"],"correcta":0}]'::jsonb);

-- ============================================================
-- PROGRAMACIÓN - 3º ESO (Python)
-- ============================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('programacion', 'eso', '{3}', 'Python: Sencillo y Potente', 'Python es uno de los lenguajes de programación más populares del mundo, tanto para principiantes como para profesionales. Fue creado en 1991 por el holandés Guido van Rossum, quien buscaba un lenguaje fácil de leer y escribir. El nombre Python no viene de la serpiente, sino del grupo de humoristas británicos Monty Python, del que el creador era admirador. Desde entonces, su filosofía ha sido siempre la simplicidad.

Lo que distingue a Python es su sintaxis clara. No usa llaves ni punto y coma: los bloques de código se delimitan mediante la indentación (sangrado). Esto obliga al programador a escribir código ordenado y legible, pero al principio puede confundir. Por ejemplo, un bloque "if" se escribe así: "if x > 0:" y la siguiente línea debe estar sangrada con cuatro espacios. Si no, Python dará un error.

Python se usa en áreas muy variadas: desarrollo web (con frameworks como Django o Flask), ciencia de datos (con pandas y numpy), inteligencia artificial (con TensorFlow y PyTorch), automatización de tareas, scripts para administración de sistemas, videojuegos (con Pygame), y muchos otros campos. Su enorme comunidad y su rica biblioteca estándar (funcionalidades incluidas sin instalar nada) lo hacen una opción excelente para aprender a programar hoy.', '[{"pregunta":"¿Quién creó Python?","opciones":["Guido van Rossum","Linus Torvalds","James Gosling","Bjarne Stroustrup"],"correcta":0},{"pregunta":"¿Cómo se delimitan los bloques en Python?","opciones":["Llaves","Indentación","Paréntesis","Punto y coma"],"correcta":1},{"pregunta":"¿De dónde viene el nombre Python?","opciones":["De la serpiente","Del grupo Monty Python","De un científico","De un río"],"correcta":1},{"pregunta":"¿Qué framework de IA usa Python?","opciones":["Laravel","TensorFlow","Spring","Ember"],"correcta":1}]'::jsonb),

('programacion', 'eso', '{3}', 'Diccionarios en Python', 'Un diccionario es una estructura de datos que guarda información asociando claves con valores. A diferencia de las listas, donde los elementos se acceden por su posición (0, 1, 2...), los diccionarios se acceden por una clave que puede ser cualquier nombre significativo. Es como una guía telefónica: en lugar de buscar al contacto número 27, buscas directamente por nombre.

En Python se escriben entre llaves, separando clave y valor con dos puntos, y los pares entre sí con comas: alumno = {"nombre": "Ana", "edad": 14, "curso": "3ESO"}. Para acceder al valor usamos alumno["nombre"], que devuelve "Ana". Podemos agregar nuevas claves, modificar valores, eliminar entradas y recorrer todas las parejas con un bucle.

Los diccionarios son extremadamente útiles cuando queremos estructurar información. Por ejemplo, los datos de un usuario en una aplicación se pueden guardar como un diccionario con todas sus propiedades. En las APIs web modernas, los datos se intercambian en un formato llamado JSON, que es casi idéntico a los diccionarios de Python. Por eso, dominarlos es fundamental para trabajar con servicios web. En otros lenguajes, este tipo de estructura se llama también "objeto", "mapa" o "tabla hash".', '[{"pregunta":"¿Cómo se accede a un diccionario?","opciones":["Por posición","Por clave","Por color","Por tamaño"],"correcta":1},{"pregunta":"¿Qué separa clave y valor?","opciones":["Coma","Dos puntos","Punto","Guion"],"correcta":1},{"pregunta":"¿Con qué formato se intercambian datos en webs?","opciones":["XML","JSON","CSV","Excel"],"correcta":1},{"pregunta":"¿Cómo se llaman en otros lenguajes?","opciones":["Listas","Arrays","Mapas o tablas hash","Tuplas"],"correcta":2}]'::jsonb),

('programacion', 'eso', '{3}', 'HTML: La Estructura de la Web', 'HTML significa HyperText Markup Language (Lenguaje de Marcado de Hipertexto) y es el código con el que se construyen todas las páginas web. No es un lenguaje de programación en sentido estricto, sino un lenguaje de marcado: sirve para estructurar el contenido de una página, indicando qué es un título, un párrafo, una imagen, un enlace... Sin HTML, la Web tal como la conocemos no existiría.

El HTML utiliza etiquetas delimitadas por los símbolos <>. Por ejemplo, <h1>Hola</h1> define un encabezado de primer nivel con el texto "Hola", y <p>texto</p> define un párrafo. Las etiquetas suelen ir por pares: una de apertura (<h1>) y otra de cierre (</h1>). Todo el contenido de una página se encierra entre las etiquetas <html> y </html>, divididas en dos partes: <head> (con información sobre la página) y <body> (con lo que el visitante ve).

HTML se combina con CSS, que define el aspecto visual (colores, tipos de letra, disposición), y con JavaScript, que añade interactividad. Estas tres tecnologías son la base del desarrollo web frontend. Aprender HTML es el primer paso para cualquier persona que quiera crear páginas web o entender cómo funcionan las que visita a diario. Es sencillo de aprender y se aprende practicando.', '[{"pregunta":"¿Qué significa HTML?","opciones":["HyperText Markup Language","HighTech Modern Language","Home Tool Markup","HighText Machine Lang"],"correcta":0},{"pregunta":"¿Es un lenguaje de programación?","opciones":["Sí","No, es de marcado","A veces","Nunca"],"correcta":1},{"pregunta":"¿Qué etiqueta envuelve todo el documento?","opciones":["<body>","<html>","<head>","<main>"],"correcta":1},{"pregunta":"¿Qué define CSS?","opciones":["La estructura","El aspecto visual","La interactividad","Nada"],"correcta":1}]'::jsonb),

('programacion', 'eso', '{3}', 'CSS: Dar Estilo a la Web', 'CSS (Cascading Style Sheets, Hojas de Estilo en Cascada) es el lenguaje que permite dar apariencia visual a las páginas HTML. Con HTML decimos "esto es un título y esto un párrafo"; con CSS decimos "el título es azul y está en mayúsculas, el párrafo tiene un margen de 20 píxeles". Separar estructura y estilo es una buena práctica que facilita mantener y rediseñar cualquier web.

Una regla CSS se compone de un selector (a qué elementos afecta) y una serie de propiedades entre llaves. Por ejemplo: "h1 { color: blue; font-size: 30px; }" aplica color azul y tamaño de fuente 30 píxeles a todos los elementos h1 de la página. Los selectores pueden ser etiquetas (h1, p), clases (.destacado) o identificadores (#menu). Las clases y los ids se añaden a las etiquetas HTML para identificarlas.

Además de colores y tamaños, CSS permite controlar cualquier aspecto visual: fondos, bordes, sombras, posicionamiento, animaciones, responsive design (adaptación a distintas pantallas), y un largo etcétera. Las webs modernas usan técnicas avanzadas como Flexbox y CSS Grid para crear diseños complejos que se adaptan automáticamente a móviles, tabletas y ordenadores. CSS, aunque parezca simple al principio, es una herramienta muy rica y en constante evolución.', '[{"pregunta":"¿Qué significa CSS?","opciones":["Central Style System","Cascading Style Sheets","Computer Style Script","Core Style Sheet"],"correcta":1},{"pregunta":"¿Qué hacen los selectores?","opciones":["Nada","Indican a qué elementos se aplican las reglas","Eliminan","Añaden HTML"],"correcta":1},{"pregunta":"¿Qué son Flexbox y Grid?","opciones":["Navegadores","Técnicas de diseño flexible","Colores","Fuentes"],"correcta":1},{"pregunta":"¿Qué ventaja tiene separar HTML y CSS?","opciones":["Ninguna","Facilita mantener y rediseñar","Es más lento","Solo estético"],"correcta":1}]'::jsonb),

('programacion', 'eso', '{3}', 'JavaScript: Interactividad Web', 'JavaScript es el lenguaje de programación de la Web. Junto con HTML y CSS forma el trío fundamental del desarrollo web: HTML da la estructura, CSS el aspecto y JavaScript la interactividad. Gracias a JavaScript, las páginas web pueden reaccionar al usuario, actualizarse sin recargar, mostrar animaciones complejas, validar formularios, comunicarse con servidores y muchísimo más.

JavaScript fue creado en 1995 por Brendan Eich para Netscape, en apenas diez días. Pese a su origen apresurado, se convirtió en el lenguaje más usado en la Web. Hoy se ejecuta directamente en todos los navegadores modernos: no necesita instalación alguna. Los programadores pueden añadir código JavaScript a una página HTML mediante la etiqueta <script> o enlazando un archivo .js externo.

Pese a su nombre, JavaScript no tiene apenas relación con Java, que es otro lenguaje distinto. La similitud se debe a motivos de marketing de los años noventa. JavaScript ha evolucionado enormemente con los años y hoy se usa también fuera del navegador: con Node.js se pueden escribir servidores web, herramientas de línea de comandos, aplicaciones de escritorio (con Electron) e incluso apps móviles (con React Native). Es probablemente el lenguaje más versátil del momento.', '[{"pregunta":"¿En qué año fue creado JavaScript?","opciones":["1990","1995","2000","2010"],"correcta":1},{"pregunta":"¿En cuántos días se diseñó?","opciones":["Uno","Diez","Un mes","Un año"],"correcta":1},{"pregunta":"¿Qué relación tiene con Java?","opciones":["Son el mismo","Casi ninguna, solo el nombre","Java es anterior","JavaScript es mejor"],"correcta":1},{"pregunta":"¿Qué permite Node.js?","opciones":["Nada","Ejecutar JavaScript fuera del navegador","Crear HTML","Editar CSS"],"correcta":1}]'::jsonb),

('programacion', 'eso', '{3}', 'Algoritmos de Búsqueda', 'Un algoritmo de búsqueda sirve para encontrar un elemento concreto dentro de un conjunto de datos. Es una tarea fundamental en informática porque constantemente necesitamos localizar información: un usuario en una base de datos, un producto en una tienda online, una palabra en un texto. La eficiencia del algoritmo determina cuánto tardaremos en obtener el resultado.

El algoritmo más sencillo es la búsqueda lineal. Consiste en recorrer todos los elementos uno a uno, comparando cada uno con el que buscamos. Si lo encontramos, devolvemos su posición. Si llegamos al final sin encontrarlo, devolvemos "no existe". Es fácil de programar y funciona siempre, pero es lenta cuando los datos son muy grandes: si hay un millón de elementos, podríamos necesitar un millón de comparaciones en el peor caso.

Un algoritmo mucho más rápido es la búsqueda binaria, pero requiere que los datos estén ordenados. Consiste en comparar el elemento buscado con el del medio: si coincide, lo hemos encontrado; si es menor, buscamos en la mitad inferior; si es mayor, en la superior. Repetimos el proceso hasta encontrarlo o determinar que no existe. En un millón de elementos, la búsqueda binaria necesita solo unas veinte comparaciones. Es un ejemplo claro de cómo un buen algoritmo puede transformar el rendimiento de un programa.', '[{"pregunta":"¿Qué hace la búsqueda lineal?","opciones":["Revisa elementos uno a uno","Va al azar","Solo mira el primero","No busca"],"correcta":0},{"pregunta":"¿Qué requiere la búsqueda binaria?","opciones":["Nada","Que los datos estén ordenados","Que sean pequeños","Que sean texto"],"correcta":1},{"pregunta":"¿Cuántas comparaciones necesita binaria con un millón?","opciones":["Un millón","Cien mil","Veinte","Una"],"correcta":2},{"pregunta":"¿Por qué importa el algoritmo elegido?","opciones":["Para hacer bonito","Determina el rendimiento","Por política","Por moda"],"correcta":1}]'::jsonb),

('programacion', 'eso', '{3}', 'Algoritmos de Ordenación', 'Los algoritmos de ordenación organizan los elementos de una lista según un criterio (alfabético, numérico, por fecha...). Es una de las operaciones más estudiadas en informática, porque muchas otras tareas son mucho más eficientes si los datos están previamente ordenados. Existen decenas de algoritmos distintos, cada uno con ventajas e inconvenientes.

El más sencillo de entender es el ordenamiento por burbuja (bubble sort): se comparan pares de elementos adyacentes y se intercambian si están en orden incorrecto, repitiendo hasta que ninguna pareja necesite intercambio. Es fácil de programar pero lento para listas grandes. Otro sencillo es el ordenamiento por selección: se busca el menor elemento y se coloca al principio, luego el siguiente, y así sucesivamente.

Los algoritmos eficientes, como el quicksort y el mergesort, usan técnicas más inteligentes y pueden ordenar millones de elementos en segundos. El quicksort elige un elemento "pivote" y divide la lista en dos partes: los menores y los mayores. Después ordena cada parte por separado usando el mismo método (recursión). En el mundo real, los programadores rara vez implementan estos algoritmos a mano: los lenguajes modernos ya incluyen funciones de ordenación altamente optimizadas en sus bibliotecas estándar.', '[{"pregunta":"¿Qué hace el ordenamiento burbuja?","opciones":["Elige el menor","Compara pares adyacentes y los intercambia","No funciona","Ordena al azar"],"correcta":1},{"pregunta":"¿Cuál es más eficiente?","opciones":["Burbuja","Quicksort","Selección","Por inserción pura"],"correcta":1},{"pregunta":"¿Qué es un pivote en quicksort?","opciones":["El menor","Un elemento que divide la lista","El último","Nada"],"correcta":1},{"pregunta":"¿Qué técnica usa quicksort?","opciones":["Fuerza bruta","Recursión","Intuición","Ninguna"],"correcta":1}]'::jsonb),

('programacion', 'eso', '{3}', 'Git y el Control de Versiones', 'Git es un sistema de control de versiones creado en 2005 por Linus Torvalds, el creador de Linux. Sirve para guardar el historial de cambios de un proyecto de software, permitiendo volver a versiones anteriores, comparar modificaciones y trabajar en equipo sin sobrescribirse los cambios unos a otros. Hoy es una herramienta imprescindible para cualquier programador profesional.

El funcionamiento básico de Git es simple: a medida que el programador hace cambios en los archivos, puede "guardarlos" creando un commit. Cada commit es una fotografía del estado del proyecto en ese momento, con un mensaje que describe el cambio. El historial completo de commits permite ver la evolución del código, volver a versiones pasadas si hay errores y comparar diferencias entre versiones.

Git también permite trabajar con ramas (branches). Una rama es una línea paralela de desarrollo: un programador puede crear una rama para probar una nueva funcionalidad sin afectar al código principal. Cuando termina, fusiona (merge) su rama con la principal. Esta capacidad hace que equipos de decenas o cientos de personas puedan colaborar en el mismo proyecto sin caos. Las plataformas como GitHub, GitLab o Bitbucket alojan proyectos Git en la nube y facilitan el trabajo colaborativo a escala global.', '[{"pregunta":"¿Quién creó Git?","opciones":["Guido van Rossum","Linus Torvalds","Brendan Eich","Tim Berners-Lee"],"correcta":1},{"pregunta":"¿Qué es un commit?","opciones":["Un error","Una fotografía del proyecto en un momento","Un archivo","Una rama"],"correcta":1},{"pregunta":"¿Qué es una rama en Git?","opciones":["Un bucle","Una línea paralela de desarrollo","Un error","Una función"],"correcta":1},{"pregunta":"¿Qué es GitHub?","opciones":["Un lenguaje","Una plataforma de alojamiento Git","Un compilador","Una base de datos"],"correcta":1}]'::jsonb),

('programacion', 'eso', '{3}', 'Expresiones Regulares', 'Las expresiones regulares (regex) son patrones que describen conjuntos de cadenas de texto. Permiten buscar, validar y manipular texto de forma muy potente. Por ejemplo, con una expresión regular podemos comprobar si una dirección de correo electrónico tiene formato correcto, extraer todos los números de un texto o reemplazar palabras que siguen un cierto patrón. Son una herramienta transversal, disponible en casi todos los lenguajes de programación.

Su sintaxis usa caracteres especiales que representan tipos de letras. Por ejemplo, \\d representa cualquier dígito del 0 al 9, \\w cualquier letra o número, y . cualquier carácter. También se pueden indicar repeticiones: * significa "cero o más veces", + significa "una o más veces", y {n} significa "exactamente n veces". Combinando estos elementos se construyen patrones muy expresivos.

Un ejemplo: la expresión "\\d{3}-\\d{4}" busca un grupo de tres dígitos, seguido de un guion y cuatro dígitos más. Eso podría usarse para validar números de teléfono con formato "555-1234". La potencia de las regex es enorme, pero su sintaxis puede parecer críptica al principio. Hay herramientas online como regex101 que ayudan a construir y probar expresiones visualmente. Dominar regex es una habilidad muy valorada en programación, análisis de datos y administración de sistemas.', '[{"pregunta":"¿Qué son las regex?","opciones":["Bucles","Patrones que describen cadenas de texto","Clases","Variables"],"correcta":1},{"pregunta":"¿Qué representa \\d?","opciones":["Cualquier letra","Cualquier dígito","Un espacio","Nada"],"correcta":1},{"pregunta":"¿Qué significa +?","opciones":["Cero o más","Una o más veces","Exactamente una","Nunca"],"correcta":1},{"pregunta":"¿Para qué se usan?","opciones":["Dibujar","Buscar, validar y manipular texto","Calcular","Eliminar"],"correcta":1}]'::jsonb),

('programacion', 'eso', '{3}', 'Las APIs Web', 'Una API (Application Programming Interface, Interfaz de Programación de Aplicaciones) es un conjunto de reglas que permite que dos programas se comuniquen entre sí. Las APIs web son especialmente importantes: permiten que una aplicación acceda a los datos o funciones de otro servicio a través de internet. Gracias a ellas, puedes iniciar sesión en una app con tu cuenta de Google, comprobar el tiempo meteorológico desde cualquier web o mostrar un mapa con Google Maps dentro de tu propia aplicación.

El funcionamiento es similar al de un restaurante: el cliente (la aplicación que pide datos) hace una petición al camarero (la API) y el cocinero (el servidor) prepara la respuesta. La mayoría de APIs web modernas usan el protocolo HTTP y devuelven los datos en formato JSON, que es legible por humanos y fácil de procesar por programas.

Usar una API típicamente implica hacer una petición HTTP a una URL concreta, indicando qué recurso queremos (por ejemplo, el tiempo en una ciudad) y, en muchos casos, una clave de autenticación. La respuesta del servidor llega en forma de datos estructurados que podemos mostrar o procesar. Aprender a usar APIs es fundamental hoy, porque muchos programas reales combinan servicios de varios proveedores, y saber conectarlos es una habilidad esencial del desarrollo moderno.', '[{"pregunta":"¿Qué es una API?","opciones":["Un dibujo","Un conjunto de reglas para que programas se comuniquen","Un lenguaje","Un color"],"correcta":1},{"pregunta":"¿En qué formato devuelven datos las APIs web?","opciones":["Word","JSON","PDF","MP3"],"correcta":1},{"pregunta":"¿Qué protocolo usan las APIs web?","opciones":["FTP","HTTP","SMTP","TCP"],"correcta":1},{"pregunta":"¿Qué ejemplo se da en el texto?","opciones":["Twitter","Google Maps","YouTube","Netflix"],"correcta":1}]'::jsonb);

