-- PROGRAMACIÓN - 4º ESO (POO, web, bases de datos)
-- ============================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('programacion', 'eso', '{4}', 'Programación Orientada a Objetos', 'La programación orientada a objetos (POO) es un paradigma que organiza el código en torno a "objetos" que combinan datos (atributos) y funciones que operan sobre esos datos (métodos). Es uno de los paradigmas más usados hoy y está disponible en lenguajes como Python, Java, C++, C# y muchos más. Su éxito se debe a que permite modelar problemas complejos de manera intuitiva y reutilizar código fácilmente.

El concepto central es la "clase": una plantilla que define cómo son los objetos de un cierto tipo. Por ejemplo, una clase "Alumno" puede tener atributos (nombre, edad, notas) y métodos (calcular_media, mostrar_datos). A partir de esa clase podemos crear tantos objetos como queramos (instancias): cada alumno real es una instancia de la clase Alumno, con sus propios valores. Todos comparten los métodos, pero cada uno tiene sus propios datos.

La POO se apoya en cuatro principios: encapsulación (ocultar los detalles internos y exponer solo lo necesario), herencia (una clase puede heredar de otra, reutilizando sus características), polimorfismo (objetos distintos pueden usarse de la misma forma) y abstracción (centrarse en lo importante). Dominar estos conceptos es esencial para trabajar en proyectos grandes de software, donde sin POO el código se vuelve muy difícil de mantener.', '[{"pregunta":"¿Qué combinan los objetos?","opciones":["Solo datos","Datos y métodos","Solo métodos","Ni uno ni otro"],"correcta":1},{"pregunta":"¿Qué es una clase?","opciones":["Un bucle","Una plantilla para crear objetos","Una variable","Un error"],"correcta":1},{"pregunta":"¿Cuántos principios tiene la POO?","opciones":["Dos","Tres","Cuatro","Cinco"],"correcta":2},{"pregunta":"¿Qué significa herencia?","opciones":["Copiar y pegar","Una clase hereda características de otra","Borrar","Ocultar"],"correcta":1}]'::jsonb),

('programacion', 'eso', '{4}', 'Bases de Datos y SQL', 'Una base de datos es un sistema organizado para guardar, buscar y modificar grandes cantidades de información de forma eficiente y segura. Las aplicaciones modernas guardan datos en bases de datos: una red social guarda los usuarios, sus publicaciones y sus amigos; una tienda online guarda productos, pedidos y clientes. Sin bases de datos, el software moderno sería inimaginable.

Las bases de datos más tradicionales son las relacionales, que organizan los datos en tablas con filas y columnas. Cada tabla tiene un conjunto de columnas (nombre, edad, ciudad...) y cada fila es un registro. Las tablas pueden estar relacionadas entre sí: por ejemplo, una tabla "pedidos" puede contener una referencia a la tabla "clientes" para saber quién hizo cada pedido.

Para consultar y manipular las bases de datos relacionales se usa el lenguaje SQL (Structured Query Language). Con SQL podemos hacer consultas como "SELECT * FROM clientes WHERE ciudad = ''Madrid''" que devuelve todos los clientes de Madrid. También podemos insertar nuevos registros (INSERT), modificarlos (UPDATE) o eliminarlos (DELETE). SQL es uno de los lenguajes más usados del mundo, y dominarlo es imprescindible para cualquier programador que trabaje con datos.', '[{"pregunta":"¿Cómo organizan los datos las bases de datos relacionales?","opciones":["En árboles","En tablas con filas y columnas","En listas","En pilas"],"correcta":1},{"pregunta":"¿Qué significa SQL?","opciones":["Simple Query Line","Structured Query Language","Sequential Quick Lang","Script Query Lang"],"correcta":1},{"pregunta":"¿Qué comando SQL elimina registros?","opciones":["SELECT","INSERT","DELETE","UPDATE"],"correcta":2},{"pregunta":"¿Qué devuelve SELECT * FROM clientes?","opciones":["Nada","Todos los campos de todos los clientes","Un solo registro","Solo nombres"],"correcta":1}]'::jsonb),

('programacion', 'eso', '{4}', 'Frameworks y Librerías', 'En programación, un framework y una librería (o biblioteca) son conjuntos de código ya escritos que podemos usar en nuestros proyectos para no tener que reinventar la rueda. La diferencia entre ambos es sutil pero importante: cuando usas una librería, tú decides cuándo llamarla; cuando usas un framework, él decide cuándo llamar a tu código. Por eso se dice que los frameworks siguen el principio de inversión de control.

Las librerías son típicamente más pequeñas y especializadas. Por ejemplo, la librería numpy de Python se centra en cálculo numérico eficiente, y la librería requests facilita hacer peticiones HTTP. Las usas cuando las necesitas y el resto de tu código sigue siendo tuyo. Los frameworks, en cambio, definen la estructura general de tu aplicación. Ejemplos son Django (para web en Python), React (para interfaces web en JavaScript) o Spring (para Java).

Usar frameworks y librerías permite construir aplicaciones complejas en mucho menos tiempo del que requeriría hacerlo todo desde cero. Sin embargo, también obligan a aprender sus convenciones y a seguir sus reglas. La elección del framework adecuado depende del tipo de proyecto, la experiencia del equipo y el ecosistema del lenguaje. En cualquier caso, saber buscar, evaluar y usar código ajeno es una habilidad básica del programador moderno.', '[{"pregunta":"¿Quién controla el flujo con una librería?","opciones":["La librería","Tu código","Ambos","Nadie"],"correcta":1},{"pregunta":"¿Qué principio siguen los frameworks?","opciones":["Compilación","Inversión de control","Suma de código","Modularidad"],"correcta":1},{"pregunta":"¿Cuál es un framework web de Python?","opciones":["Django","numpy","requests","TensorFlow"],"correcta":0},{"pregunta":"¿Qué ventaja aportan?","opciones":["Son más lentos","Construir apps en menos tiempo","Ocultan errores","Nada"],"correcta":1}]'::jsonb),

('programacion', 'eso', '{4}', 'Ciberseguridad y Contraseñas', 'La ciberseguridad es el campo que se ocupa de proteger los sistemas informáticos, los datos y las redes de accesos no autorizados, ataques y daños. Es uno de los sectores más demandados en tecnología, porque cada año aumentan los ciberataques a empresas e instituciones. Un fallo de seguridad puede suponer pérdidas millonarias y graves problemas de privacidad.

Una de las primeras líneas de defensa son las contraseñas. Una contraseña segura debe ser larga (al menos 12 caracteres), combinar mayúsculas, minúsculas, números y símbolos, y no contener datos personales como fechas de nacimiento o nombres. También es fundamental no reutilizar la misma contraseña en distintos servicios: si uno se ve comprometido, todos los demás quedan expuestos. Los gestores de contraseñas ayudan a tener contraseñas distintas y fuertes en cada servicio sin tener que memorizarlas.

Además de contraseñas fuertes, las mejores prácticas incluyen la autenticación de dos factores (2FA), que exige un segundo código enviado al móvil o generado por una app. También es importante mantener los sistemas actualizados, desconfiar de correos sospechosos que piden datos (phishing) y no descargar archivos de fuentes poco fiables. La seguridad perfecta no existe, pero aplicando estas medidas básicas se reduce drásticamente el riesgo de sufrir un ataque.', '[{"pregunta":"¿Cuántos caracteres mínimo se recomienda?","opciones":["6","8","12","20"],"correcta":2},{"pregunta":"¿Qué es la 2FA?","opciones":["Doble autenticación","Doble firewall","Doble antivirus","Dos programas"],"correcta":0},{"pregunta":"¿Qué es el phishing?","opciones":["Un virus","Correos que piden datos engañosamente","Un antivirus","Un juego"],"correcta":1},{"pregunta":"¿Por qué no reutilizar contraseñas?","opciones":["Por moda","Si una se compromete, todas quedan expuestas","Por política","Sin motivo"],"correcta":1}]'::jsonb),

('programacion', 'eso', '{4}', 'Inteligencia Artificial y Machine Learning', 'La inteligencia artificial (IA) es la rama de la informática que busca crear sistemas capaces de realizar tareas que tradicionalmente requerían inteligencia humana, como reconocer imágenes, entender el lenguaje, tomar decisiones o aprender de la experiencia. Dentro de la IA, el machine learning (aprendizaje automático) es la técnica más importante hoy: consiste en que los sistemas aprendan por sí mismos a partir de ejemplos, sin ser programados explícitamente para cada caso.

El machine learning se basa en el análisis de grandes cantidades de datos para descubrir patrones. Si mostramos a un sistema miles de fotos de gatos y perros, correctamente etiquetadas, aprenderá a distinguirlos por sí mismo. Esta técnica se llama aprendizaje supervisado. Existen también el aprendizaje no supervisado (sin etiquetas, donde el sistema descubre grupos) y el aprendizaje por refuerzo (aprende por prueba y error, recibiendo recompensas).

Python es el lenguaje más utilizado en machine learning gracias a librerías como TensorFlow, PyTorch y scikit-learn, que facilitan muchísimo el trabajo. La IA ya está presente en nuestra vida: asistentes de voz, recomendaciones de Netflix, traducción automática, diagnóstico médico, coches autónomos. Sus aplicaciones crecen cada año, y con ellas también el debate ético sobre sus riesgos y beneficios.', '[{"pregunta":"¿Qué hace el machine learning?","opciones":["Programa explícitamente","Aprende a partir de datos","Borra datos","Copia textos"],"correcta":1},{"pregunta":"¿Qué tipo usa fotos etiquetadas?","opciones":["No supervisado","Supervisado","Por refuerzo","Manual"],"correcta":1},{"pregunta":"¿Cuál es el lenguaje más usado en ML?","opciones":["Java","Python","C++","JavaScript"],"correcta":1},{"pregunta":"¿Qué librería NO es de ML?","opciones":["TensorFlow","PyTorch","scikit-learn","React"],"correcta":3}]'::jsonb),

('programacion', 'eso', '{4}', 'Desarrollo Web Backend', 'En el desarrollo web distinguimos dos grandes áreas: el frontend, que es todo lo que el usuario ve e interactúa directamente (interfaz, diseño, botones), y el backend, que es lo que ocurre detrás, en los servidores, lejos de los ojos del usuario. El backend se ocupa de procesar las peticiones, acceder a las bases de datos, aplicar la lógica de negocio y enviar las respuestas apropiadas al frontend.

Los lenguajes más usados en el backend son Python (con frameworks como Django o Flask), JavaScript/Node.js (con Express), PHP (con Laravel), Ruby (con Rails), Java (con Spring) y C# (con ASP.NET). Cada uno tiene sus fortalezas: Python es muy productivo para proyectos medianos, Node.js es rápido para APIs, PHP sigue dominando muchos sitios existentes, y Java es habitual en empresas grandes.

El backend debe ser robusto, rápido y seguro. Maneja tareas críticas como autenticación de usuarios, pagos online, protección frente a ataques y almacenamiento de datos sensibles. Un error en el backend puede dejar un servicio inaccesible para millones de usuarios. Los desarrolladores backend suelen trabajar con arquitecturas de servidores, balanceadores de carga, caches, colas de mensajes y sistemas distribuidos, temas complejos que requieren años de experiencia para dominar.', '[{"pregunta":"¿Qué es el backend?","opciones":["Lo que el usuario ve","Lo que ocurre detrás, en servidores","El diseño","La base de datos solo"],"correcta":1},{"pregunta":"¿Cuál es un framework de Python backend?","opciones":["React","Django","Vue","Angular"],"correcta":1},{"pregunta":"¿Qué NO suele hacer el backend?","opciones":["Autenticar","Procesar pagos","Dibujar el logo","Acceder a datos"],"correcta":2},{"pregunta":"¿Qué maneja Node.js?","opciones":["Solo CSS","JavaScript en el servidor","Python en frontend","Java en móviles"],"correcta":1}]'::jsonb),

('programacion', 'eso', '{4}', 'DevOps y Despliegue', 'DevOps es una cultura y un conjunto de prácticas que unen el desarrollo de software (Dev) con las operaciones y administración de sistemas (Ops). Tradicionalmente, estos dos equipos trabajaban por separado: los programadores escribían el código y los administradores lo ponían en producción. DevOps propone una colaboración fluida entre ambos, automatizando el despliegue y el mantenimiento para conseguir entregas rápidas y fiables.

Una práctica clave de DevOps es la integración continua (Continuous Integration, CI). Consiste en que cada vez que un programador sube código al repositorio, un sistema automático lo compila, lo prueba y avisa si hay errores. Así se detectan problemas enseguida, sin esperar semanas. La entrega continua (Continuous Delivery, CD) va un paso más allá: el código validado se despliega automáticamente en el servidor de pruebas o producción.

Las herramientas más usadas son Jenkins, GitHub Actions, Docker y Kubernetes. Docker permite empaquetar aplicaciones en "contenedores" que funcionan igual en cualquier máquina, resolviendo el famoso problema de "en mi ordenador funciona pero en producción no". Kubernetes orquesta muchos contenedores en grandes sistemas. DevOps se ha convertido en una filosofía clave del desarrollo moderno, y empresas como Google, Amazon y Netflix hacen miles de despliegues al día gracias a ella.', '[{"pregunta":"¿Qué une DevOps?","opciones":["Solo desarrollo","Desarrollo y operaciones","Marketing y ventas","Diseño y pruebas"],"correcta":1},{"pregunta":"¿Qué es CI?","opciones":["Carga intensa","Integración continua","Código interno","Cambio inmediato"],"correcta":1},{"pregunta":"¿Para qué sirve Docker?","opciones":["Compilar","Empaquetar apps en contenedores","Dibujar","Enviar correos"],"correcta":1},{"pregunta":"¿Qué problema resuelve Docker?","opciones":["Ninguno","Que el código funcione igual en cualquier máquina","La estética","La velocidad del wifi"],"correcta":1}]'::jsonb),

('programacion', 'eso', '{4}', 'Pruebas Unitarias', 'Las pruebas unitarias (unit tests) son trozos de código que comprueban automáticamente si otra parte del código funciona correctamente. Se llaman "unitarias" porque prueban unidades pequeñas, normalmente funciones o métodos individuales. Escribir pruebas es una buena práctica profesional: permite detectar errores rápidamente, confiar en los cambios y refactorizar sin miedo.

Una prueba unitaria sigue un patrón muy simple: preparar los datos de entrada, ejecutar la función bajo prueba y comprobar que el resultado es el esperado. Por ejemplo, si probamos una función sumar(a, b), escribimos una prueba que llame a sumar(2, 3) y verifique que devuelve 5. Si en el futuro modificamos la función y por error rompe algo, la prueba fallará y lo sabremos enseguida.

Los lenguajes modernos tienen frameworks específicos para pruebas. En Python se usan unittest y pytest; en JavaScript, Jest o Mocha; en Java, JUnit. Estos frameworks organizan, ejecutan y reportan las pruebas de forma sistemática. Los proyectos profesionales suelen tener cientos o miles de pruebas unitarias que se ejecutan automáticamente en cada commit. Aunque al principio escribir pruebas parece trabajo extra, a medio plazo ahorra muchísimo tiempo y reduce los errores en producción.', '[{"pregunta":"¿Qué prueban las pruebas unitarias?","opciones":["Todo el programa","Unidades pequeñas como funciones","Solo la interfaz","Nada"],"correcta":1},{"pregunta":"¿Qué framework se usa en Python?","opciones":["JUnit","pytest","Mocha","Rails"],"correcta":1},{"pregunta":"¿Qué detecta una prueba que falla?","opciones":["Nada","Posibles errores en el código","Fallo de hardware","Falta de red"],"correcta":1},{"pregunta":"¿Qué ventaja aportan?","opciones":["Alargan el desarrollo","Permiten refactorizar con confianza","Son estética","Nada"],"correcta":1}]'::jsonb),

('programacion', 'eso', '{4}', 'La Nube y los Servicios Web', 'La computación en la nube (cloud computing) consiste en ofrecer servicios informáticos (procesamiento, almacenamiento, redes, aplicaciones) a través de internet, en lugar de tenerlos en servidores propios. En vez de comprar hardware físico, las empresas y los desarrolladores alquilan estos recursos a proveedores como Amazon Web Services (AWS), Microsoft Azure o Google Cloud, pagando solo por lo que usan. Este modelo ha revolucionado la industria.

La nube ofrece ventajas enormes. La escalabilidad permite aumentar o reducir los recursos al momento, según la demanda: si una web recibe un pico de visitantes, se pueden añadir servidores en minutos. La fiabilidad es alta porque los proveedores replican los datos en varios centros geográficos. Y el coste inicial es bajo: cualquier persona con una tarjeta de crédito puede poner en marcha una aplicación profesional sin comprar hardware.

Existen distintos niveles de servicios en la nube. IaaS (Infrastructure as a Service) ofrece máquinas virtuales y almacenamiento bruto. PaaS (Platform as a Service) ofrece entornos listos para desplegar aplicaciones sin preocuparse por el sistema operativo. SaaS (Software as a Service) ofrece aplicaciones ya hechas a través del navegador, como Gmail o Dropbox. Saber elegir el nivel adecuado y aprovechar los servicios de la nube es una habilidad muy valorada hoy en día.', '[{"pregunta":"¿Qué es la computación en la nube?","opciones":["Servidores en casa","Ofrecer servicios informáticos por internet","Un programa","Un antivirus"],"correcta":1},{"pregunta":"¿Cuál es un proveedor importante?","opciones":["AWS","Facebook","Spotify","Zoom"],"correcta":0},{"pregunta":"¿Qué significa SaaS?","opciones":["Software as a Service","Server as a Store","Solo aplicaciones","Sistema aislado"],"correcta":0},{"pregunta":"¿Qué ventaja destaca el texto?","opciones":["Muy caro","Escalabilidad inmediata","Lentitud","Poca fiabilidad"],"correcta":1}]'::jsonb),

('programacion', 'eso', '{4}', 'Ética en la Programación', 'La programación no es una actividad neutra. Cada línea de código tiene consecuencias reales sobre las personas: puede proteger su privacidad o vulnerarla, puede hacer un sistema accesible o excluyente, puede amplificar prejuicios o corregirlos. Por eso, la ética es un aspecto cada vez más importante en el desarrollo de software y se debate activamente en la industria.

Algunos dilemas habituales incluyen: ¿es ético recopilar datos de usuarios sin su pleno conocimiento? ¿Se debe desarrollar software que automatiza despidos masivos? ¿Qué responsabilidad tiene un programador si su código causa daños, como en un coche autónomo que atropella a un peatón? ¿Se deben auditar los algoritmos de recomendación que pueden polarizar a la sociedad? No hay respuestas fáciles, pero el debate es necesario.

Varias organizaciones han publicado códigos deontológicos para ingenieros de software, como el de la ACM (Association for Computing Machinery). En general, se recomienda: respetar la privacidad, ser transparente sobre cómo funciona el código, evitar sesgos discriminatorios, considerar el impacto social antes de construir, y atreverse a rechazar proyectos que contradigan valores éticos fundamentales. Formarse en ética es tan importante como formarse en algoritmos.', '[{"pregunta":"¿Es neutra la programación?","opciones":["Sí","No, tiene consecuencias reales","Solo a veces","Solo comercial"],"correcta":1},{"pregunta":"¿Qué organización publicó un código ético?","opciones":["ACM","FIFA","UEFA","UNESCO"],"correcta":0},{"pregunta":"¿Qué NO se recomienda?","opciones":["Respetar privacidad","Ser transparente","Ocultar sesgos","Considerar el impacto"],"correcta":2},{"pregunta":"¿Qué dilema se cita en el texto?","opciones":["Coche autónomo que atropella","Mejor lenguaje","Mejor sueldo","Gráficos bonitos"],"correcta":0}]'::jsonb),

('programacion', 'eso', '{4}', 'Accesibilidad Web', 'La accesibilidad web es la práctica de diseñar y desarrollar páginas web para que puedan ser usadas por cualquier persona, incluyendo usuarios con discapacidades visuales, auditivas, motrices o cognitivas. No es un extra opcional: en muchos países es una obligación legal para organismos públicos, y en todos los casos es una cuestión de inclusión y derechos.

Algunos principios básicos incluyen: añadir texto alternativo a las imágenes (para que un lector de pantalla pueda describirlas a una persona ciega), garantizar un contraste suficiente entre texto y fondo (para usuarios con baja visión), permitir la navegación completa por teclado (para quienes no pueden usar ratón), estructurar correctamente el contenido con encabezados, y subtitular los vídeos.

Las pautas internacionales más conocidas son las WCAG (Web Content Accessibility Guidelines), publicadas por la W3C. Definen tres niveles de conformidad: A (básico), AA (intermedio, el más exigido legalmente) y AAA (máximo). Existen herramientas automáticas como WAVE o Axe que ayudan a detectar problemas de accesibilidad en las webs. Una web accesible no solo beneficia a las personas con discapacidad, sino que mejora la experiencia de todos los usuarios y puntúa mejor en los buscadores.', '[{"pregunta":"¿Qué busca la accesibilidad web?","opciones":["Hacer webs más rápidas","Que cualquiera pueda usarlas","Reducir costes","Bloquear usuarios"],"correcta":1},{"pregunta":"¿Qué son las WCAG?","opciones":["Un virus","Pautas de accesibilidad del W3C","Un lenguaje","Un navegador"],"correcta":1},{"pregunta":"¿Cuál es el nivel más exigido legalmente?","opciones":["A","AA","AAA","ninguno"],"correcta":1},{"pregunta":"¿Qué ayuda a usuarios ciegos?","opciones":["Imágenes sin texto","Texto alternativo en imágenes","Colores vivos","Música de fondo"],"correcta":1}]'::jsonb);

-- ============================================================
-- ROBÓTICA - 1º ESO (sensores / conceptos básicos)
-- ============================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('robotica', 'eso', '{1}', 'La Historia de los Robots', 'La palabra "robot" fue utilizada por primera vez en 1920 por el escritor checo Karel Capek en su obra de teatro "R.U.R." (Rossum''s Universal Robots). Proviene de la palabra checa "robota", que significa trabajo forzado o servidumbre. En la obra, los robots eran seres artificiales creados para trabajar, pero al final se rebelaban contra sus creadores. Desde entonces, el término se adoptó en todos los idiomas.

Aunque la palabra es reciente, la idea de construir máquinas que imiten a los seres vivos es muy antigua. Los griegos ya imaginaban autómatas en sus mitos, y durante los siglos XVIII y XIX hubo inventores que construyeron figuras mecánicas capaces de escribir, dibujar o tocar instrumentos. Estas máquinas, llamadas autómatas, usaban engranajes y poleas ocultas para simular movimientos humanos.

Los robots modernos aparecieron en el siglo XX. El primer robot industrial, llamado Unimate, se instaló en una fábrica de General Motors en 1961 para manipular piezas calientes de metal. A partir de ahí la industria creció exponencialmente. Hoy los robots están en todas partes: fábricas, hospitales, almacenes, casas particulares y hasta en otros planetas, como los rovers que exploran Marte.', '[{"pregunta":"¿Quién usó por primera vez la palabra robot?","opciones":["Asimov","Karel Capek","Tesla","Turing"],"correcta":1},{"pregunta":"¿Qué significa robota en checo?","opciones":["Fiesta","Trabajo forzado","Estrella","Amigo"],"correcta":1},{"pregunta":"¿Cómo se llamó el primer robot industrial?","opciones":["Unimate","RoboCop","ASIMO","Nao"],"correcta":0},{"pregunta":"¿En qué año se instaló el primer robot industrial?","opciones":["1920","1950","1961","1980"],"correcta":2}]'::jsonb),

('robotica', 'eso', '{1}', 'Sensores de Contacto', 'Los sensores de contacto son los más sencillos que usa un robot: detectan si hay un objeto tocándolos físicamente. Funcionan como interruptores: cuando algo los presiona, cierran el circuito eléctrico; cuando la presión desaparece, lo abren. Esta información simple (sí/no) llega al microcontrolador del robot, que puede reaccionar en consecuencia.

A pesar de su simplicidad, los sensores de contacto son muy útiles. Un robot aspirador los usa en su parachoques para detectar cuando choca contra una pared y entonces cambiar de dirección. En una línea de producción, un sensor de contacto puede indicar que una pieza ha llegado a la posición correcta. En un robot educativo como el Lego Mindstorms, los alumnos pueden programar respuestas sencillas como "cuando toque algo, gira 90 grados".

El tipo más común es el pulsador o "touch sensor". Lleva un pequeño resorte que lo devuelve a su estado inicial cuando deja de ser presionado. Hay versiones reforzadas para entornos industriales y miniatura para productos electrónicos. Los sensores de contacto son el primer tipo de sensor que se aprende en robótica básica porque ilustran perfectamente el concepto de entrada digital: un valor que solo puede ser 0 o 1, encendido o apagado, presionado o no.', '[{"pregunta":"¿Qué detectan los sensores de contacto?","opciones":["Luz","Presión física","Temperatura","Sonido"],"correcta":1},{"pregunta":"¿Qué dos valores envían?","opciones":["0 y 100","Alto y bajo","Sí/no (digital)","Muchos grados"],"correcta":2},{"pregunta":"¿Qué robot doméstico los usa?","opciones":["Lavavajillas","Robot aspirador","Microondas","Nevera"],"correcta":1},{"pregunta":"¿Cómo funciona al ser presionado?","opciones":["Abre el circuito","Cierra el circuito eléctrico","Enciende un LED","Emite sonido"],"correcta":1}]'::jsonb),

('robotica', 'eso', '{1}', 'Sensor de Luz', 'Un sensor de luz mide la cantidad de luz que llega a su superficie. El componente electrónico más común para esto es la fotorresistencia o LDR (Light Dependent Resistor), cuya resistencia eléctrica cambia según la luz que recibe: cuanta más luz, menos resistencia. Conectándola a un circuito, podemos convertir esta variación en un número que el robot puede leer.

Los sensores de luz permiten al robot reaccionar a las condiciones de iluminación. Por ejemplo, una farola inteligente puede encenderse automáticamente al anochecer y apagarse al amanecer. Un robot seguidor de línea utiliza dos sensores de luz apuntando al suelo: cuando uno detecta más oscuridad (la línea negra) que el otro, el robot gira para seguirla. Es una de las aplicaciones más clásicas en robótica educativa.

Existen también sensores de luz más avanzados, como los fotodiodos y los fototransistores, que responden más rápido que las LDR. Y los sensores de color, que no solo detectan luz sino que distinguen entre distintas longitudes de onda. Todos ellos se basan en el mismo principio: convertir luz en señal eléctrica. Los sensores de luz son imprescindibles en muchísimas aplicaciones modernas, desde cámaras digitales hasta paneles solares automatizados.', '[{"pregunta":"¿Qué es una LDR?","opciones":["Un motor","Fotorresistencia","Una batería","Un cable"],"correcta":1},{"pregunta":"¿Qué ocurre con más luz en una LDR?","opciones":["Más resistencia","Menos resistencia","Igual","Se rompe"],"correcta":1},{"pregunta":"¿Para qué sirve un seguidor de línea?","opciones":["Para volar","Para seguir una línea del suelo","Para cargar baterías","Para medir temperatura"],"correcta":1},{"pregunta":"¿Qué sensor distingue colores?","opciones":["LDR","Fotodiodo","Sensor de color","Sensor táctil"],"correcta":2}]'::jsonb),

('robotica', 'eso', '{1}', 'Los Actuadores: Músculos del Robot', 'Si los sensores son los sentidos del robot, los actuadores son sus músculos. Son los componentes que convierten las señales eléctricas en movimiento o acción física. Sin actuadores, un robot solo podría "pensar" y "percibir", pero sería incapaz de influir en el mundo. Los actuadores son, por tanto, lo que nos permite ver resultados visibles de cualquier programa robótico.

El actuador más común es el motor eléctrico, que convierte electricidad en movimiento giratorio. Hay de varios tipos: los motores de corriente continua (DC) son sencillos y baratos; los motores paso a paso permiten girar un ángulo exacto; los servomotores llevan una electrónica interna que controla con precisión la posición de su eje. Todos ellos se usan en robótica según las necesidades del proyecto.

Además de los motores, existen otros tipos de actuadores. Los solenoides generan un movimiento lineal cuando se activan. Los pistones neumáticos usan aire a presión para mover brazos robóticos industriales. Los altavoces son actuadores acústicos que generan sonido. Y las pantallas y los LEDs son actuadores visuales. En un proyecto robótico real, el diseñador escoge los actuadores adecuados según lo que el robot necesite hacer: moverse, agarrar, señalar, comunicar.', '[{"pregunta":"¿Qué convierten los actuadores?","opciones":["Luz en sonido","Señales eléctricas en acción física","Agua en energía","Calor en frío"],"correcta":1},{"pregunta":"¿Qué motor gira ángulos exactos?","opciones":["DC","Paso a paso","De combustión","Eólico"],"correcta":1},{"pregunta":"¿Qué tipo de movimiento genera un solenoide?","opciones":["Rotativo","Lineal","Curvo","Vibratorio"],"correcta":1},{"pregunta":"¿Qué son los LEDs como actuadores?","opciones":["Acústicos","Visuales","Motrices","Térmicos"],"correcta":1}]'::jsonb),

('robotica', 'eso', '{1}', 'El Microcontrolador', 'El microcontrolador es el cerebro del robot: un pequeño chip que ejecuta el programa que hemos escrito y coordina todos los componentes. Recibe las señales de los sensores, las procesa siguiendo las instrucciones del código, y envía órdenes a los actuadores. En un robot educativo típico es, por ejemplo, una placa Arduino o un ladrillo inteligente de Lego Mindstorms.

Un microcontrolador contiene varios elementos en un mismo chip: una CPU (unidad central de procesamiento) que ejecuta las instrucciones, memoria para guardar el programa y los datos, y puertos de entrada y salida para conectar sensores y actuadores. Todo esto en un espacio de apenas unos centímetros. Gracias a esta miniaturización, los microcontroladores son asequibles y pueden incorporarse a cualquier dispositivo inteligente.

Los microcontroladores no solo están en robots: también en electrodomésticos, coches, juguetes, termostatos, relojes y prácticamente cualquier aparato electrónico moderno. Se estima que cada persona de un país desarrollado tiene cientos de microcontroladores a su alrededor sin darse cuenta. Su enorme difusión se debe a que permiten añadir inteligencia a objetos cotidianos con muy poco coste y consumo energético. La informática embebida es una de las ramas más activas del mundo electrónico actual.', '[{"pregunta":"¿Qué función cumple el microcontrolador?","opciones":["Cerebro del robot","Fuente de energía","Soporte mecánico","Piel del robot"],"correcta":0},{"pregunta":"¿Qué contiene un microcontrolador?","opciones":["Solo memoria","CPU, memoria y puertos E/S","Solo batería","Solo cable"],"correcta":1},{"pregunta":"¿Dónde más encontramos microcontroladores?","opciones":["Solo en robots","En electrodomésticos, coches, etc.","Solo en móviles","Solo en aviones"],"correcta":1},{"pregunta":"¿Qué es Arduino?","opciones":["Un robot completo","Una placa microcontroladora","Un sensor","Un motor"],"correcta":1}]'::jsonb),

('robotica', 'eso', '{1}', 'El Chasis del Robot', 'El chasis es la estructura física que sostiene todos los demás componentes del robot: microcontrolador, baterías, sensores, actuadores y cableado. Es, por así decirlo, el esqueleto del robot. Sin un chasis bien diseñado, los componentes se desordenarían y el robot sería frágil e inestable. Por eso, aunque pueda parecer un aspecto secundario, el chasis influye enormemente en el éxito del proyecto.

Los materiales más utilizados en robótica educativa son el plástico (ligero y barato, como las piezas de Lego), el metacrilato (plástico rígido transparente que se corta con láser), la madera (fácil de trabajar) y el aluminio (ligero pero resistente). En robótica profesional se usan metales más sofisticados y composites como la fibra de carbono. La elección depende del peso, la fuerza necesaria, el coste y la estética del robot.

El diseño del chasis debe considerar varios factores: la forma en que se moverá el robot (con ruedas, orugas, patas), el centro de gravedad (para que no vuelque), el espacio disponible para los componentes, y la accesibilidad para reparaciones. Los robots de competición, por ejemplo, suelen diseñarse para ser robustos y compactos. Muchos estudiantes de robótica educativa construyen sus chasis desde cero, lo que les enseña conceptos de mecánica y diseño.', '[{"pregunta":"¿Qué sostiene el chasis?","opciones":["Solo la batería","Todos los componentes del robot","Solo los motores","Solo los sensores"],"correcta":1},{"pregunta":"¿Qué material ligero se usa en competición?","opciones":["Cemento","Fibra de carbono","Hierro masivo","Vidrio"],"correcta":1},{"pregunta":"¿Por qué importa el centro de gravedad?","opciones":["Es estético","Para que el robot no vuelque","Para decorarlo","No importa"],"correcta":1},{"pregunta":"¿Qué usa un robot con orugas?","opciones":["Patas","Hélices","Orugas como ruedas anchas","Ruedas esféricas"],"correcta":2}]'::jsonb),

('robotica', 'eso', '{1}', 'Programación por Bloques en Robots', 'Muchos robots educativos se programan con entornos gráficos de bloques, similares a Scratch. Esta aproximación facilita el aprendizaje porque no requiere memorizar sintaxis: basta con arrastrar y encajar bloques visuales que representan las distintas instrucciones. Los entornos más populares incluyen Scratch for Arduino (S4A), mBlock, BlocklyDuino, el software de Lego Mindstorms EV3 y el de Vex IQ.

La programación por bloques permite a los estudiantes concentrarse en la lógica del programa en lugar de en los detalles del lenguaje. Por ejemplo, en vez de escribir "digitalWrite(13, HIGH)" para encender un LED, simplemente arrastran un bloque "encender LED". El entorno traduce automáticamente los bloques al código que entiende el microcontrolador.

Este enfoque no es exclusivo de la educación: hay empresas que lo usan para que no programadores puedan crear automatizaciones. Sin embargo, la programación por bloques tiene sus limitaciones: para proyectos más complejos conviene pasar a lenguajes textuales como C++, Python o JavaScript. Por eso en cursos superiores de ESO y Bachillerato se da el salto a escribir código real, que ofrece más flexibilidad y refleja mejor cómo se programa en el mundo profesional.', '[{"pregunta":"¿En qué se parece la programación por bloques a Scratch?","opciones":["En nada","Usa bloques visuales arrastrables","Es idéntica","Es más difícil"],"correcta":1},{"pregunta":"¿Qué ventaja tiene?","opciones":["Es más lento","Facilita centrarse en la lógica sin memorizar sintaxis","Es más complicado","Requiere saber inglés"],"correcta":1},{"pregunta":"¿Qué hace el entorno con los bloques?","opciones":["Nada","Los traduce a código del microcontrolador","Los borra","Los imprime"],"correcta":1},{"pregunta":"¿Para qué proyectos se queda corta?","opciones":["Ninguno","Los muy complejos","Los simples","Los educativos"],"correcta":1}]'::jsonb),

('robotica', 'eso', '{1}', 'Robots en la Vida Diaria', 'Aunque a veces imaginemos los robots como criaturas futuristas, lo cierto es que ya conviven con nosotros en forma de máquinas que nos simplifican la vida. El robot aspirador es quizá el ejemplo más popular: un disco pequeño que recorre la casa aspirando, esquivando obstáculos y volviendo a su base de carga cuando se le agota la batería. Usa sensores de choque, de caídas y de navegación.

En las cocinas de muchos hogares también hay robots: los robots de cocina mezclan, baten, amasan, cocinan al vapor, fríen y hasta pesan los ingredientes. Algunos tienen pantallas con recetas guiadas. Aunque no parezcan "robots" en el sentido clásico, cumplen la definición: son máquinas programables con sensores y actuadores que realizan tareas de forma autónoma o semiautomática.

Otros robots domésticos incluyen los cortacéspedes automáticos, los limpiadores de piscinas y los drones de ocio. En hospitales, los robots quirúrgicos asisten a los cirujanos con movimientos de gran precisión. En almacenes, robots móviles transportan cajas autónomamente, como en los centros logísticos de Amazon. La robótica ha dejado de ser ciencia ficción: ya está entre nosotros, y su presencia crecerá mucho en las próximas décadas.', '[{"pregunta":"¿Cuál es un robot doméstico popular?","opciones":["Microondas","Robot aspirador","Tostadora","Licuadora"],"correcta":1},{"pregunta":"¿Qué robots ayudan en operaciones?","opciones":["Aspiradores","Robots quirúrgicos","Robots de cocina","Drones"],"correcta":1},{"pregunta":"¿Qué hacen los robots en los almacenes?","opciones":["Nada","Transportan cajas autónomamente","Limpian","Vigilan"],"correcta":1},{"pregunta":"¿Qué sensores usa un aspirador robot?","opciones":["Ninguno","Choque, caídas, navegación","Solo temperatura","Solo sonido"],"correcta":1}]'::jsonb),

('robotica', 'eso', '{1}', 'Las Leyes de Asimov', 'Isaac Asimov, escritor estadounidense de ciencia ficción, formuló en 1942 las famosas Tres Leyes de la Robótica para sus relatos. Aunque son ficción, se han convertido en una referencia cultural y ética muy citada cuando se habla de robots. Las leyes son: (1) Un robot no hará daño a un ser humano ni, por inacción, permitirá que un ser humano sufra daño. (2) Un robot debe obedecer las órdenes humanas, excepto si entran en conflicto con la primera ley. (3) Un robot debe proteger su propia existencia, siempre que no contradiga las dos primeras.

Más adelante, Asimov añadió la Ley Cero: un robot no hará daño a la humanidad en su conjunto, ni por inacción permitirá que la humanidad sufra daño. Esta ley sería incluso superior a las anteriores. El propio Asimov reconocía que sus historias exploraban los dilemas y paradojas que aparecen al aplicar estas leyes a situaciones reales, porque a veces las leyes entran en conflicto unas con otras.

Aunque las leyes de Asimov no rigen literalmente la robótica real, sí han inspirado el debate sobre la ética de las máquinas inteligentes. Hoy, cuando los coches autónomos, los robots militares o los asistentes de IA son una realidad, los investigadores discuten cómo deben comportarse moralmente. Las leyes de Asimov siguen siendo un punto de partida para pensar estos problemas, aunque insuficientes para resolverlos por completo.', '[{"pregunta":"¿Cuántas son las leyes principales?","opciones":["Dos","Tres","Cuatro","Cinco"],"correcta":1},{"pregunta":"¿Qué dice la primera ley?","opciones":["Obedecer a humanos","No hacer daño a un humano","Protegerse","Ayudar"],"correcta":1},{"pregunta":"¿Qué añade la Ley Cero?","opciones":["Es sobre robots","Proteger a la humanidad en su conjunto","Solo energía","Poder atacar"],"correcta":1},{"pregunta":"¿Son leyes reales o de ficción?","opciones":["Reales","De ficción pero influyentes","Antiguas","Nuevas"],"correcta":1}]'::jsonb),

('robotica', 'eso', '{1}', 'Robots Humanoides', 'Un robot humanoide es aquel que imita la forma general del cuerpo humano: cabeza, torso, dos brazos y dos piernas. Diseñar robots con esta morfología es un enorme reto porque caminar erguido sobre dos piernas es mucho más complicado que rodar o moverse con cuatro patas. Mantener el equilibrio, coordinar el movimiento y reaccionar a empujones requiere controles muy sofisticados.

Uno de los robots humanoides más famosos fue ASIMO, de la empresa Honda, presentado en 2000. Medía 1,30 metros y era capaz de caminar, correr, subir escaleras, reconocer rostros y responder a voz. Estuvo en activo hasta 2018, visitando museos y eventos por todo el mundo como embajador de la robótica japonesa. Fue pionero pero relativamente limitado para tareas reales.

En los últimos años, la empresa estadounidense Boston Dynamics ha revolucionado el campo con robots como Atlas, capaces de saltar, hacer piruetas y levantarse tras una caída. Los avances en sensores, baterías, motores y sobre todo algoritmos de control los han hecho posibles. Aunque los humanoides aún no trabajan a diario en nuestras vidas, algunos expertos creen que en la próxima década podrían aparecer en fábricas, residencias de ancianos o misiones de rescate.', '[{"pregunta":"¿Qué forma imitan los humanoides?","opciones":["Animal","Humana","Robótica genérica","Vehículos"],"correcta":1},{"pregunta":"¿De qué empresa era ASIMO?","opciones":["Sony","Honda","Panasonic","Boston Dynamics"],"correcta":1},{"pregunta":"¿Qué empresa es conocida por el robot Atlas?","opciones":["Tesla","Boston Dynamics","Google","Samsung"],"correcta":1},{"pregunta":"¿Por qué es difícil caminar a dos piernas?","opciones":["Es fácil","Requiere gran equilibrio y coordinación","No se puede","Los robots no caen"],"correcta":1}]'::jsonb);

