-- ROBÓTICA - 2º ESO (Arduino)
-- ============================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('robotica', 'eso', '{2}', 'Arduino UNO: Anatomía', 'Arduino UNO es la placa más popular de la familia Arduino y una de las plataformas de electrónica educativa más usadas del mundo. Fue diseñada en Italia en 2005 por un grupo de profesores del Interaction Design Institute Ivrea, buscando una herramienta asequible para sus alumnos. Desde entonces, millones de placas Arduino se han vendido por todo el planeta.

La placa UNO mide unos 7x5 centímetros y contiene un microcontrolador ATmega328P, el "cerebro" que ejecuta nuestros programas. Dispone de 14 pines digitales (que pueden ser entrada o salida), 6 pines analógicos (solo de entrada), un conector USB para programarla desde el ordenador y un conector de alimentación externa. También tiene algunos LEDs indicadores, un botón de reset y un regulador de tensión que le permite trabajar con diferentes voltajes.

Programar un Arduino es muy sencillo gracias al Arduino IDE, un programa gratuito para Windows, Mac y Linux. Los programas se llaman "sketches" y están escritos en un lenguaje derivado de C++. Un sketch mínimo tiene dos funciones: setup(), que se ejecuta una vez al encender la placa, y loop(), que se ejecuta en bucle infinito. Esta estructura tan simple permite aprender en pocos minutos y construir proyectos increíbles con práctica.', '[{"pregunta":"¿Dónde se diseñó Arduino?","opciones":["Estados Unidos","Italia","Japón","Alemania"],"correcta":1},{"pregunta":"¿Cuántos pines digitales tiene UNO?","opciones":["6","10","14","20"],"correcta":2},{"pregunta":"¿Cómo se llaman los programas de Arduino?","opciones":["Apps","Sketches","Códigos","Scripts"],"correcta":1},{"pregunta":"¿Qué hace la función loop()?","opciones":["Se ejecuta una vez","Se ejecuta en bucle infinito","Apaga el Arduino","Nada"],"correcta":1}]'::jsonb),

('robotica', 'eso', '{2}', 'El LED Parpadeante (Blink)', 'El primer programa que todo el mundo hace con Arduino es el famoso Blink: hacer que un LED se encienda y se apague repetidamente. Es el "Hola mundo" de la electrónica, y aunque parezca trivial, introduce todos los conceptos básicos: configurar un pin como salida, activarlo y desactivarlo, y crear pausas. Una vez dominado, cualquier otro proyecto es cuestión de combinar y ampliar estas ideas.

El código del Blink estándar tiene esta estructura. En setup() se ejecuta pinMode(13, OUTPUT), que configura el pin 13 como salida. Arduino UNO tiene un LED incorporado conectado a ese pin, por eso es el más usado. En loop() se alternan cuatro instrucciones: digitalWrite(13, HIGH) enciende el LED, delay(1000) espera un segundo, digitalWrite(13, LOW) apaga el LED y delay(1000) espera otro segundo. El ciclo se repite indefinidamente.

A partir del Blink básico se pueden hacer variaciones: parpadeo más rápido o más lento, encender varios LEDs en secuencia para simular un semáforo, generar patrones morse, etcétera. También se puede mejorar evitando delay(), que bloquea el programa, mediante la función millis(), que permite realizar varias tareas aparentemente simultáneas. Estas técnicas son la base del control de tiempos en proyectos más complejos.', '[{"pregunta":"¿Cuál es el programa más básico de Arduino?","opciones":["Hola","Blink","Test","Motor"],"correcta":1},{"pregunta":"¿Qué pin tiene LED incorporado en UNO?","opciones":["5","13","20","A0"],"correcta":1},{"pregunta":"¿Qué hace pinMode(13, OUTPUT)?","opciones":["Lee valor","Configura el pin 13 como salida","Apaga todo","Borra memoria"],"correcta":1},{"pregunta":"¿Qué alternativa hay a delay()?","opciones":["Ninguna","millis() para no bloquear","setTimeout()","pause()"],"correcta":1}]'::jsonb),

('robotica', 'eso', '{2}', 'Resistencias: La Protección del Circuito', 'Una resistencia es un componente eléctrico que se opone al paso de la corriente. En un circuito, su función principal es limitar la corriente que pasa por otros componentes, protegiéndolos de daños. Por ejemplo, si conectamos un LED directamente a 5V, recibirá demasiada corriente y se quemará. Poniendo una resistencia en serie, reducimos la corriente a un valor seguro.

La ley que rige este comportamiento es la Ley de Ohm: V = I·R, donde V es la tensión (en voltios), I la corriente (en amperios) y R la resistencia (en ohmios). Si conocemos dos valores, podemos calcular el tercero. Por ejemplo, si queremos que por un LED pase 20 mA (0,02 A) a partir de una fuente de 5V con caída del LED de 2V, necesitamos una resistencia de (5-2)/0,02 = 150 ohmios.

Las resistencias se identifican por un código de colores: anillos de colores pintados en el cuerpo indican su valor. Los dos primeros son los dígitos, el tercero es el multiplicador (potencia de 10) y el cuarto la tolerancia. Aprender a leer el código es una habilidad básica de electrónica, aunque hoy también se puede usar un multímetro para medir directamente. Las resistencias son el componente pasivo más usado en cualquier circuito.', '[{"pregunta":"¿Qué hace una resistencia?","opciones":["Aumenta la corriente","Se opone al paso de la corriente","Corta el circuito","Mide tensión"],"correcta":1},{"pregunta":"¿Qué dice la Ley de Ohm?","opciones":["V = R·I","V = I/R","V + I = R","I = V·R"],"correcta":0},{"pregunta":"¿Qué indica el código de colores?","opciones":["La marca","El valor de la resistencia","El material","La fecha"],"correcta":1},{"pregunta":"¿Qué pasa si no pones resistencia a un LED?","opciones":["Nada","Puede quemarse","Brilla menos","Mejora"],"correcta":1}]'::jsonb),

('robotica', 'eso', '{2}', 'El Sensor de Ultrasonidos HC-SR04', 'El HC-SR04 es uno de los sensores más populares en proyectos Arduino. Mide distancias utilizando el principio de los ultrasonidos, del mismo modo que los murciélagos o los sonares de los barcos. El sensor emite una ráfaga de sonido de alta frecuencia (unos 40 kHz, inaudible para el oído humano) y mide el tiempo que tarda en volver tras rebotar contra un objeto. Como la velocidad del sonido es conocida (343 m/s en el aire), podemos calcular la distancia.

La fórmula es simple: distancia = (velocidad × tiempo) / 2. Dividimos entre dos porque el sonido recorre el camino de ida y vuelta. El HC-SR04 puede detectar objetos desde 2 cm hasta aproximadamente 4 metros, con una precisión de unos pocos milímetros. Es ideal para robots que deben esquivar obstáculos, aparcamientos inteligentes o alarmas de proximidad.

Tiene cuatro pines: VCC (alimentación, 5V), GND (tierra), TRIG (señal de activación) y ECHO (señal de respuesta). El programa Arduino envía un pulso corto al TRIG, y mide cuánto tarda en recibir la señal por el ECHO. Con la librería NewPing o directamente con la función pulseIn(), obtenemos el valor en microsegundos, que convertimos en distancia. Es un sensor barato, preciso y fácil de usar: por eso se incluye en casi todos los kits educativos.', '[{"pregunta":"¿A qué frecuencia emite el HC-SR04?","opciones":["4 kHz","40 kHz","400 kHz","4 MHz","44 kHz"],"correcta":1},{"pregunta":"¿Por qué se divide el tiempo entre dos?","opciones":["Por seguridad","Porque el sonido va y vuelve","Por estética","Porque sí"],"correcta":1},{"pregunta":"¿Cuánto detecta al máximo?","opciones":["1 metro","2 metros","4 metros","10 metros"],"correcta":2},{"pregunta":"¿Qué pin envía la señal de activación?","opciones":["ECHO","TRIG","VCC","GND"],"correcta":1}]'::jsonb),

('robotica', 'eso', '{2}', 'Los Servomotores', 'Un servomotor es un tipo de motor que, a diferencia de un motor normal, no gira libremente, sino que se posiciona en un ángulo exacto indicado por el programa. Internamente lleva un motor, una reductora de engranajes, un potenciómetro que mide su posición y un pequeño circuito electrónico de control que compara la posición deseada con la actual y ajusta hasta alcanzarla. El resultado es un actuador preciso y fácil de usar.

Los servomotores más comunes en robótica educativa giran entre 0 y 180 grados. Tienen tres cables: alimentación (normalmente roja), tierra (negro o marrón) y señal (amarilla o naranja). La señal que reciben es un pulso cuya duración indica el ángulo: 1 ms significa 0°, 1,5 ms significa 90° y 2 ms significa 180°. Este sistema se llama PWM (Pulse Width Modulation).

Arduino facilita mucho el uso de servomotores con la librería Servo. Una vez incluida, basta con escribir servo.write(angulo) para mover el eje a esa posición. Los servos se usan en brazos robóticos, pequeñas cabezas móviles, timones de barcos radiocontrol, aletas de aviones modelo y cualquier otro proyecto que requiera posicionamiento preciso. Son más baratos que otros sistemas de control y muy fiables para ángulos pequeños.', '[{"pregunta":"¿Qué caracteriza a un servomotor?","opciones":["Gira libre","Se posiciona en un ángulo exacto","No gira","Solo al máximo"],"correcta":1},{"pregunta":"¿Cuántos cables suele tener?","opciones":["Dos","Tres","Cuatro","Cinco"],"correcta":1},{"pregunta":"¿Qué significa PWM?","opciones":["Power Mode","Pulse Width Modulation","Pin Wire Mode","Program Write"],"correcta":1},{"pregunta":"¿Qué librería se usa en Arduino?","opciones":["Motor","Servo","Step","NewPing"],"correcta":1}]'::jsonb),

('robotica', 'eso', '{2}', 'Los Protoboards', 'El protoboard, también llamado breadboard o placa de pruebas, es una placa con pequeños agujeros donde podemos insertar componentes electrónicos y cables sin necesidad de soldar. Su nombre viene de que permite hacer prototipos rápidos: probar circuitos antes de fabricarlos en una placa final. Es la herramienta imprescindible de cualquier aficionado o estudiante de electrónica.

Internamente, los agujeros están conectados entre sí en grupos. Las filas centrales están unidas horizontalmente de cinco en cinco, mientras que las carriles laterales (marcados en rojo y azul) están unidos verticalmente y sirven para alimentación (+) y tierra (-). Al insertar componentes en los agujeros correctos, quedan automáticamente conectados sin necesidad de cables. Esto acelera el montaje y facilita las modificaciones.

Para hacer conexiones entre distintos puntos del protoboard se utilizan cables de jumpers, unos cablecitos rígidos o flexibles con extremos metálicos. Hay de distintos colores para que visualmente queda claro qué cable va a dónde. Aunque los protoboards son geniales para aprender y probar ideas, no deben usarse para proyectos definitivos, porque las conexiones son poco fiables a largo plazo. Para un proyecto final, conviene soldar los componentes a una placa permanente.', '[{"pregunta":"¿Para qué sirve un protoboard?","opciones":["Soldar","Probar circuitos sin soldar","Pintar","Guardar componentes"],"correcta":1},{"pregunta":"¿Cómo están conectadas las filas centrales?","opciones":["Al azar","Horizontalmente en grupos","Verticalmente todas","No están conectadas"],"correcta":1},{"pregunta":"¿Para qué sirven los carriles laterales?","opciones":["Decoración","Alimentación y tierra","No sirven","Solo un pin"],"correcta":1},{"pregunta":"¿Qué son los jumpers?","opciones":["Resistencias","Cables de conexión","Chips","Botones"],"correcta":1}]'::jsonb),

('robotica', 'eso', '{2}', 'Entradas Analógicas y Digitales', 'Arduino puede leer dos tipos de entradas. Las entradas digitales solo admiten dos valores: 0 (bajo, cero voltios) o 1 (alto, típicamente 5 voltios). Se usan para leer el estado de un botón, un interruptor, un sensor de contacto o cualquier dispositivo que tenga solo dos estados: activado o desactivado. Para leerlas se usa digitalRead(pin), que devuelve HIGH o LOW.

Las entradas analógicas, en cambio, pueden leer una gama continua de valores, desde 0 voltios hasta 5 voltios, convertidos en un número entre 0 y 1023 (en Arduino UNO). Se usan para leer sensores que producen una tensión variable: una LDR, un potenciómetro, un sensor de temperatura analógico, un micrófono... Cualquier magnitud que varíe con continuidad. Para leerlas se usa analogRead(pin), que devuelve un entero entre 0 y 1023.

Arduino UNO tiene 6 entradas analógicas (A0-A5) y 14 pines digitales. Algunos de los digitales pueden actuar también como salidas PWM, simulando una señal analógica mediante pulsos rápidos. Esto permite controlar el brillo de un LED, la velocidad de un motor o la posición de un servo. Entender la diferencia entre analógico y digital es fundamental para diseñar cualquier proyecto electrónico.', '[{"pregunta":"¿Qué valores tiene una entrada digital?","opciones":["De 0 a 1023","Solo 0 o 1","Solo 1","De 0 a 100"],"correcta":1},{"pregunta":"¿Qué devuelve analogRead en UNO?","opciones":["0 o 1","0 a 255","0 a 1023","0 a 5"],"correcta":2},{"pregunta":"¿Cuántas entradas analógicas tiene UNO?","opciones":["Cuatro","Seis","Ocho","Diez"],"correcta":1},{"pregunta":"¿Qué pines simulan salida analógica?","opciones":["PWM","GND","VCC","Reset"],"correcta":0}]'::jsonb),

('robotica', 'eso', '{2}', 'El Zumbador Piezoeléctrico', 'Un zumbador piezoeléctrico, llamado también buzzer, es un pequeño dispositivo que emite sonido cuando se le aplica una tensión eléctrica. Funciona gracias a un material cerámico con propiedades piezoeléctricas: cuando recibe corriente, se deforma ligeramente, y esa vibración se convierte en ondas sonoras. Es el componente ideal para añadir avisos acústicos a un proyecto Arduino.

Existen dos tipos principales. Los zumbadores activos generan un tono fijo al recibir cualquier corriente: basta con aplicarles voltaje para oír su sonido característico. Son fáciles de usar pero solo dan una frecuencia, así que no se pueden tocar melodías con ellos. Los zumbadores pasivos, en cambio, requieren que el Arduino les envíe una señal cuadrada con la frecuencia deseada; así podemos generar cualquier nota que queramos.

Con Arduino, los zumbadores pasivos se controlan con la función tone(pin, frecuencia, duracion). Por ejemplo, tone(8, 440, 500) emite un la durante medio segundo por el pin 8. Combinando varias llamadas con retardos entre ellas, se pueden tocar melodías sencillas. Es un proyecto muy popular: tocar canciones con un Arduino. No sonará como una orquesta, pero es divertido y educativo, porque enseña los conceptos de frecuencia, duración y temporización.', '[{"pregunta":"¿Qué material convierte corriente en vibración?","opciones":["Metal","Plástico","Cerámica piezoeléctrica","Goma"],"correcta":2},{"pregunta":"¿Cuál tipo suena con cualquier corriente?","opciones":["Activo","Pasivo","Digital","Analógico"],"correcta":0},{"pregunta":"¿Qué función se usa en Arduino?","opciones":["noTone()","buzz()","tone()","music()"],"correcta":2},{"pregunta":"¿Qué se puede hacer con un pasivo?","opciones":["Solo un tono","Cualquier frecuencia y melodía","Nada","Solo grave"],"correcta":1}]'::jsonb),

('robotica', 'eso', '{2}', 'El Potenciómetro Variable', 'Un potenciómetro es una resistencia cuyo valor puede variar manualmente girando un eje. Tiene tres terminales: dos extremos y un cursor central. La resistencia entre los extremos es fija, pero la que hay entre cada extremo y el cursor cambia al girar el eje. Es decir, un potenciómetro funciona como un divisor de tensión variable, que podemos usar para leer una posición como valor analógico.

En Arduino, un uso muy común del potenciómetro es como entrada analógica para controlar algo: el brillo de un LED, la velocidad de un motor, la frecuencia de un sonido, etc. Conectamos sus extremos a 5V y GND, y el cursor a un pin analógico. Al leerlo con analogRead() obtenemos un valor entre 0 y 1023 que corresponde a la posición del eje. Con map() transformamos ese rango al que necesitemos.

Los potenciómetros están en muchos aparatos cotidianos: mandos de volumen de equipos de música, reguladores de intensidad de luz, ajustes de temperatura, etc. Aunque cada vez más aparatos se controlan con botones digitales o pantallas, el potenciómetro sigue siendo una forma intuitiva de ajustar un valor continuo. En proyectos educativos se usa a menudo como primer ejemplo de entrada analógica porque permite ver inmediatamente el cambio de valor al mover el eje.', '[{"pregunta":"¿Cuántos terminales tiene?","opciones":["Dos","Tres","Cuatro","Cinco"],"correcta":1},{"pregunta":"¿Qué función cumple en Arduino?","opciones":["Motor","Entrada analógica variable","Cargador","LED"],"correcta":1},{"pregunta":"¿Qué devuelve analogRead del potenciómetro?","opciones":["Solo 0","Un valor entre 0 y 1023","Solo 1023","HIGH"],"correcta":1},{"pregunta":"¿Qué uso cotidiano tiene?","opciones":["Cargar móviles","Control de volumen, luz, temperatura","Ninguno","Frenos"],"correcta":1}]'::jsonb),

('robotica', 'eso', '{2}', 'Conexión Serie con el PC', 'Arduino puede comunicarse con el ordenador mientras se está ejecutando, enviando y recibiendo datos por el cable USB. Esta comunicación se llama "comunicación serie" y es muy útil para depurar programas (ver qué valores están leyendo los sensores) o para crear proyectos interactivos donde el ordenador y el Arduino trabajan juntos.

Para usar la comunicación serie, lo primero es iniciarla en setup() con Serial.begin(9600), donde 9600 es la velocidad en baudios (bits por segundo). Después, desde loop() podemos enviar mensajes con Serial.print() o Serial.println(). Por ejemplo, Serial.println(temperatura) enviará el valor de esa variable al ordenador, seguido de un salto de línea.

Para leer los mensajes desde el ordenador se usa el Monitor Serie del Arduino IDE, accesible con un clic en la barra superior. Al abrirlo, aparecen en tiempo real los datos que Arduino envía. Esta herramienta es imprescindible para encontrar errores: si nuestro robot no se comporta como esperamos, imprimiendo los valores de los sensores a cada paso vemos dónde se produce el problema. Además, se puede enviar datos al Arduino escribiendo en el monitor y pulsando enter, lo que permite crear sketches interactivos.', '[{"pregunta":"¿Por dónde se comunica Arduino con el PC?","opciones":["Wifi","Cable USB","Bluetooth","Infrarrojos"],"correcta":1},{"pregunta":"¿Qué función inicia la comunicación?","opciones":["Serial.start()","Serial.begin()","Serial.init()","startSerial()"],"correcta":1},{"pregunta":"¿Cómo se ven los mensajes?","opciones":["En la consola","En el Monitor Serie del IDE","En la placa","En un móvil"],"correcta":1},{"pregunta":"¿Para qué es útil?","opciones":["Solo estética","Depurar y ver datos","Cargar programas","Alimentar la placa"],"correcta":1}]'::jsonb);

