-- ROBÓTICA - 3º ESO (IoT)
-- ============================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('robotica', 'eso', '{3}', 'ESP32: Microcontrolador con Wifi', 'El ESP32 es un microcontrolador moderno desarrollado por la empresa china Espressif Systems. A diferencia del Arduino UNO, incluye conectividad inalámbrica wifi y Bluetooth directamente en el chip, lo que lo hace ideal para proyectos de Internet de las Cosas (IoT). Es más potente, más rápido y además más barato que muchas alternativas.

Entre sus características técnicas destacan un procesador dual-core a 240 MHz, más de 500 KB de memoria RAM (comparado con los 2 KB del Arduino UNO), más pines digitales y analógicos, y varios sensores integrados como un termómetro y un sensor táctil capacitivo. Puede ejecutar programas mucho más complejos y mantener conexiones de red mientras lo hace.

El ESP32 se puede programar con el Arduino IDE añadiendo el soporte correspondiente, lo que facilita la transición desde Arduino. También acepta MicroPython, una versión reducida de Python pensada para microcontroladores. Gracias a su bajo coste (entre 5 y 10 euros) y sus prestaciones, el ESP32 se ha convertido en el corazón de miles de proyectos: estaciones meteorológicas domésticas, sistemas de riego automático, cámaras con visión artificial, y cualquier proyecto que requiera conectarse a internet sin añadir hardware externo.', '[{"pregunta":"¿Qué añade ESP32 al Arduino básico?","opciones":["Nada","Wifi y Bluetooth integrados","Más botones","Ruedas"],"correcta":1},{"pregunta":"¿De qué país es su fabricante?","opciones":["EE.UU.","China","Japón","Italia"],"correcta":1},{"pregunta":"¿Qué lenguaje alternativo acepta?","opciones":["JavaScript","MicroPython","Ruby","Rust"],"correcta":1},{"pregunta":"¿Cuántos núcleos tiene?","opciones":["Uno","Dos","Cuatro","Ocho"],"correcta":1}]'::jsonb),

('robotica', 'eso', '{3}', 'Internet de las Cosas (IoT)', 'El Internet de las Cosas (IoT, del inglés Internet of Things) es la red de objetos físicos conectados a internet que recogen, envían y reciben datos. Estos objetos pueden ser electrodomésticos, coches, ropa, lámparas, sensores industriales, pulseras de actividad o prácticamente cualquier cosa con un chip y capacidad de comunicación. El IoT transforma objetos "tontos" en objetos inteligentes capaces de interactuar con otros dispositivos y con nosotros.

Un ejemplo cotidiano es la calefacción conectada, que sabemos controlar desde el móvil para que se encienda antes de llegar a casa. Otro es la nevera inteligente que avisa cuando se acaba la leche, o la pulsera que registra nuestros pasos y los envía a una aplicación. En el sector industrial, el IoT permite monitorizar máquinas en tiempo real, predecir averías y optimizar procesos, un concepto conocido como Industria 4.0.

El funcionamiento del IoT depende de varias capas: sensores que recogen datos, dispositivos con conectividad que los envían, redes (wifi, 4G/5G, LoRa, Zigbee) que los transportan, plataformas en la nube que los almacenan y analizan, y aplicaciones que los presentan al usuario. Cada capa tiene sus propios retos técnicos, pero todas deben trabajar juntas para que un simple gesto como encender una luz desde el móvil funcione sin problemas.', '[{"pregunta":"¿Qué significa IoT?","opciones":["Internet of Technology","Internet of Things","Interactive of Things","Internet Online Tools"],"correcta":1},{"pregunta":"¿Qué ejemplo industrial se cita?","opciones":["Industria 4.0","Fábrica manual","Oficina","Colegio"],"correcta":0},{"pregunta":"¿Qué capa recoge los datos?","opciones":["Nube","Sensores","Redes","Apps"],"correcta":1},{"pregunta":"¿Cuál NO es una red IoT típica?","opciones":["Wifi","5G","LoRa","Cable coaxial"],"correcta":3}]'::jsonb),

('robotica', 'eso', '{3}', 'Comunicación I2C', 'I2C (pronunciado "i cuadrado ce") es un protocolo de comunicación usado para conectar varios dispositivos electrónicos con solo dos cables. Fue inventado por Philips en los años ochenta y hoy se usa en miles de sensores, pantallas y chips de memoria. Su gran ventaja es que permite conectar múltiples dispositivos a una misma placa microcontroladora sin necesidad de un cable por cada uno, ahorrando pines.

Los dos cables se llaman SDA (datos) y SCL (reloj). El reloj sincroniza la comunicación, marcando el ritmo al que se envían los bits. Cada dispositivo conectado tiene una dirección única (un número) que el maestro usa para dirigirse a él específicamente. Así, un Arduino puede hablar con una pantalla, un reloj en tiempo real y un sensor de temperatura, todos a través de los mismos dos cables, simplemente llamándolos por su dirección.

En Arduino, la librería Wire facilita el uso de I2C. Muchos componentes vienen con librerías ya hechas que usan Wire por debajo, así que los usuarios ni siquiera necesitan entender los detalles del protocolo. Por ejemplo, para usar un módulo RTC DS3231 basta con incluir la librería RTClib y llamar a sus funciones. Aunque I2C no es el protocolo más rápido, su facilidad de uso y ahorro de pines lo hacen imprescindible en proyectos con varios componentes.', '[{"pregunta":"¿Cuántos cables usa I2C?","opciones":["Uno","Dos","Tres","Cuatro"],"correcta":1},{"pregunta":"¿Qué empresa lo inventó?","opciones":["Intel","Philips","IBM","Apple"],"correcta":1},{"pregunta":"¿Cómo se llaman los cables?","opciones":["VCC y GND","SDA y SCL","TX y RX","CLK y DTA"],"correcta":1},{"pregunta":"¿Qué librería de Arduino lo gestiona?","opciones":["Serial","Wire","SPI","I2CLib"],"correcta":1}]'::jsonb),

('robotica', 'eso', '{3}', 'MQTT: El Protocolo IoT', 'MQTT (Message Queuing Telemetry Transport) es un protocolo de mensajería ligero, diseñado específicamente para la comunicación entre dispositivos IoT. Fue creado en 1999 por IBM y Cirrus Link para conectar sensores en plataformas petrolíferas, lugares con conexiones de red inestables. Esos requisitos lo hicieron especialmente eficiente, y hoy es el estándar de facto en muchas aplicaciones IoT.

MQTT usa un modelo "publicador-suscriptor" en lugar del clásico cliente-servidor. Los dispositivos publican mensajes en "temas" (topics) concretos, y otros dispositivos que estén interesados se suscriben a esos temas para recibirlos. Entre medias hay un servidor llamado broker que distribuye los mensajes. Por ejemplo, un sensor de temperatura publica en el tema "casa/sala/temperatura", y una aplicación móvil suscrita al mismo tema recibe los valores en tiempo real.

Una ventaja clave de MQTT es su ligereza. Los mensajes son muy pequeños, lo que ahorra batería y ancho de banda. Esto es fundamental para dispositivos alimentados por batería o con conexión limitada. Brokers populares son Mosquitto (código abierto) y HiveMQ. En proyectos Arduino y ESP32 se usa frecuentemente con la librería PubSubClient, que facilita publicar y suscribirse a temas con pocas líneas de código. MQTT es clave en la domótica moderna, el smart farming y la monitorización industrial.', '[{"pregunta":"¿Qué modelo usa MQTT?","opciones":["Cliente-servidor","Publicador-suscriptor","Peer-to-peer","Monolítico"],"correcta":1},{"pregunta":"¿Quién creó MQTT?","opciones":["Microsoft","IBM y Cirrus Link","Google","Intel"],"correcta":1},{"pregunta":"¿Qué es un broker?","opciones":["Un cliente","Servidor que distribuye los mensajes","Un sensor","Una aplicación"],"correcta":1},{"pregunta":"¿Qué ventaja destaca?","opciones":["Lento","Ligereza de mensajes","Caro","Solo wifi"],"correcta":1}]'::jsonb),

('robotica', 'eso', '{3}', 'Sensor DHT22 de Temperatura y Humedad', 'El DHT22 es un sensor económico y muy popular que mide dos magnitudes a la vez: temperatura y humedad ambiental. Dentro contiene un termistor (que mide temperatura) y un sensor de humedad capacitivo. Los dos resultados se procesan internamente y se envían al microcontrolador mediante un protocolo digital de un solo cable. Es ideal para estaciones meteorológicas, invernaderos automatizados y monitorización ambiental.

Sus características técnicas incluyen un rango de temperatura de -40°C a +80°C, con una precisión de ±0,5°C, y un rango de humedad del 0 al 100% con precisión de ±2%. No es el sensor más preciso del mercado, pero su bajo coste (unos pocos euros) y su facilidad de uso lo hacen muy atractivo para proyectos educativos y hobbies. Existe una versión más básica, el DHT11, más barata pero menos precisa.

Para usarlo con Arduino se conecta al pin de alimentación (VCC), tierra (GND) y un pin digital para la señal. La librería DHT.h facilita la lectura con funciones como readTemperature() y readHumidity(). Los datos obtenidos se pueden mostrar en una pantalla, enviar por MQTT a un servidor, guardar en una tarjeta SD para análisis posterior, o usarse para tomar decisiones (encender un ventilador si hace calor, activar riego si baja la humedad del suelo).', '[{"pregunta":"¿Qué mide el DHT22?","opciones":["Solo temperatura","Temperatura y humedad","Solo humedad","Presión"],"correcta":1},{"pregunta":"¿Cuál es su precisión en temperatura?","opciones":["±0,1°C","±0,5°C","±1°C","±5°C"],"correcta":1},{"pregunta":"¿Cuál es más básico que el DHT22?","opciones":["DHT99","DHT11","DHT33","DHT44"],"correcta":1},{"pregunta":"¿Qué librería lo controla?","opciones":["Servo","DHT.h","Wire","Serial"],"correcta":1}]'::jsonb),

('robotica', 'eso', '{3}', 'Los Motores Paso a Paso', 'Un motor paso a paso (stepper motor) es un tipo de motor que gira en pequeños incrementos fijos llamados pasos. En lugar de girar continuamente como un motor normal, avanza de uno en uno cuando recibe pulsos eléctricos adecuados. Un motor típico hace 200 pasos por revolución, lo que significa que cada paso son 1,8 grados. Esta precisión exacta lo hace ideal cuando necesitamos controlar con detalle la posición del eje.

Internamente, un motor paso a paso tiene varias bobinas que se energizan en secuencia, generando campos magnéticos que hacen girar el rotor. Para controlarlo se usa un driver especializado, como el A4988 o el DRV8825 en proyectos Arduino. El driver simplifica las señales que debe enviar el microcontrolador: basta con un pin para indicar la dirección y otro para cada pulso de paso.

Los motores paso a paso se usan en impresoras 3D, máquinas CNC, plotters, escáneres, sistemas de apertura de puertas y telescopios. En todos estos casos, la posición precisa es más importante que la velocidad. Una desventaja es que consumen corriente incluso cuando están parados manteniendo la posición, lo que genera calor y gasta batería. Por eso hay que elegirlos con cuidado: no siempre son la mejor opción. A veces un servomotor o un motor DC con encoder es más apropiado.', '[{"pregunta":"¿Cuántos grados tiene un paso típico?","opciones":["0,1°","1,8°","10°","90°"],"correcta":1},{"pregunta":"¿Qué maneja las señales hacia el motor?","opciones":["El Arduino solo","Un driver como A4988","Un LED","Una resistencia"],"correcta":1},{"pregunta":"¿Dónde se usan mucho?","opciones":["Altavoces","Impresoras 3D","Bombillas","Televisores"],"correcta":1},{"pregunta":"¿Qué desventaja tienen?","opciones":["Son imprecisos","Consumen corriente incluso parados","No hay drivers","Son muy lentos"],"correcta":1}]'::jsonb),

('robotica', 'eso', '{3}', 'Impresión 3D y Prototipos', 'La impresión 3D es una técnica de fabricación aditiva que construye objetos capa a capa a partir de un modelo digital tridimensional. La más común en entornos educativos es la FDM (Fused Deposition Modeling), que funde un filamento plástico y lo va depositando con precisión para formar cada capa. Al solidificarse, queda una pieza sólida que respeta el diseño original.

En robótica, la impresión 3D es muy útil para construir piezas del chasis, soportes para sensores, carcasas para la electrónica y engranajes personalizados. Antes, hacer estas piezas requería talleres con máquinas caras o paciencia artesanal; hoy, con una impresora 3D doméstica que cuesta unos 200 euros, cualquiera puede fabricar sus propios componentes en casa o en el aula. Esto democratiza el diseño y abre infinitas posibilidades creativas.

El proceso comienza con un diseño en un programa CAD (como Tinkercad, Fusion 360 o FreeCAD). El archivo se exporta en formato STL y se procesa con un "slicer" (cortador), que lo divide en capas y genera el código que entiende la impresora. El material más usado es el PLA, un plástico biodegradable hecho de maíz, fácil de imprimir y con buen resultado. Otros materiales son el ABS (más resistente pero difícil), el PETG, la resina e incluso metal en impresoras profesionales.', '[{"pregunta":"¿Qué significa FDM?","opciones":["Fast Digital Machine","Fused Deposition Modeling","File Data Model","Flexible Design Mode"],"correcta":1},{"pregunta":"¿Qué formato exporta el CAD?","opciones":["JPG","STL","PDF","PNG"],"correcta":1},{"pregunta":"¿Qué material es biodegradable?","opciones":["ABS","PLA","Metal","PETG"],"correcta":1},{"pregunta":"¿Qué hace el slicer?","opciones":["Imprime","Divide el modelo en capas y genera el código","Corta papel","Mide"],"correcta":1}]'::jsonb),

('robotica', 'eso', '{3}', 'La Domótica', 'La domótica es la automatización de los hogares mediante tecnología. Su objetivo es hacer que las casas sean más cómodas, seguras, eficientes y accesibles gracias a dispositivos que controlan las luces, la calefacción, las persianas, la seguridad, los electrodomésticos y prácticamente cualquier aspecto del entorno doméstico. Forma parte del concepto más amplio de smart home (casa inteligente).

Los sistemas domóticos pueden ser cerrados o abiertos. Los cerrados son los que venden grandes empresas como una solución completa: instalan sus dispositivos, sus aplicaciones y sus servidores, pero suelen ser caros y no se pueden combinar con otros sistemas. Los abiertos, como los basados en el software Home Assistant, permiten combinar dispositivos de distintos fabricantes y personalizar cualquier aspecto del comportamiento.

En proyectos educativos de robótica se pueden construir versiones caseras de domótica con Arduino o ESP32: una luz que se enciende automáticamente al detectar presencia, una persiana motorizada controlable por móvil, un sistema de riego que mide la humedad del suelo. Estos proyectos combinan sensores, actuadores, conectividad y lógica de programación, dando al estudiante una visión completa de cómo funcionan los sistemas IoT reales.', '[{"pregunta":"¿Qué busca la domótica?","opciones":["Casas vacías","Hogares más cómodos, seguros, eficientes","Menos aparatos","Más ruido"],"correcta":1},{"pregunta":"¿Cómo se llaman también las casas domóticas?","opciones":["Big house","Smart home","Wild home","Main home"],"correcta":1},{"pregunta":"¿Qué es Home Assistant?","opciones":["Un teléfono","Software de domótica abierto","Un sensor","Una IA"],"correcta":1},{"pregunta":"¿Qué placa educativa se usa?","opciones":["GPU","Arduino o ESP32","Televisor","Frigorífico"],"correcta":1}]'::jsonb),

('robotica', 'eso', '{3}', 'Los Robots Industriales', 'Los robots industriales son máquinas automatizadas que realizan tareas repetitivas en fábricas, reemplazando o asistiendo el trabajo humano. Se usan sobre todo en la industria automovilística, donde soldar, pintar y ensamblar requieren precisión constante. El primer robot industrial, Unimate, se instaló en 1961 en una fábrica de General Motors, marcando el inicio de una transformación industrial sin precedentes.

Existen distintos tipos. Los robots articulados tienen brazos con varias articulaciones, parecidos a un brazo humano pero más versátiles y fuertes. Los robots cartesianos se mueven a lo largo de tres ejes rectos (X, Y, Z), ideales para tareas de "coger y colocar" muy precisas. Los robots SCARA mezclan ambos enfoques y son muy rápidos. Los robots paralelos, con forma de araña, destacan por su velocidad extrema en el embalaje de productos.

Los robots industriales se programan con lenguajes específicos de cada fabricante (ABB, KUKA, FANUC, Yaskawa) y siguen funcionando durante años con mantenimiento mínimo. Aumentan la productividad, reducen los errores y hacen tareas peligrosas para los humanos. Pero también plantean debates sobre empleo: ¿qué pasa con los trabajadores que pierden sus puestos? Muchos expertos sostienen que los robots crean nuevos empleos en otras áreas (programación, mantenimiento, diseño), pero la transición no siempre es fácil.', '[{"pregunta":"¿En qué industria destaca su uso?","opciones":["Textil","Automovilística","Agricultura","Pesca"],"correcta":1},{"pregunta":"¿Cuándo se instaló Unimate?","opciones":["1910","1961","1990","2010"],"correcta":1},{"pregunta":"¿Cuál es conocido por su velocidad extrema en embalaje?","opciones":["Articulado","Cartesiano","SCARA","Paralelo"],"correcta":3},{"pregunta":"¿Cuál NO es un fabricante?","opciones":["ABB","KUKA","FANUC","Apple"],"correcta":3}]'::jsonb),

('robotica', 'eso', '{3}', 'Los Drones', 'Un dron es una aeronave no tripulada que se pilota por control remoto o vuela de manera autónoma siguiendo un programa. Técnicamente se llaman UAV (Unmanned Aerial Vehicle). Los modelos más conocidos son los multirrotores, que usan cuatro, seis u ocho hélices para sustentarse y maniobrar en el aire. Los más comunes son los cuadricópteros, con cuatro hélices, que ofrecen un buen equilibrio entre simplicidad y estabilidad.

Los drones surgieron como tecnología militar, pero en los últimos años se han popularizado enormemente como herramientas civiles. Hoy se usan para fotografía aérea, grabación de vídeo, agricultura de precisión, inspección de infraestructuras, vigilancia forestal, rescate en zonas inaccesibles, reparto de paquetes y, por supuesto, ocio y deporte. Los drones de competición pueden alcanzar velocidades superiores a 200 km/h.

En muchos países, incluido España, el uso de drones está regulado. Hay que registrarse, obtener licencias para ciertos usos, respetar alturas máximas y zonas prohibidas (cerca de aeropuertos, multitudes, edificios oficiales). Los drones educativos suelen ser pequeños y seguros, diseñados para aprender a programarlos con bloques o Python. Aprender a manejar un dron enseña conceptos de física, aerodinámica, control automático y regulación legal, todo a la vez.', '[{"pregunta":"¿Cómo se llaman los drones en inglés?","opciones":["UAV","GPS","UFO","AIS"],"correcta":0},{"pregunta":"¿Cuántas hélices tiene un cuadricóptero?","opciones":["Dos","Tres","Cuatro","Seis"],"correcta":2},{"pregunta":"¿De dónde vienen los drones originalmente?","opciones":["Pesca","Uso militar","Cine","Ocio"],"correcta":1},{"pregunta":"¿Qué regulaciones existen?","opciones":["Ninguna","Licencias, alturas y zonas prohibidas","Solo tasas","Solo el peso"],"correcta":1}]'::jsonb);

