-- ROBÓTICA - 4º ESO (IA en robótica)
-- ============================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('robotica', 'eso', '{4}', 'Visión por Computador', 'La visión por computador es el campo de la informática dedicado a dar a las máquinas la capacidad de ver e interpretar imágenes, como hacen los ojos humanos. Un robot con visión por computador puede analizar lo que hay frente a él: identificar objetos, reconocer rostros, medir distancias, seguir el movimiento, leer textos o detectar anomalías. Es una de las áreas de la IA que más ha avanzado en los últimos años.

El proceso habitual comienza con una cámara que capta una imagen. El ordenador la convierte en una matriz de píxeles (números que representan colores) y la procesa con algoritmos. Las operaciones clásicas incluyen la detección de bordes, el filtrado de ruido, el reconocimiento de formas y la segmentación. Hoy, gran parte del trabajo se realiza con redes neuronales entrenadas específicamente para tareas de visión, como YOLO (You Only Look Once), capaz de detectar objetos en tiempo real.

Las aplicaciones son infinitas. En robótica industrial, un brazo robótico puede usar visión para clasificar piezas defectuosas en una línea de producción. En coches autónomos, la visión permite reconocer peatones, señales de tráfico y otros vehículos. En medicina, ayuda a analizar radiografías y detectar tumores. En agricultura, drones con cámaras evalúan el estado de los cultivos. La visión por computador ha transformado prácticamente todos los sectores productivos.', '[{"pregunta":"¿Qué da la visión por computador a las máquinas?","opciones":["Oído","Capacidad de ver e interpretar imágenes","Gusto","Olfato"],"correcta":1},{"pregunta":"¿En qué se convierte una imagen para el ordenador?","opciones":["Texto","Matriz de píxeles","Audio","Código morse"],"correcta":1},{"pregunta":"¿Qué es YOLO?","opciones":["Un coche","Red neuronal de detección en tiempo real","Un cable","Un sensor"],"correcta":1},{"pregunta":"¿Qué aplicación médica se menciona?","opciones":["Pintar","Analizar radiografías","Cocinar","Cortar pelo"],"correcta":1}]'::jsonb),

('robotica', 'eso', '{4}', 'Redes Neuronales Artificiales', 'Las redes neuronales artificiales son un tipo de algoritmo de inteligencia artificial inspirado vagamente en el funcionamiento del cerebro humano. Están formadas por "neuronas" artificiales organizadas en capas: una capa de entrada que recibe los datos, una o varias capas ocultas que procesan la información, y una capa de salida que produce el resultado. Cada neurona aplica una operación matemática simple, pero en conjunto son capaces de aprender tareas muy complejas.

El aprendizaje de una red neuronal se realiza ajustando los pesos de las conexiones entre neuronas. Al principio, los pesos son aleatorios y la red produce resultados erróneos. Durante el entrenamiento se le muestran muchos ejemplos con las respuestas correctas, y un algoritmo llamado retropropagación ajusta los pesos para reducir los errores. Después de millones de repeticiones, la red aprende a reconocer patrones con gran precisión.

Las redes neuronales profundas (deep neural networks) tienen muchas capas ocultas y son capaces de aprender representaciones muy abstractas. Son el núcleo de los grandes avances recientes en IA: reconocimiento de voz, traducción automática, generación de imágenes, coches autónomos. En robótica, las redes neuronales permiten a los robots aprender a caminar, a manipular objetos complejos o a interpretar comandos de voz sin necesidad de programar cada detalle.', '[{"pregunta":"¿En qué están inspiradas?","opciones":["En el hígado","En el cerebro humano","En el corazón","En los pulmones"],"correcta":1},{"pregunta":"¿Cómo se llaman las capas intermedias?","opciones":["Visibles","Ocultas","Finales","Iniciales"],"correcta":1},{"pregunta":"¿Qué algoritmo ajusta los pesos?","opciones":["Fuerza bruta","Retropropagación","Ordenación","Búsqueda binaria"],"correcta":1},{"pregunta":"¿Qué son las redes profundas?","opciones":["Con una sola capa","Con muchas capas ocultas","Sin capas","Con capas circulares"],"correcta":1}]'::jsonb),

('robotica', 'eso', '{4}', 'Aprendizaje por Refuerzo', 'El aprendizaje por refuerzo es una rama del machine learning donde un agente aprende a tomar decisiones interactuando con un entorno. La idea es similar a cómo aprende un animal: prueba diferentes acciones, observa los resultados y, cuando una acción produce un buen resultado (una "recompensa"), tiende a repetirla en el futuro. Al revés, evita las acciones con consecuencias negativas. Con el tiempo, desarrolla una "política" óptima para conseguir el mayor premio posible.

Esta técnica ha conseguido resultados asombrosos. En 2016, un programa llamado AlphaGo, desarrollado por DeepMind, venció al campeón del mundo de Go, un juego de estrategia oriental considerado mucho más complejo que el ajedrez. AlphaGo aprendió jugando millones de partidas contra sí mismo, mejorando con cada una. Posteriormente, AlphaZero aprendió ajedrez, shogi y Go por sí solo sin ninguna información previa, alcanzando niveles sobrehumanos en pocas horas.

En robótica, el aprendizaje por refuerzo permite entrenar robots para tareas complejas como caminar, correr, saltar o manipular objetos. En lugar de programar cada movimiento a mano, se simulan millones de intentos en un ordenador y se premian los que conducen a buenos resultados. El robot aprende por sí mismo la mejor manera de moverse. Esta técnica es prometedora pero costosa: requiere grandes cantidades de cálculo y un diseño cuidadoso de las recompensas.', '[{"pregunta":"¿Cómo aprende el agente?","opciones":["Leyendo","Recibiendo recompensas por sus acciones","Por instrucciones","Por copia"],"correcta":1},{"pregunta":"¿Qué juego venció AlphaGo?","opciones":["Ajedrez","Go","Damas","Póker"],"correcta":1},{"pregunta":"¿Cómo aprendió AlphaZero?","opciones":["Leyendo libros","Jugando contra sí mismo","Copiando","Al azar"],"correcta":1},{"pregunta":"¿Qué se usa para entrenar robots así?","opciones":["Simulaciones con millones de intentos","Instrucciones directas","Copias de humanos","Manuales"],"correcta":0}]'::jsonb),

('robotica', 'eso', '{4}', 'Navegación Autónoma y SLAM', 'SLAM son las siglas en inglés de Simultaneous Localization and Mapping (localización y mapeo simultáneos). Es la técnica que permite a un robot moverse por un espacio desconocido creando un mapa del entorno al mismo tiempo que averigua su propia posición dentro de él. Es un problema clásico de la robótica móvil, porque para crear un mapa fiable el robot necesita saber dónde está, pero para saber dónde está necesita un mapa. Resolver esta paradoja es lo que hace SLAM.

Para lograrlo, el robot combina datos de múltiples sensores. Los más comunes son los LIDAR (que lanzan pulsos láser para medir distancias a objetos circundantes), cámaras, sensores inerciales (IMU) que miden aceleraciones y giros, y los encoders de las ruedas, que cuentan las vueltas para estimar el movimiento. Con todas estas fuentes, algoritmos matemáticos van construyendo progresivamente el mapa y la trayectoria del robot.

SLAM es esencial para los robots aspiradores que mapean tu casa, los coches autónomos que se orientan por las ciudades, los robots de almacén que se mueven por la logística y hasta los rovers marcianos que exploran planetas. Los principales algoritmos (EKF-SLAM, Graph-SLAM, Visual SLAM) difieren en los sensores que usan y en los detalles matemáticos. Es un tema activo de investigación y una de las áreas más interesantes de la robótica moderna.', '[{"pregunta":"¿Qué significa SLAM?","opciones":["Simultaneous Localization and Mapping","Solo Localization Algorithm","Simple Location Map","Smart Light Auto Map"],"correcta":0},{"pregunta":"¿Qué sensor láser se usa?","opciones":["LIDAR","Termómetro","Micrófono","Barómetro"],"correcta":0},{"pregunta":"¿Dónde se usa SLAM?","opciones":["Robots aspiradores","Coches autónomos","Rovers marcianos","Todas son correctas"],"correcta":3},{"pregunta":"¿Qué paradoja resuelve?","opciones":["Ninguna","Necesita mapa y posición a la vez","Solo mapa","Solo posición"],"correcta":1}]'::jsonb),

('robotica', 'eso', '{4}', 'Robots Sociales', 'Los robots sociales son aquellos diseñados para interactuar con humanos de manera amigable, emocional o terapéutica. A diferencia de los robots industriales, que hacen tareas repetitivas, los sociales buscan comunicarse, ayudar o acompañar. Tienen rostros expresivos, voces agradables y capacidades para reconocer emociones. Son un campo en rápido crecimiento con aplicaciones en educación, salud y asistencia.

Uno de los más famosos es Pepper, un robot humanoide creado por SoftBank Robotics en 2014. Mide 1,20 m, tiene cara expresiva con ojos LED, y una pantalla táctil en el pecho. Reconoce voces, rostros y emociones básicas, pudiendo adaptar su comportamiento. Se ha usado en tiendas, hoteles, colegios y hospitales como recepcionista o compañero para pacientes. Otro ejemplo es Paro, un robot con forma de foca bebé diseñado para calmar a enfermos de demencia, que ha demostrado efectos terapéuticos reales.

Los robots sociales plantean dilemas interesantes. ¿Es ético que un niño forme un vínculo afectivo con un robot? ¿Pueden sustituir la compañía humana en residencias de ancianos? ¿Qué pasa con la privacidad cuando un robot escucha y ve todo lo que ocurre en una casa? Los investigadores trabajan no solo en mejorar las capacidades técnicas de estos robots, sino también en definir unos principios éticos que garanticen que su uso es responsable y beneficioso para las personas.', '[{"pregunta":"¿Qué buscan los robots sociales?","opciones":["Ser rápidos","Interactuar con humanos amigablemente","Trabajar en fábricas","Pescar"],"correcta":1},{"pregunta":"¿Quién creó Pepper?","opciones":["Sony","SoftBank Robotics","Boston Dynamics","Apple"],"correcta":1},{"pregunta":"¿Qué forma tiene Paro?","opciones":["Perro","Foca bebé","Gato","Oso"],"correcta":1},{"pregunta":"¿Qué dilema se plantea?","opciones":["Ninguno","Afectos y privacidad","Solo costes","Solo estética"],"correcta":1}]'::jsonb),

('robotica', 'eso', '{4}', 'Coches Autónomos', 'Un coche autónomo es un vehículo capaz de conducir sin intervención humana, gracias a sensores, cámaras, sistemas de IA y mapas digitales. Se clasifican en niveles de autonomía, del 0 (conducción totalmente manual) al 5 (plena autonomía en cualquier situación). La mayoría de coches actuales con "autopilot" están en nivel 2 o 3, donde el coche puede gestionar carretera en ciertas condiciones pero el conductor debe estar atento.

Para funcionar, un coche autónomo combina múltiples tecnologías. Los sensores LIDAR crean mapas 3D del entorno. Las cámaras reconocen señales, semáforos, peatones y otros vehículos. Los radares detectan objetos a largo alcance, incluso con lluvia o niebla. Los sistemas GPS sitúan el coche en un mapa detallado. Todos estos datos se procesan en tiempo real por redes neuronales entrenadas con millones de horas de conducción. La redundancia (varios sensores solapándose) es clave para la seguridad.

El desarrollo de coches autónomos plantea retos éticos, legales y técnicos enormes. En caso de accidente inevitable, ¿a quién debe proteger el algoritmo? ¿Quién es responsable legal: el fabricante, el propietario o el software? ¿Cómo garantizamos que la IA no falle en situaciones extrañas? Empresas como Waymo, Tesla, Cruise y otras siguen avanzando, pero la autonomía total en entornos reales todavía no es realidad. Los expertos estiman que tardaremos años, o décadas, en verla completamente desplegada.', '[{"pregunta":"¿Qué nivel es plena autonomía?","opciones":["0","3","5","10"],"correcta":2},{"pregunta":"¿Qué sensor crea mapa 3D?","opciones":["LIDAR","Termómetro","Acelerómetro","Sonar"],"correcta":0},{"pregunta":"¿Qué es la redundancia?","opciones":["Sobrar","Tener varios sensores solapados por seguridad","Un código","Una velocidad"],"correcta":1},{"pregunta":"¿Qué empresas lo desarrollan?","opciones":["Solo Tesla","Waymo, Tesla, Cruise...","Ninguna","Solo estatales"],"correcta":1}]'::jsonb),

('robotica', 'eso', '{4}', 'Brazos Robóticos Colaborativos', 'Los cobots, o robots colaborativos, son brazos robóticos diseñados para trabajar junto a personas sin necesidad de barreras de seguridad. A diferencia de los robots industriales tradicionales, que se encierran tras vallas por su potencia y peligro, los cobots son más ligeros, más lentos y están equipados con sensores que detectan el contacto humano y se detienen instantáneamente. Esto permite integrarlos en pequeños talleres y empresas que no podrían permitirse soluciones industriales completas.

El pionero en cobots fue Universal Robots, una empresa danesa que lanzó su primer modelo UR5 en 2008. Desde entonces, los cobots han proliferado en multitud de sectores: automoción, electrónica, alimentación, laboratorios, arte. Un cobot puede atornillar tornillos, montar componentes, empaquetar productos, pintar piezas o incluso asistir en cirugías con supervisión médica. Su gran ventaja es la facilidad de reprogramación: muchos permiten enseñarles movimientos simplemente moviendo el brazo con la mano.

Los cobots cambian la relación entre robots y trabajadores. En lugar de sustituir a los humanos, los complementan: el robot hace las tareas repetitivas, pesadas o peligrosas, mientras el humano aporta juicio, flexibilidad y creatividad. Este enfoque se conoce como "robotización colaborativa" y gana fuerza año tras año. Para manejarlos se requiere formación específica, y cada vez más centros formativos incluyen cobots en sus programas de robótica industrial.', '[{"pregunta":"¿Qué significa cobot?","opciones":["Cosa con botones","Robot colaborativo","Combate robot","Compact robot"],"correcta":1},{"pregunta":"¿Qué empresa fue pionera?","opciones":["ABB","Universal Robots","KUKA","FANUC"],"correcta":1},{"pregunta":"¿Por qué no necesitan vallas?","opciones":["Son muy rápidos","Detectan contacto y se detienen","Son invisibles","Trabajan lejos"],"correcta":1},{"pregunta":"¿Cómo se enseñan muchos movimientos?","opciones":["Programación lenta","Moviendo el brazo con la mano","Leyendo libros","A distancia"],"correcta":1}]'::jsonb),

('robotica', 'eso', '{4}', 'Ética de la IA en Robótica', 'Con el avance de la inteligencia artificial y la robótica surgen preguntas éticas cada vez más urgentes. Si un robot toma decisiones que afectan a personas (como un coche autónomo o un robot de asistencia médica), ¿quién es responsable de sus actos? ¿Cómo garantizamos que sus decisiones sean justas y no reflejen prejuicios ocultos en los datos con que ha aprendido? Estos dilemas no tienen respuestas simples, pero es fundamental afrontarlos antes de que la tecnología esté demasiado extendida.

Una preocupación central son los sesgos algorítmicos. Si entrenamos una red neuronal con datos que contienen prejuicios (por ejemplo, imágenes donde ciertos grupos están infrarrepresentados), el resultado heredará esos prejuicios. Ha habido casos reales: sistemas de reconocimiento facial que funcionan peor con caras de personas negras, algoritmos de contratación que penalizan a mujeres, IAs médicas que no sirven para todas las poblaciones. Solucionarlo requiere datos equilibrados, auditorías y transparencia.

Otros temas son el uso militar de robots autónomos (los llamados "sistemas de armas letales autónomas"), la posible pérdida masiva de empleo por la automatización y el control de las superinteligencias futuras. La Unión Europea aprobó en 2024 la primera Ley de IA del mundo, que clasifica los sistemas por riesgo y prohíbe algunos usos. Pero la regulación va siempre por detrás de la tecnología, y los retos éticos seguirán creciendo en los próximos años.', '[{"pregunta":"¿Qué son los sesgos algorítmicos?","opciones":["Errores técnicos","Prejuicios heredados de los datos","Fallos de hardware","Virus"],"correcta":1},{"pregunta":"¿Cuándo aprobó la UE la Ley de IA?","opciones":["2010","2018","2024","2030"],"correcta":2},{"pregunta":"¿Qué sistemas militares preocupan?","opciones":["Aviones","Armas letales autónomas","Tanques normales","Rifles"],"correcta":1},{"pregunta":"¿Qué es importante en los datos?","opciones":["Mucho volumen","Estén equilibrados","Sean anónimos","Sean cortos"],"correcta":1}]'::jsonb),

('robotica', 'eso', '{4}', 'Exoesqueletos Robotizados', 'Un exoesqueleto es una estructura mecánica que se coloca sobre el cuerpo humano y lo asiste en sus movimientos, multiplicando su fuerza o ayudando a moverse. Los hay pasivos (sin motor, solo mecánicos) y activos (con motores eléctricos o hidráulicos controlados por sensores). Pueden cubrir todo el cuerpo o solo partes como brazos, piernas o columna. Son una de las aplicaciones más prometedoras de la robótica.

En medicina, los exoesqueletos ayudan a personas con paraplejia a volver a caminar. El ReWalk y el Ekso son dos ejemplos comerciales que permiten a usuarios con lesión medular desplazarse por sí mismos, con apoyo en muletas. Los fisioterapeutas los utilizan también para rehabilitar pacientes tras accidentes o ictus, ayudándolos a recuperar movimiento de forma guiada.

Otra aplicación es la industrial. Trabajadores que cargan pesos o mantienen posturas forzadas durante horas pueden usar exoesqueletos pasivos que distribuyen el esfuerzo y reducen la fatiga muscular. Algunas empresas los han incorporado en sus cadenas de montaje para prevenir lesiones laborales. Los exoesqueletos militares, por su parte, están en desarrollo para soldados que deben cargar equipamiento pesado en condiciones duras. Esta tecnología combina robótica, biomecánica, electrónica y diseño ergonómico, todo al servicio del cuerpo humano.', '[{"pregunta":"¿Qué tipos de exoesqueletos hay?","opciones":["Solo activos","Pasivos y activos","Solo pasivos","Digitales"],"correcta":1},{"pregunta":"¿Cuál es un uso médico?","opciones":["Paraplejia","Gripe","Caries","Dolor de cabeza"],"correcta":0},{"pregunta":"¿Para qué se usa en la industria?","opciones":["Estéticamente","Distribuir esfuerzo y prevenir lesiones","Para comunicar","Para ver mejor"],"correcta":1},{"pregunta":"¿Qué campos combina esta tecnología?","opciones":["Solo electrónica","Robótica, biomecánica, electrónica, ergonomía","Solo medicina","Solo mecánica"],"correcta":1}]'::jsonb),

('robotica', 'eso', '{4}', 'Ros: Sistema Operativo de Robots', 'ROS (Robot Operating System) es un sistema de software libre que se ha convertido en el estándar de facto para el desarrollo de robots modernos. A pesar de su nombre, no es un sistema operativo en sentido estricto, sino un framework que ofrece herramientas, librerías y convenciones para crear aplicaciones robóticas complejas. Fue desarrollado inicialmente en el laboratorio Willow Garage en 2007 y hoy lo utilizan universidades, empresas y aficionados en todo el mundo.

Lo que hace potente a ROS es su arquitectura modular. En lugar de tener un único programa gigante, una aplicación ROS consta de múltiples "nodos" (pequeños programas) que se comunican entre sí mediante "topics" (similares a los de MQTT). Un nodo puede encargarse de leer la cámara, otro de procesar imágenes, otro de controlar los motores. Esta división facilita el desarrollo, permite probar partes por separado y reutilizar código de otros proyectos.

ROS incluye herramientas muy útiles: simuladores (como Gazebo, donde puedes probar robots virtuales antes de construirlos), visores (como RViz, que muestra datos de sensores en 3D), y paquetes para tareas comunes como SLAM, visión o manipulación. Gracias a su comunidad abierta, un programador nunca empieza de cero: probablemente ya exista un paquete ROS para lo que quiere hacer. Aprender ROS es casi obligatorio para cualquiera que quiera dedicarse profesionalmente a la robótica avanzada.', '[{"pregunta":"¿Qué significa ROS?","opciones":["Robot Original System","Robot Operating System","Real Open Source","Robotic Online Service"],"correcta":1},{"pregunta":"¿Cómo se organiza una aplicación ROS?","opciones":["Un único programa","Múltiples nodos que se comunican","Sin programa","Con bases de datos"],"correcta":1},{"pregunta":"¿Qué es Gazebo?","opciones":["Un lenguaje","Un simulador de robots","Un sensor","Un robot"],"correcta":1},{"pregunta":"¿Dónde nació ROS?","opciones":["MIT","Willow Garage","Stanford","Google"],"correcta":1}]'::jsonb);

-- ============================================================
-- TECNOLOGÍA - 1º ESO (materiales)
-- ============================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('tecnologia', 'eso', '{1}', 'Materiales: Clasificación General', 'En tecnología llamamos materiales a las sustancias con las que fabricamos objetos. Su elección condiciona cómo será el producto final: su peso, resistencia, durabilidad, coste, estética y facilidad de trabajo. Los materiales se clasifican en grandes familias según su origen y propiedades: maderas y derivados, metales, materiales pétreos y cerámicos, plásticos y textiles, además de los materiales compuestos modernos.

Cada familia tiene unas propiedades características que determinan sus usos. La madera es cálida, fácil de trabajar con herramientas sencillas pero sensible a la humedad. Los metales son duros, conducen electricidad y se pueden moldear, aunque son pesados y se oxidan. Los plásticos son ligeros y moldeables, pero contaminantes si no se reciclan. Las cerámicas resisten altas temperaturas pero son frágiles. Los textiles son flexibles y cómodos.

Hoy se valoran también criterios como la sostenibilidad: preferimos materiales renovables, reciclables y de bajo impacto ambiental. Los ingenieros estudian las propiedades de los materiales para escoger el más adecuado en cada caso: no tiene sentido hacer un tornillo de madera ni una casa de plástico. Elegir bien el material es uno de los primeros pasos de cualquier proyecto tecnológico.', '[{"pregunta":"¿Qué son los materiales en tecnología?","opciones":["Solo plásticos","Sustancias con las que fabricamos objetos","Herramientas","Programas"],"correcta":1},{"pregunta":"¿Qué material es sensible a la humedad?","opciones":["Plástico","Madera","Acero inoxidable","Vidrio"],"correcta":1},{"pregunta":"¿Qué familia es frágil pero resiste el calor?","opciones":["Metales","Cerámicas","Textiles","Maderas"],"correcta":1},{"pregunta":"¿Qué criterio moderno se valora?","opciones":["Sostenibilidad","Olor","Color","Nombre"],"correcta":0}]'::jsonb),

('tecnologia', 'eso', '{1}', 'Tipos de Madera', 'La madera es un material natural que obtenemos de los árboles. Ha sido utilizada por el ser humano desde la prehistoria para construir herramientas, muebles, viviendas y barcos. Se clasifica en dos grandes grupos según su dureza: maderas blandas (coníferas como el pino, el abeto o el cedro) y maderas duras (frondosas como el roble, la haya, el nogal o el olmo). Las blandas son más fáciles de trabajar y baratas; las duras, más resistentes y caras.

Además de la madera maciza, existen los llamados derivados de la madera. El contrachapado está hecho con láminas finas pegadas en direcciones perpendiculares, lo que le da gran resistencia. El aglomerado se fabrica prensando virutas con resinas y es barato, aunque menos resistente. El DM (Densidad Media) o MDF es similar al aglomerado pero con fibras más finas, lo que da un acabado liso ideal para pintar. Estos derivados aprovechan restos de la madera maciza y reducen el desperdicio.

La madera es un material renovable si proviene de bosques gestionados sosteniblemente. Las certificaciones FSC y PEFC garantizan que la madera procede de explotaciones responsables. Al trabajar la madera en clase conviene usar herramientas adecuadas (serrucho, sierra de marquetería, lija, martillo) y respetar las medidas de seguridad. La madera es probablemente el material más común en los proyectos de tecnología escolar.', '[{"pregunta":"¿Qué es una madera blanda?","opciones":["De frutales","Coníferas como pino","Roble","Madera muerta"],"correcta":1},{"pregunta":"¿Qué es el DM/MDF?","opciones":["Madera maciza","Fibras finas prensadas","Un tipo de cerámica","Un plástico"],"correcta":1},{"pregunta":"¿Qué certificaciones verifican la gestión sostenible?","opciones":["FSC y PEFC","ISO 9001","UNE","CE"],"correcta":0},{"pregunta":"¿Qué derivado usa láminas cruzadas?","opciones":["Aglomerado","Contrachapado","DM","Tablero"],"correcta":1}]'::jsonb),

('tecnologia', 'eso', '{1}', 'Los Metales y sus Propiedades', 'Los metales son materiales caracterizados por su brillo, su capacidad de conducir el calor y la electricidad, y su ductilidad (se pueden estirar en hilos) y maleabilidad (se pueden laminar). Estas propiedades los hacen imprescindibles en la industria. Los metales puros se obtienen a partir de minerales mediante procesos de fundición, donde se calientan a altas temperaturas para separarlos de las impurezas.

Se clasifican en dos grandes grupos: ferrosos y no ferrosos. Los ferrosos contienen hierro; incluyen el acero (hierro con algo de carbono), muy usado en construcción y herramientas, y la fundición, más frágil pero fácil de moldear. Los no ferrosos no contienen hierro: el aluminio (ligero y resistente, usado en aviones y latas), el cobre (excelente conductor eléctrico, usado en cables), el zinc, el plomo, el estaño o metales preciosos como el oro y la plata.

Muchas aplicaciones no usan metales puros, sino aleaciones: combinaciones de dos o más metales, o de un metal con otros elementos, que mejoran las propiedades. El acero inoxidable es una aleación de hierro, cromo y níquel que no se oxida. El bronce es cobre con estaño, más duro que cada uno por separado. Las aleaciones permiten adaptar las propiedades a cada uso concreto, lo que las hace fundamentales en ingeniería.', '[{"pregunta":"¿Qué propiedad permite estirar un metal en hilos?","opciones":["Maleabilidad","Ductilidad","Dureza","Fragilidad"],"correcta":1},{"pregunta":"¿Qué metales son ferrosos?","opciones":["Aluminio","Contienen hierro","Cobre","Oro"],"correcta":1},{"pregunta":"¿Qué metal es buen conductor eléctrico?","opciones":["Hierro","Cobre","Plomo","Estaño"],"correcta":1},{"pregunta":"¿Qué es el bronce?","opciones":["Aleación de cobre y estaño","Hierro puro","Aluminio","Cerámica"],"correcta":0}]'::jsonb),

('tecnologia', 'eso', '{1}', 'Los Plásticos', 'Los plásticos son materiales sintéticos derivados, en su mayor parte, del petróleo. Están formados por largas cadenas de moléculas llamadas polímeros. Desde su aparición a principios del siglo XX, los plásticos han revolucionado la industria y la vida cotidiana. Son ligeros, moldeables, aislantes, resistentes a la humedad y baratos de producir, por lo que se encuentran en miles de objetos a nuestro alrededor.

Se clasifican en dos grandes grupos. Los termoplásticos se ablandan al calentarlos y pueden moldearse muchas veces; ejemplos son el polietileno (PE, bolsas y envases), el PVC (tuberías, marcos), el polipropileno (PP, tápers), el poliestireno (PS, vasos desechables). Los termoestables se endurecen al calentarlos una primera vez y ya no pueden fundirse de nuevo; incluyen las resinas epoxi y los fenólicos. La diferencia es importante para el reciclado, porque los termoplásticos sí se pueden reciclar y los termoestables no.

El gran problema del plástico es medioambiental. Tardan siglos en degradarse y gran parte acaba en vertederos y océanos, formando microplásticos que contaminan toda la cadena alimentaria. Para reducir el impacto, conviene usar menos plásticos de un solo uso, reciclar correctamente los envases y buscar alternativas más sostenibles como los bioplásticos hechos a partir de materias orgánicas. La tecnología avanza, pero cada persona puede contribuir con gestos pequeños.', '[{"pregunta":"¿De qué vienen la mayoría de plásticos?","opciones":["De plantas","Del petróleo","Del agua","De rocas"],"correcta":1},{"pregunta":"¿Qué plásticos se pueden reciclar fácilmente?","opciones":["Termoestables","Termoplásticos","Ambos por igual","Ninguno"],"correcta":1},{"pregunta":"¿Qué son los microplásticos?","opciones":["Plásticos grandes","Pequeños fragmentos que contaminan","Plásticos coloridos","Plásticos líquidos"],"correcta":1},{"pregunta":"¿Qué plástico se usa para bolsas?","opciones":["PE (polietileno)","PVC","PS","Epoxi"],"correcta":0}]'::jsonb),

('tecnologia', 'eso', '{1}', 'Dibujo Técnico: Escuadra y Cartabón', 'La escuadra y el cartabón son dos reglas triangulares básicas del dibujo técnico. La escuadra tiene forma de triángulo rectángulo isósceles, con ángulos de 45°, 45° y 90°. El cartabón es también un triángulo rectángulo pero escaleno, con ángulos de 30°, 60° y 90°. Ambos forman parte del equipo esencial de cualquier estudiante de tecnología o de artes plásticas.

Usados conjuntamente permiten trazar líneas paralelas, perpendiculares y con distintos ángulos. Por ejemplo, si apoyamos el cartabón sobre la escuadra y lo deslizamos, obtenemos líneas paralelas. Combinando las inclinaciones de ambos instrumentos conseguimos ángulos de 15°, 75°, 45°, 30°, 60° y 90°, prácticamente todos los más comunes en los dibujos técnicos. Con paciencia y precisión, el estudiante domina esta combinación rápidamente.

Hoy el dibujo técnico a mano compite con los programas CAD de ordenador, pero sigue siendo una habilidad formativa valiosa. Entrenar la precisión manual, controlar el trazo y entender la geometría del espacio no se consiguen igual con un ratón. Por eso en los primeros cursos de tecnología se sigue enseñando el uso correcto de reglas, escuadras, cartabones y compases, antes de dar el salto al CAD.', '[{"pregunta":"¿Qué ángulos tiene la escuadra?","opciones":["45, 45, 90","30, 60, 90","15, 75, 90","0, 90, 90"],"correcta":0},{"pregunta":"¿Qué ángulos tiene el cartabón?","opciones":["45, 45, 90","30, 60, 90","20, 70, 90","50, 40, 90"],"correcta":1},{"pregunta":"¿Qué podemos trazar con ambos?","opciones":["Solo círculos","Líneas paralelas y perpendiculares","Flechas","Dibujos a mano alzada"],"correcta":1},{"pregunta":"¿Qué sustituye al dibujo manual en industria?","opciones":["Nada","Programas CAD","Fotografía","Pintura"],"correcta":1}]'::jsonb),

('tecnologia', 'eso', '{1}', 'Herramientas Básicas del Taller', 'El taller de tecnología es el espacio donde los alumnos trabajan con materiales y herramientas para fabricar sus proyectos. Las herramientas básicas se dividen según su función: para medir (regla metálica, metro, calibre), para marcar (lápiz, punzón, compás), para cortar (serrucho, sierra de marquetería, tijeras de chapa), para conformar (lima, escofina, formón), y para unir (martillo, destornilladores, pistola de cola térmica).

Cada herramienta tiene un uso específico y unas normas de seguridad. El serrucho es para cortar tablas grandes, mientras que la sierra de marquetería es para cortes curvos en madera fina. El martillo sirve para clavar y golpear, pero debe usarse con las dos manos y con el clavo bien sujeto. Las tijeras de chapa cortan metal fino, no papel ni madera. Confundir los usos lleva a herramientas estropeadas y accidentes.

Las normas generales de seguridad incluyen: usar gafas de protección cuando hay riesgo de astillas, no correr por el taller, mantener la zona de trabajo ordenada, avisar al profesor si una herramienta se rompe o se daña, y nunca dejar herramientas afiladas al borde de la mesa. El respeto a estas normas no es burocracia: los talleres escolares han visto accidentes por descuidos evitables. Un buen tecnólogo es también alguien cuidadoso.', '[{"pregunta":"¿Qué herramienta mide con precisión?","opciones":["Serrucho","Calibre","Martillo","Destornillador"],"correcta":1},{"pregunta":"¿Qué se usa para cortes curvos en madera fina?","opciones":["Serrucho","Sierra de marquetería","Tijeras","Formón"],"correcta":1},{"pregunta":"¿Qué norma de seguridad es básica?","opciones":["Correr","Gafas de protección con riesgo de astillas","No ordenar","Solo para profes"],"correcta":1},{"pregunta":"¿Para qué sirven las tijeras de chapa?","opciones":["Cortar papel","Cortar metal fino","Cortar madera","Cortar plástico"],"correcta":1}]'::jsonb),

('tecnologia', 'eso', '{1}', 'El Proceso Tecnológico', 'El proceso tecnológico es la serie ordenada de pasos que seguimos para resolver un problema fabricando un objeto o sistema que cubra una necesidad. Es una metodología estructurada, parecida al método científico, que enseña a los alumnos a pensar de manera sistemática antes de actuar. Cada paso tiene su importancia y saltárselos suele llevar a proyectos mal planteados.

Las fases típicas son: identificación del problema o necesidad (¿qué queremos conseguir?), investigación (¿qué soluciones existen ya?), diseño (bocetos y croquis del objeto), planificación (qué materiales y herramientas necesitamos y qué pasos seguiremos), construcción (fabricación siguiendo el plan), evaluación (¿funciona? ¿se puede mejorar?) y documentación (cuaderno de trabajo con todo el proceso).

Cada proyecto de tecnología en ESO se plantea como una aplicación práctica de este proceso. Por ejemplo, si el reto es construir un vehículo que se mueva solo, empezamos investigando distintos mecanismos posibles, dibujamos varios diseños, escogemos materiales, calculamos dimensiones, construimos, probamos y mejoramos. Al final, documentamos todo en una memoria. Esta forma de trabajar desarrolla competencias muy valoradas en el mundo profesional: creatividad, planificación, trabajo en equipo y autocrítica.', '[{"pregunta":"¿Cuál es la primera fase?","opciones":["Construir","Identificar el problema o necesidad","Evaluar","Dibujar"],"correcta":1},{"pregunta":"¿En qué fase hacemos bocetos?","opciones":["Construcción","Diseño","Evaluación","Planificación"],"correcta":1},{"pregunta":"¿Qué se hace al final?","opciones":["Se olvida","Se documenta todo","Se empieza de nuevo","Se borra"],"correcta":1},{"pregunta":"¿Qué desarrolla este método?","opciones":["Solo manualidades","Creatividad y planificación","Solo dibujo","Memoria"],"correcta":1}]'::jsonb),

('tecnologia', 'eso', '{1}', 'El Boceto y el Croquis', 'Cuando tenemos una idea para un proyecto tecnológico, antes de construirlo conviene plasmarla en papel. Los dos tipos de dibujo iniciales más utilizados son el boceto y el croquis. El boceto es el primer dibujo rápido de una idea, hecho a mano alzada, sin medidas ni reglas. Su objetivo es capturar rápidamente lo esencial de la forma, no los detalles técnicos. Un proyecto puede tener varios bocetos con distintas versiones antes de elegir una.

El croquis, en cambio, es un dibujo más completo: también se hace a mano alzada, pero incluye las principales medidas y detalles constructivos. Ya no es solo una idea: es una representación con información suficiente para construir el objeto. El croquis respeta las proporciones aproximadas, aunque no necesita una escala exacta. Sirve de comunicación con las personas que fabricarán el producto.

Después del croquis, en la fase industrial, se suelen hacer los planos técnicos definitivos. Estos se dibujan con reglas o, más habitualmente, con ordenador usando programas CAD. Incluyen vistas normalizadas, acotaciones precisas, símbolos y textos explicativos. Los planos son documentos oficiales que guían toda la fabricación. En un proyecto escolar de tecnología basta normalmente con un buen croquis, pero los alumnos deben entender esta progresión desde la idea hasta el plano final.', '[{"pregunta":"¿Qué es un boceto?","opciones":["Plano preciso","Dibujo rápido inicial a mano alzada","Foto","Modelo 3D"],"correcta":1},{"pregunta":"¿Qué añade el croquis al boceto?","opciones":["Nada","Medidas y detalles constructivos","Color","Firma"],"correcta":1},{"pregunta":"¿Con qué se hacen los planos industriales?","opciones":["Con lápiz","Programas CAD","Con pincel","Con cámara"],"correcta":1},{"pregunta":"¿El croquis necesita escala exacta?","opciones":["Sí","No, solo proporciones aproximadas","Siempre","A veces"],"correcta":1}]'::jsonb),

('tecnologia', 'eso', '{1}', 'Tipos de Uniones', 'Cuando fabricamos un objeto, casi siempre necesitamos unir piezas entre sí. Las uniones se clasifican en dos grandes tipos: fijas (permanentes, difíciles de deshacer sin dañar las piezas) y desmontables (se pueden soltar sin destruir nada). Elegir el tipo correcto es importante para el funcionamiento y el mantenimiento del objeto.

Ejemplos de uniones fijas son el pegado con cola o adhesivo, el clavado, la soldadura (funde los metales para unirlos), el roblonado (con roblones, parecidos a remaches) y las uniones con resinas. Son sencillas y fuertes, pero si queremos desmontar el objeto después para repararlo o reciclarlo, hay que romper la unión. Por eso en la fabricación moderna se intentan evitar cuando es posible.

Las uniones desmontables incluyen los tornillos (muy usados en muebles, maquinaria, electrónica), los clavos tornillo, los encastres mecánicos (como las piezas Lego), los imanes y los velcros. Su gran ventaja es que permiten montar, desmontar y volver a montar repetidamente, facilitando el mantenimiento y la reparación. Los muebles de IKEA son un buen ejemplo: se pueden desmontar, transportar y volver a montar gracias a su sistema de tornillos y ensambles específicos.', '[{"pregunta":"¿Qué son las uniones fijas?","opciones":["Se pueden deshacer","Permanentes, difíciles de deshacer","Baratas","Eléctricas"],"correcta":1},{"pregunta":"¿Cuál NO es una unión fija?","opciones":["Pegado","Soldadura","Tornillo","Clavado"],"correcta":2},{"pregunta":"¿Cuál es la ventaja de las desmontables?","opciones":["Ninguna","Permiten reparar y reciclar","Son más fuertes","Son más bonitas"],"correcta":1},{"pregunta":"¿Qué ejemplo usa uniones desmontables?","opciones":["Un puente soldado","Un mueble de IKEA","Un edificio","Una escultura"],"correcta":1}]'::jsonb),

('tecnologia', 'eso', '{1}', 'Las Estructuras y sus Tipos', 'Una estructura es cualquier conjunto de elementos capaz de soportar cargas sin romperse ni deformarse excesivamente. Las estructuras están en todas partes: edificios, puentes, torres, muebles, vehículos, el esqueleto humano... Comprender cómo funcionan es fundamental para cualquier ingeniero o arquitecto, y los primeros conceptos se aprenden ya en Educación Secundaria.

Existen distintos tipos de estructuras. Las estructuras masivas están formadas por grandes bloques de material, como las pirámides egipcias o las catedrales románicas. Las estructuras entramadas usan barras unidas entre sí formando triángulos, como las grúas, las torres eléctricas o los puentes metálicos. Son más ligeras y económicas, aunque requieren cálculos precisos. Las estructuras trianguladas son un caso concreto especialmente resistente porque el triángulo es la figura más estable.

Toda estructura debe soportar diversos esfuerzos. La tracción estira los elementos; la compresión los comprime; la flexión los dobla; la torsión los gira; la cortadura los corta. Cada material responde mejor ante unos esfuerzos que otros: el hormigón soporta muy bien la compresión pero mal la tracción, por eso se refuerza con varillas de acero, dando lugar al hormigón armado. Entender estos conceptos ayuda a diseñar estructuras eficientes, seguras y duraderas.', '[{"pregunta":"¿Qué forma es más estable?","opciones":["Cuadrado","Triángulo","Círculo","Pentágono"],"correcta":1},{"pregunta":"¿Qué tipo de estructura son las pirámides?","opciones":["Masivas","Entramadas","Tridimensionales","Aéreas"],"correcta":0},{"pregunta":"¿Qué esfuerzo estira?","opciones":["Compresión","Tracción","Torsión","Flexión"],"correcta":1},{"pregunta":"¿Por qué se refuerza el hormigón con acero?","opciones":["Estética","Para soportar tracción","Para flotar","Para pesar menos"],"correcta":1}]'::jsonb);

