-- TECNOLOGÍA - 2º ESO (mecanismos)
-- ============================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('tecnologia', 'eso', '{2}', 'La Palanca: Máquina Simple', 'La palanca es una de las máquinas simples más antiguas y útiles. Consiste en una barra rígida que puede girar alrededor de un punto fijo llamado fulcro o punto de apoyo. Aplicando una fuerza en un extremo (llamada potencia), podemos levantar o mover una carga situada en el otro extremo (llamada resistencia). Con una palanca podemos multiplicar nuestra fuerza si la colocamos correctamente.

La relación matemática que describe la palanca es la ley de la palanca: la fuerza por su distancia al punto de apoyo es igual en ambos lados. Es decir, Potencia × Brazo de potencia = Resistencia × Brazo de resistencia. Si el brazo de potencia es mayor, con una fuerza pequeña podemos levantar una carga grande. Este fue el principio que permitió a Arquímedes afirmar: "Dame un punto de apoyo y moveré el mundo".

Hay tres tipos de palancas según dónde esté el fulcro. Primer género: el fulcro está entre la potencia y la resistencia (tijeras, balancín). Segundo género: la resistencia está entre el fulcro y la potencia (carretilla, cascanueces). Tercer género: la potencia está entre el fulcro y la resistencia (pinzas, brazo humano). Cada tipo tiene ventajas diferentes. Las palancas están en muchos objetos cotidianos sin que nos demos cuenta.', '[{"pregunta":"¿Cómo se llama el punto fijo de la palanca?","opciones":["Fulcro","Bisagra","Polea","Eje"],"correcta":0},{"pregunta":"¿Cuál es la ley de la palanca?","opciones":["P + r = R","P × bp = R × br","P - R = 0","P ÷ R"],"correcta":1},{"pregunta":"¿Qué tipo es la carretilla?","opciones":["Primer género","Segundo género","Tercer género","Cuarto"],"correcta":1},{"pregunta":"¿Quién dijo lo de mover el mundo?","opciones":["Newton","Arquímedes","Einstein","Galileo"],"correcta":1}]'::jsonb),

('tecnologia', 'eso', '{2}', 'Poleas y Polipastos', 'Una polea es una rueda con una garganta (canal) por la que pasa una cuerda, cable o correa. Al aplicar fuerza en un extremo de la cuerda, podemos levantar una carga situada en el otro. Las poleas son, junto con las palancas y los planos inclinados, una de las máquinas simples fundamentales, conocidas desde la antigüedad.

La polea fija cambia la dirección de la fuerza pero no reduce su magnitud: si queremos levantar 10 kg, aplicamos una fuerza equivalente a 10 kg en el otro extremo. Es útil para cambiar la dirección (por ejemplo, tirar hacia abajo para subir un cubo desde un pozo), pero no multiplica la fuerza. La polea móvil, en cambio, se mueve junto con la carga y sí reduce el esfuerzo: con una polea móvil bien montada, levantar 10 kg solo requiere aplicar 5 kg de fuerza, porque el peso se reparte entre dos ramales de cuerda.

Un polipasto combina varias poleas fijas y móviles, multiplicando la ventaja mecánica. Con un polipasto de cuatro poleas podemos levantar 100 kg aplicando solo 25 kg de fuerza. La contrapartida es que tenemos que tirar de mucha más cuerda para conseguir el mismo desplazamiento de la carga. Los polipastos se usan en grúas, ascensores, garajes y en la construcción. Es un ejemplo claro de cómo las máquinas simples nos permiten hacer cosas imposibles para una sola persona.', '[{"pregunta":"¿Qué hace una polea fija?","opciones":["Reduce la fuerza","Cambia la dirección pero no la fuerza","No sirve","Multiplica el peso"],"correcta":1},{"pregunta":"¿Y una polea móvil?","opciones":["Igual que la fija","Reduce la fuerza a la mitad","Aumenta la fuerza","Es fija"],"correcta":1},{"pregunta":"¿Qué es un polipasto?","opciones":["Una polea sola","Combinación de fijas y móviles","Un motor","Un gato"],"correcta":1},{"pregunta":"¿Qué contrapartida tienen?","opciones":["Nada","Hay que tirar de más cuerda","Son muy caros","Rompen"],"correcta":1}]'::jsonb),

('tecnologia', 'eso', '{2}', 'Engranajes: Transmitir Rotación', 'Los engranajes son ruedas dentadas que transmiten movimiento rotatorio de un eje a otro. Al girar un engranaje, sus dientes se entrelazan con los del siguiente, haciéndolo girar también. Son mecanismos muy robustos y precisos, por eso se usan en todo tipo de máquinas: relojes, motores, bicicletas, electrodomésticos, coches. Su invención transformó la ingeniería mecánica.

La relación entre dos engranajes depende del número de dientes de cada uno. Si un engranaje pequeño (10 dientes) mueve uno grande (30 dientes), el grande gira tres veces más lento, pero con tres veces más fuerza (par). Esto se llama relación de transmisión: la multiplicación o reducción de la velocidad que un engranaje produce respecto al otro. Con engranajes podemos aumentar la velocidad sacrificando fuerza, o ganar fuerza sacrificando velocidad, según el uso que queramos.

Existen distintos tipos de engranajes. Los rectos son los más simples, con dientes paralelos al eje; son económicos pero ruidosos. Los helicoidales tienen dientes en diagonal, son más silenciosos y transmiten mejor fuerza. Los cónicos cambian la dirección del movimiento en 90 grados, como en los diferenciales de los coches. La cremallera es un engranaje recto que se combina con una barra dentada para convertir movimiento rotatorio en lineal, como en los gatos de coche o en las direcciones de los automóviles.', '[{"pregunta":"¿De qué depende la relación de transmisión?","opciones":["Del color","Del número de dientes","Del material","Del peso"],"correcta":1},{"pregunta":"Si pequeño mueve a grande, el grande...","opciones":["Gira más rápido","Gira más lento pero con más fuerza","Se para","Gira al revés"],"correcta":1},{"pregunta":"¿Qué engranaje es más silencioso?","opciones":["Recto","Helicoidal","Cónico","Cremallera"],"correcta":1},{"pregunta":"¿Qué convierte rotación en lineal?","opciones":["Cónicos","Cremallera","Helicoidales","Rectos"],"correcta":1}]'::jsonb),

('tecnologia', 'eso', '{2}', 'La Biela-Manivela', 'El sistema biela-manivela es un mecanismo fundamental que convierte el movimiento giratorio (rotación) en movimiento lineal alternativo (va y vuelve), o viceversa. Consta de dos elementos principales: la manivela, que gira alrededor de un eje, y la biela, una barra rígida que une la manivela con la pieza que describe el movimiento alternativo (llamada émbolo o pistón).

Este mecanismo es el corazón de los motores de combustión interna. En un coche, cuando la explosión del combustible empuja el pistón hacia abajo, la biela transmite el empuje a la manivela, que está unida al cigüeñal. El cigüeñal gira, y a través de otros mecanismos hace girar las ruedas. El funcionamiento inverso también es común: en una bicicleta estática, nosotros giramos los pedales (movimiento rotatorio) y eso mueve una barra que sube y baja.

Otros ejemplos del sistema biela-manivela incluyen las máquinas de coser (el pedal gira y la aguja sube y baja), las sierras de vaivén, los motores de vapor y los limpiaparabrisas. Es un mecanismo tan útil que prácticamente cualquier máquina que necesite convertir un tipo de movimiento en otro lo incorpora. Su dominio permite entender cómo funcionan muchísimas máquinas cotidianas.', '[{"pregunta":"¿Qué convierte la biela-manivela?","opciones":["Nada","Rotatorio en lineal alternativo","Luz en calor","Sonido en señal"],"correcta":1},{"pregunta":"¿Cómo se llama la barra que une?","opciones":["Manivela","Biela","Cigüeñal","Pistón"],"correcta":1},{"pregunta":"¿Qué máquina lo usa en su corazón?","opciones":["Licuadora","Motor de combustión","Ascensor","Frigorífico"],"correcta":1},{"pregunta":"¿Qué más lo usa?","opciones":["Reloj","Máquina de coser","Imán","Batería"],"correcta":1}]'::jsonb),

('tecnologia', 'eso', '{2}', 'La Ley de Ohm', 'La Ley de Ohm es una de las leyes fundamentales de la electricidad, descubierta por el físico alemán Georg Simon Ohm en 1827. Establece la relación entre tres magnitudes básicas de un circuito eléctrico: la tensión (V, medida en voltios), la intensidad (I, medida en amperios) y la resistencia (R, medida en ohmios). La fórmula es tan simple como imprescindible: V = I × R.

La tensión se puede imaginar como la "presión" con la que se mueve la electricidad. La intensidad es la cantidad de corriente que fluye por el circuito. La resistencia es la dificultad que encuentran los electrones para avanzar. Cuanta más tensión, más corriente; cuanta más resistencia, menos corriente. La fórmula V = I × R nos permite calcular cualquiera de las tres magnitudes si conocemos las otras dos.

Por ejemplo, si aplicamos 12 voltios a una resistencia de 4 ohmios, la corriente será 12/4 = 3 amperios. Si por una bombilla circula 0,5 A a 230 V, su resistencia es 230/0,5 = 460 ohmios. Esta ley es el primer paso para entender cualquier circuito eléctrico, y aparece constantemente en tecnología, electrónica y física. Memorizar V = I × R y saber despejar cualquiera de sus variables es una habilidad básica que todo estudiante de secundaria debe dominar.', '[{"pregunta":"¿Cuál es la fórmula?","opciones":["V = I + R","V = I × R","V = I/R","V = R - I"],"correcta":1},{"pregunta":"¿Quién la formuló?","opciones":["Edison","Ohm","Tesla","Ampère"],"correcta":1},{"pregunta":"¿En qué unidad se mide R?","opciones":["Voltios","Amperios","Ohmios","Vatios"],"correcta":2},{"pregunta":"Con 12 V y 4 Ω, ¿qué intensidad fluye?","opciones":["1 A","2 A","3 A","48 A"],"correcta":2}]'::jsonb),

('tecnologia', 'eso', '{2}', 'Circuitos en Serie y en Paralelo', 'Los componentes eléctricos se pueden conectar entre sí de dos formas básicas: en serie o en paralelo. Cada forma tiene consecuencias distintas sobre la intensidad y la tensión del circuito, y se usa en situaciones diferentes. Comprender la diferencia es fundamental para diseñar o analizar cualquier instalación eléctrica, desde una linterna casera hasta una red doméstica.

En un circuito en serie, los componentes se conectan uno detrás de otro, de forma que la corriente recorre todos ellos por el mismo camino. Si uno se estropea, se corta el paso y el resto dejan de funcionar (como en las luces de Navidad antiguas, donde una bombilla fundida apagaba toda la serie). La resistencia total es la suma de las individuales, y la corriente es la misma en todos los elementos.

En un circuito en paralelo, cada componente tiene su propio camino para la corriente. Si uno se estropea, los demás siguen funcionando, porque la corriente puede seguir por los otros caminos. Todos los componentes reciben la misma tensión, y la corriente total se reparte entre las ramas. Las instalaciones eléctricas de las casas usan siempre el paralelo: cada bombilla o enchufe tiene su propio circuito, de modo que si uno falla el resto no se ve afectado. Por eso el paralelo es más práctico para la mayoría de los usos reales.', '[{"pregunta":"¿Qué pasa en serie si una lámpara se funde?","opciones":["Nada","Las demás se apagan","Solo la anterior","Se enciende más"],"correcta":1},{"pregunta":"¿Qué ocurre con la tensión en paralelo?","opciones":["Se divide","Todos reciben la misma","Se suma","Varía siempre"],"correcta":1},{"pregunta":"¿Cómo son las casas?","opciones":["En serie","En paralelo","En mixto","Sin circuito"],"correcta":1},{"pregunta":"¿Qué suman en serie las resistencias?","opciones":["Nada","Sus valores","Su mitad","Su inverso"],"correcta":1}]'::jsonb),

('tecnologia', 'eso', '{2}', 'Las Energías Renovables', 'Las energías renovables son aquellas que provienen de fuentes inagotables a escala humana: el Sol, el viento, el agua, la biomasa, el calor interno de la Tierra. A diferencia de los combustibles fósiles (petróleo, carbón, gas) que tardaron millones de años en formarse y que contaminan al usarlos, las renovables se regeneran constantemente y producen muchas menos emisiones de gases de efecto invernadero.

La energía solar se obtiene directamente del Sol mediante paneles fotovoltaicos (que convierten la luz en electricidad) o colectores térmicos (que calientan agua). La energía eólica proviene del viento, aprovechado por aerogeneradores. La hidráulica usa la fuerza del agua en movimiento, principalmente en presas. La biomasa quema materia orgánica (residuos agrícolas, madera) de forma renovable. La geotérmica usa el calor del subsuelo.

España es uno de los países europeos con más recursos renovables por su clima: mucho sol, viento abundante en la costa y zonas de montaña, e importantes ríos. En los últimos años, la generación renovable ha crecido enormemente y supone ya más de la mitad de la electricidad producida en determinadas horas del día. Frente al cambio climático y la dependencia de combustibles importados, las renovables son una pieza clave del futuro energético.', '[{"pregunta":"¿Qué caracteriza a las renovables?","opciones":["Son baratas","Provienen de fuentes inagotables","Son caras","Son eléctricas"],"correcta":1},{"pregunta":"¿Qué convierten los paneles fotovoltaicos?","opciones":["Calor en frío","Luz en electricidad","Agua en vapor","Viento en luz"],"correcta":1},{"pregunta":"¿Qué es la biomasa?","opciones":["Agua corriente","Materia orgánica que se quema de forma renovable","El sol","El viento"],"correcta":1},{"pregunta":"¿Cómo está España en recursos renovables?","opciones":["Mal","Es de los más ricos en Europa","Media","Depende del día"],"correcta":1}]'::jsonb),

('tecnologia', 'eso', '{2}', 'Interruptores y Pulsadores', 'Los interruptores y pulsadores son dispositivos de control que permiten al usuario activar o desactivar circuitos eléctricos. Aunque ambos cumplen la misma función básica (abrir o cerrar el paso de la corriente), se diferencian en cómo mantienen su estado tras ser accionados.

Un interruptor, una vez cambiado de posición, mantiene el estado hasta que alguien lo cambia de nuevo. Es el típico de los enchufes de pared y lámparas: si lo pulsamos, queda encendido o apagado. Existen variantes como el interruptor unipolar (una sola línea), bipolar (corta las dos líneas), conmutador (permite controlar una lámpara desde dos puntos), cruce, etc.

Un pulsador, en cambio, solo cambia su estado mientras se mantiene presionado. Al soltarlo, vuelve automáticamente a la posición original gracias a un muelle interno. Los timbres de las puertas son pulsadores típicos: mientras mantienes apretado el botón, suena el timbre; al soltarlo, se calla. En electrónica digital los pulsadores son fundamentales para detectar eventos, como pulsaciones de botones en un juego. Combinando interruptores, pulsadores, relés y temporizadores se pueden construir circuitos de control muy variados.', '[{"pregunta":"¿Qué mantiene su estado al dejar de pulsar?","opciones":["Pulsador","Interruptor","Ambos","Ninguno"],"correcta":1},{"pregunta":"¿Qué vuelve a su estado al soltarlo?","opciones":["Interruptor","Pulsador","Relé","Temporizador"],"correcta":1},{"pregunta":"¿Qué pulsador ejemplar se cita?","opciones":["Enchufe","Timbre de puerta","Interruptor de luz","Fusible"],"correcta":1},{"pregunta":"¿Qué hace un conmutador?","opciones":["Solo apagar","Controlar una lámpara desde dos puntos","Bloquear","Mide"],"correcta":1}]'::jsonb),

('tecnologia', 'eso', '{2}', 'El Uso Seguro de la Electricidad', 'La electricidad, aunque imprescindible, puede ser muy peligrosa si no se maneja correctamente. Un electrocutamiento puede provocar quemaduras graves, fibrilación del corazón e incluso la muerte. Por eso existen normas de seguridad que todos debemos conocer, incluso quienes no son profesionales de la electricidad, para evitar accidentes domésticos y laborales.

Normas básicas en el hogar: no manipular enchufes con las manos mojadas; no sobrecargar las regletas enchufando demasiados aparatos; revisar periódicamente los cables buscando desgastes o peladuras; no usar aparatos eléctricos en el baño cerca de agua; enseñar a los niños a no meter objetos en los enchufes. Cualquier instalación eléctrica debe llevar un interruptor diferencial, que corta la corriente al detectar fugas peligrosas hacia tierra.

Antes de manipular cualquier parte de una instalación, hay que cortar la corriente desde el cuadro eléctrico. Siempre hay que trabajar con herramientas aisladas y, en instalaciones profesionales, comprobar con un medidor que no queda tensión residual. Nunca se debe intentar "apañar" empalmes con cinta aislante de mala calidad ni usar fusibles de valor superior al recomendado. La electricidad no perdona: lo que parece un pequeño riesgo puede costar muy caro.', '[{"pregunta":"¿Qué es un interruptor diferencial?","opciones":["Un pulsador","Corta corriente ante fugas a tierra","Un fusible","Un medidor"],"correcta":1},{"pregunta":"¿Qué NO se debe hacer?","opciones":["Cortar corriente antes","Manipular con manos mojadas","Revisar cables","Usar herramientas aisladas"],"correcta":1},{"pregunta":"¿Antes de trabajar qué hay que hacer?","opciones":["Nada","Cortar la corriente en el cuadro","Llamar","Dar tensión"],"correcta":1},{"pregunta":"¿Por qué no sobrecargar regletas?","opciones":["Para ahorrar","Peligro de incendio y sobrecalentamiento","Por estética","Por ruido"],"correcta":1}]'::jsonb),

('tecnologia', 'eso', '{2}', 'La Hoja de Cálculo', 'Una hoja de cálculo es un programa informático que organiza datos en celdas formando filas y columnas, permitiendo realizar operaciones matemáticas automáticas sobre ellos. Los programas más conocidos son Microsoft Excel, Google Sheets y LibreOffice Calc. Son herramientas fundamentales en tecnología, matemáticas, empresa, contabilidad, investigación científica y prácticamente cualquier ámbito donde haya que manejar datos numéricos.

Cada celda tiene una referencia única formada por una letra (columna) y un número (fila): A1 es la primera celda, B3 la segunda columna tercera fila, etc. En cada celda podemos introducir un texto, un número o una fórmula. Las fórmulas empiezan por el signo =, seguido de operaciones o funciones. Por ejemplo, =A1+B1 suma los contenidos de esas dos celdas, y =SUMA(A1:A10) suma todas las celdas desde A1 hasta A10.

Las hojas de cálculo también permiten crear gráficos a partir de los datos: barras, líneas, sectores, etc. Son muy útiles para visualizar tendencias, comparaciones y distribuciones. Aprender a usar una hoja de cálculo es una competencia básica del siglo XXI: casi cualquier trabajo requiere hoy en día algún manejo de Excel o similar. En tecnología, se usan para calcular resistencias, organizar presupuestos de proyectos, llevar control de notas o analizar datos de experimentos.', '[{"pregunta":"¿Qué forman las celdas?","opciones":["Filas y columnas","Páginas","Menús","Pestañas"],"correcta":0},{"pregunta":"¿Con qué signo empieza una fórmula?","opciones":["$","=","#","+"],"correcta":1},{"pregunta":"¿Qué hace SUMA(A1:A10)?","opciones":["Resta","Suma de A1 a A10","Borra","Cuenta"],"correcta":1},{"pregunta":"¿Qué permite crear con los datos?","opciones":["Vídeos","Gráficos","Fotos","Mapas"],"correcta":1}]'::jsonb);

-- ============================================================
-- TECNOLOGÍA - 3º ESO (electricidad avanzada)
-- ============================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('tecnologia', 'eso', '{3}', 'Potencia Eléctrica', 'La potencia eléctrica es la cantidad de energía que consume o produce un dispositivo por unidad de tiempo. Se mide en vatios (W), en honor al ingeniero escocés James Watt. Un aparato de 1000 vatios consume 1000 julios cada segundo. Cuanta más potencia tiene un aparato, más corriente necesita y más rápidamente transforma la electricidad en calor, luz, movimiento o cualquier otra forma de energía.

La fórmula más usada para calcular la potencia es P = V × I, donde P es la potencia en vatios, V la tensión en voltios e I la intensidad en amperios. Por ejemplo, una lámpara de 230 V que consume 0,3 A tiene una potencia de 230 × 0,3 = 69 W. Cuando vemos etiquetas energéticas, comparamos potencias: un microondas de 800 W gasta más electricidad que uno de 600 W.

La energía consumida por un aparato depende de su potencia y del tiempo que esté funcionando. Se mide en kilovatios-hora (kWh): un aparato de 1000 W funcionando durante una hora consume 1 kWh. Las compañías eléctricas facturan en kWh, y por eso entendiendo estos conceptos podemos calcular cuánto nos cuesta tener un aparato encendido. Por ejemplo, si un ordenador de 200 W se deja encendido 10 horas, consume 2 kWh, que al precio actual de la electricidad cuesta unos 30-40 céntimos.', '[{"pregunta":"¿En qué unidad se mide la potencia?","opciones":["Voltios","Amperios","Vatios","Ohmios"],"correcta":2},{"pregunta":"¿Cuál es la fórmula?","opciones":["P = V/I","P = V × I","P = R × I","P = V - I"],"correcta":1},{"pregunta":"¿En qué facturan las compañías?","opciones":["Voltios","kWh","Amperios","Ohmios"],"correcta":1},{"pregunta":"¿Quién da nombre al vatio?","opciones":["Ohm","Watt","Ampère","Volta"],"correcta":1}]'::jsonb),

('tecnologia', 'eso', '{3}', 'Resistencias y Condensadores', 'En electrónica, resistencias y condensadores son los dos componentes pasivos más comunes. Las resistencias, ya estudiadas, limitan la corriente y se miden en ohmios. Los condensadores, por su parte, almacenan carga eléctrica entre dos placas separadas por un material aislante llamado dieléctrico. Su capacidad de almacenar carga se mide en faradios (F), aunque en la práctica se usan submúltiplos como microfaradios (µF) o nanofaradios (nF).

Un condensador tiene la propiedad de cargarse y descargarse progresivamente, en lugar de instantáneamente. Por eso se usa para crear retardos en circuitos, suavizar variaciones de corriente (en fuentes de alimentación), acumular energía para liberarla en flashes fotográficos o arrancar motores, y filtrar señales eléctricas en circuitos de audio. Los condensadores electrolíticos tienen polaridad (positivo/negativo) y hay que conectarlos correctamente; los cerámicos suelen ser más pequeños y sin polaridad.

Cuando se combinan resistencia y condensador formando un circuito RC, obtenemos un comportamiento temporal interesante: el condensador se carga a través de la resistencia siguiendo una curva exponencial. La constante de tiempo del circuito es τ = R × C, y es fundamental para calcular retardos y filtros. Estos circuitos básicos son la base de muchísimos sistemas electrónicos, desde temporizadores sencillos hasta equipos de audio profesionales.', '[{"pregunta":"¿En qué unidad se mide un condensador?","opciones":["Ohmios","Faradios","Voltios","Hercios"],"correcta":1},{"pregunta":"¿Qué almacena un condensador?","opciones":["Calor","Carga eléctrica","Luz","Agua"],"correcta":1},{"pregunta":"¿Qué es τ (tau)?","opciones":["La tensión","Constante de tiempo R × C","La frecuencia","El radio"],"correcta":1},{"pregunta":"¿Qué tipo tiene polaridad?","opciones":["Cerámico","Electrolítico","Ninguno","Mica"],"correcta":1}]'::jsonb),

('tecnologia', 'eso', '{3}', 'La Corriente Alterna', 'Existen dos tipos básicos de corriente eléctrica: continua y alterna. La continua (DC) fluye siempre en la misma dirección y con la misma intensidad, como la que proporciona una pila. La alterna (AC) cambia su dirección y magnitud de forma periódica, formando una onda sinusoidal. La electricidad que llega a nuestras casas es alterna: en Europa, con una frecuencia de 50 Hz, es decir, cambia 50 veces por segundo.

¿Por qué alterna y no continua? A finales del siglo XIX se produjo la famosa "guerra de las corrientes" entre Thomas Edison, defensor de la continua, y Nikola Tesla junto con George Westinghouse, defensores de la alterna. Tesla demostró que la alterna permite transportar la electricidad a mucha más distancia con menos pérdidas, porque se puede elevar y reducir la tensión fácilmente mediante transformadores. Esto la hizo imbatible para las redes eléctricas nacionales.

Para usar en electrónica, donde casi todos los componentes trabajan con continua, se necesita convertir la alterna de la red en continua. El proceso se llama rectificación y usa diodos para dejar pasar solo una polaridad de la corriente. Tras la rectificación, un condensador de gran capacidad suaviza los picos restantes, y un regulador ajusta la tensión al valor exacto. Cualquier cargador de móvil o adaptador de portátil hace esta conversión internamente.', '[{"pregunta":"¿A qué frecuencia es la corriente europea?","opciones":["10 Hz","50 Hz","100 Hz","500 Hz"],"correcta":1},{"pregunta":"¿Quién defendía la continua?","opciones":["Tesla","Edison","Westinghouse","Ampère"],"correcta":1},{"pregunta":"¿Qué permite transportar lejos sin pérdidas?","opciones":["La continua","La alterna gracias a los transformadores","Ambas igual","Ninguna"],"correcta":1},{"pregunta":"¿Qué componente rectifica?","opciones":["Resistencia","Diodo","Condensador","LED"],"correcta":1}]'::jsonb),

('tecnologia', 'eso', '{3}', 'El Motor Eléctrico', 'Un motor eléctrico es una máquina que convierte energía eléctrica en energía mecánica, es decir, en movimiento. Su principio básico fue descubierto por Michael Faraday en 1821: cuando una corriente eléctrica atraviesa un conductor situado en un campo magnético, aparece una fuerza que lo empuja. Aprovechando esto, los motores hacen girar un eje que luego puede mover una rueda, una hélice o cualquier otro mecanismo.

Un motor de corriente continua básico consta de un imán permanente fijo (estator) y una bobina de hilo conductor que gira dentro de él (rotor). La corriente circula por la bobina generando un campo magnético propio, que interactúa con el del imán y crea la fuerza de giro. Unas escobillas (contactos deslizantes) conectan la corriente al rotor en rotación. El resultado es un giro continuo que se puede usar para cualquier aplicación.

Los motores eléctricos están en todas partes: ventiladores, batidoras, lavadoras, ascensores, coches eléctricos, juguetes, taladros, drones. Su eficiencia es muy alta, convirtiendo casi toda la electricidad en movimiento útil, mucho más que los motores de combustión (que pierden gran parte como calor). Por eso los coches eléctricos son más eficientes que los de gasolina, aunque el problema actual sea el almacenamiento de energía en baterías, que todavía tiene limitaciones de capacidad y coste.', '[{"pregunta":"¿Qué convierten los motores eléctricos?","opciones":["Luz en sonido","Electricidad en movimiento","Agua en energía","Calor en luz"],"correcta":1},{"pregunta":"¿Quién descubrió el principio?","opciones":["Tesla","Edison","Faraday","Newton"],"correcta":2},{"pregunta":"¿Cómo se llama la parte fija?","opciones":["Rotor","Estator","Eje","Bobina"],"correcta":1},{"pregunta":"¿Por qué son eficientes?","opciones":["Son baratos","Convierten casi toda la electricidad en movimiento","Son pequeños","No giran"],"correcta":1}]'::jsonb),

('tecnologia', 'eso', '{3}', 'Las Redes Locales', 'Una red local o LAN (Local Area Network) es un conjunto de ordenadores y otros dispositivos conectados entre sí en un área geográfica limitada, como una casa, una oficina o un colegio. Permite compartir recursos (archivos, impresoras, internet) y comunicarse. La tecnología más común para conectar dispositivos en una red local es Ethernet, que usa cables, y Wifi, que usa ondas de radio.

En el centro de una red local suele haber un router, un dispositivo que actúa como puerta de enlace con internet y distribuye la conexión a todos los dispositivos. El router asigna una dirección IP única a cada aparato para que la red sepa quién es quién. Las direcciones IP locales son como las matrículas dentro de la red: 192.168.1.1, 192.168.1.2, etc. Cuando un dispositivo pide una página web, el router reenvía la petición a internet y devuelve la respuesta al dispositivo correcto.

Los protocolos más importantes de una red son TCP/IP, que definen cómo se estructura la información en paquetes y cómo viajan. También hay protocolos de seguridad como WPA2 o WPA3, que cifran el tráfico en redes wifi para que nadie cercano pueda espiarlo. Configurar una red doméstica con seguridad incluye cambiar la contraseña por defecto del router, usar WPA3 si el equipo lo soporta, y mantener el firmware actualizado para corregir vulnerabilidades.', '[{"pregunta":"¿Qué significa LAN?","opciones":["Local Area Network","Large Access Node","Line And Node","Long Area Network"],"correcta":0},{"pregunta":"¿Qué dispositivo centraliza una red local?","opciones":["El ordenador","El router","El cable","La impresora"],"correcta":1},{"pregunta":"¿Qué protocolos estructuran los paquetes?","opciones":["HTML","TCP/IP","SMTP","FTP"],"correcta":1},{"pregunta":"¿Qué protocolo protege el wifi?","opciones":["HTTP","WPA2/WPA3","TCP","POP3"],"correcta":1}]'::jsonb),

('tecnologia', 'eso', '{3}', 'Sistemas Operativos', 'Un sistema operativo es el programa fundamental de un ordenador: gestiona el hardware, organiza los archivos, ejecuta las aplicaciones y proporciona al usuario la interfaz con la que interactúa. Sin sistema operativo, un ordenador sería inútil para cualquier persona que no fuera un experto en electrónica. Los sistemas operativos más populares hoy son Windows (Microsoft), macOS (Apple), Linux (software libre), Android y iOS (móviles).

Windows es el más extendido en ordenadores personales. Su interfaz gráfica basada en ventanas facilita el uso a millones de usuarios, aunque algunos expertos lo critican por ser cerrado y de pago. macOS, exclusivo de los ordenadores Apple, tiene fama de estabilidad y buen diseño, pero requiere un hardware concreto y más caro. Linux, en cambio, es software libre y gratuito, muy usado en servidores y cada vez más en ordenadores personales por su flexibilidad y respeto por la privacidad.

En móviles, Android es el sistema más usado del mundo (más del 70% del mercado), seguido por iOS. Android se basa en Linux y está controlado por Google, aunque los fabricantes lo personalizan. iOS, exclusivo de iPhones y iPads, destaca por su integración con el resto de productos Apple y por su política estricta con las aplicaciones. Conocer los distintos sistemas operativos ayuda a elegir el que mejor se adapta a cada necesidad y situación.', '[{"pregunta":"¿Qué hace un sistema operativo?","opciones":["Navegar en internet","Gestionar hardware y ejecutar apps","Jugar","Escribir textos"],"correcta":1},{"pregunta":"¿Cuál es gratuito y libre?","opciones":["Windows","macOS","Linux","iOS"],"correcta":2},{"pregunta":"¿Qué sistema domina en móviles?","opciones":["Windows","Android","Linux","iOS"],"correcta":1},{"pregunta":"¿De qué empresa es iOS?","opciones":["Google","Microsoft","Apple","Samsung"],"correcta":2}]'::jsonb),

('tecnologia', 'eso', '{3}', 'Los Plásticos Técnicos', 'Los plásticos técnicos o de ingeniería son una clase avanzada de plásticos con propiedades mecánicas, térmicas y químicas muy superiores a las de los plásticos comunes. Pueden soportar cargas pesadas, temperaturas altas, agentes químicos agresivos y desgastes intensos. Por eso se usan en aplicaciones exigentes donde los plásticos comunes fallarían, como en piezas de motores, engranajes industriales, componentes electrónicos o dispositivos médicos.

Entre los plásticos técnicos más conocidos están el nailon (poliamida), que combina resistencia mecánica y flexibilidad, usado en engranajes, cuerdas, tejidos y piezas de coches; el policarbonato (PC), muy transparente y resistente a los golpes, con el que se fabrican cristales antibalas, cascos y CDs; y el polietileno de alta densidad (HDPE), más resistente que el polietileno común, usado en tuberías, botellas y juguetes.

En aplicaciones aún más exigentes se usan plásticos de altas prestaciones como el PEEK (polieteretercetona), que resiste temperaturas de más de 250°C y ambientes químicos extremos, o el Teflón (PTFE), conocido por su antiadherencia y usado en sartenes y juntas industriales. Los plásticos técnicos han sustituido a metales en muchos usos porque ofrecen un mejor balance entre peso, resistencia y coste, especialmente en sectores como automoción, aeronáutica y medicina.', '[{"pregunta":"¿Cuál es un uso del nailon?","opciones":["Vidrios","Engranajes y cuerdas","Antenas","Combustible"],"correcta":1},{"pregunta":"¿Qué plástico es transparente y resistente?","opciones":["Nailon","Policarbonato","Teflón","PVC"],"correcta":1},{"pregunta":"¿Qué plástico resiste altas temperaturas?","opciones":["PEEK","PE","PS","Nailon"],"correcta":0},{"pregunta":"¿Para qué se usa el Teflón?","opciones":["Para cascos","Para sartenes antiadherentes","Para cables","Para agua"],"correcta":1}]'::jsonb),

('tecnologia', 'eso', '{3}', 'Engranajes y Ruedas Dentadas', 'Los trenes de engranajes son combinaciones de varias ruedas dentadas que trabajan conjuntamente para lograr efectos mecánicos complejos. En el más simple, dos engranajes en contacto giran en sentidos opuestos; si son de distinto tamaño, cambian la velocidad y el par. En los trenes de más engranajes, las combinaciones permiten reducir mucho la velocidad o multiplicar la fuerza con gran eficiencia.

La relación de transmisión entre dos engranajes se calcula como el cociente entre el número de dientes del conducido y el conductor. Si el conductor tiene 20 dientes y el conducido 60, la relación es 3, lo que significa que el conducido gira tres veces más lento pero con tres veces más fuerza. Esta relación se puede multiplicar en varias etapas para obtener reducciones muy grandes, como en los relojes mecánicos o las reductoras de los motores industriales.

Un caso especial son los engranajes planetarios, donde un engranaje central (solar) está rodeado por engranajes satélites que a su vez engranan con un engranaje exterior (corona). Estos sistemas, aunque complejos, permiten transmisiones muy compactas y potentes, y se usan en cajas de cambios automáticas de coches, en reductoras para robótica y en muchas aplicaciones industriales. Diseñar un tren de engranajes requiere conocimientos de matemáticas y de mecánica, y es una de las especialidades más tradicionales de la ingeniería.', '[{"pregunta":"¿Qué son los trenes de engranajes?","opciones":["Un solo engranaje","Combinaciones de varias ruedas dentadas","Motores","Ruedas sin dientes"],"correcta":1},{"pregunta":"¿Cómo se calcula la relación?","opciones":["Sumar dientes","Dientes conducido / conductor","Restar","Multiplicar tamaños"],"correcta":1},{"pregunta":"¿Qué son los engranajes planetarios?","opciones":["De aviones","Con solar, satélites y corona","Sin dientes","De papel"],"correcta":1},{"pregunta":"¿Dónde se usan mucho?","opciones":["Cajas de cambios automáticas","Luces","Antenas","Pinturas"],"correcta":0}]'::jsonb),

('tecnologia', 'eso', '{3}', 'Fabricación por Sustracción', 'La fabricación por sustracción es aquella en la que partimos de un bloque de material y quitamos las partes sobrantes hasta obtener la pieza deseada. Es el opuesto de la fabricación aditiva (impresión 3D). Las técnicas de sustracción han sido el método principal de fabricación mecánica durante siglos: tornear, fresar, taladrar, cortar, lijar, todas son operaciones sustractivas.

El torno es una máquina que hace girar rápidamente una pieza mientras una herramienta estacionaria la va desbastando, ideal para piezas cilíndricas. La fresadora funciona al revés: la herramienta gira y se mueve sobre una pieza fija, permitiendo crear formas complejas con gran precisión. El taladro perfora agujeros. La tronzadora corta metales gruesos con un disco abrasivo. Estas máquinas, operadas manualmente, requieren experiencia y habilidad.

En las fábricas modernas, la mayoría de estas máquinas son CNC (Control Numérico por Computadora): un ordenador controla todos los movimientos con precisión milimétrica siguiendo un programa escrito previamente. Así se pueden producir piezas idénticas en grandes cantidades sin intervención humana, garantizando calidad y consistencia. Las máquinas CNC son el corazón de muchos talleres e industrias actuales. Aprender a programarlas es una carrera profesional con mucha demanda.', '[{"pregunta":"¿Qué hace una técnica sustractiva?","opciones":["Añade material","Quita material de un bloque","Nada","Lo mismo que la aditiva"],"correcta":1},{"pregunta":"¿Para qué sirve el torno?","opciones":["Perforar","Piezas cilíndricas","Soldar","Pintar"],"correcta":1},{"pregunta":"¿Qué significa CNC?","opciones":["Control Numérico por Computadora","Cutting New Concept","Control Natural Cero","Corte Nuclear Continuo"],"correcta":0},{"pregunta":"¿Qué ventaja tienen las máquinas CNC?","opciones":["Son manuales","Producen piezas idénticas con precisión","Son lentas","Son baratas siempre"],"correcta":1}]'::jsonb),

('tecnologia', 'eso', '{3}', 'El Reciclaje', 'El reciclaje es el proceso mediante el cual los materiales de los productos usados se recuperan y transforman en nueva materia prima para fabricar otros productos. Reciclar permite ahorrar recursos naturales, reducir los residuos en vertederos y disminuir las emisiones contaminantes asociadas a la extracción y fabricación de materiales nuevos. Es una pieza clave de la llamada economía circular.

En España se separan los residuos domésticos en diferentes contenedores: azul (papel y cartón), amarillo (envases plásticos, briks, latas), verde (vidrio), marrón (materia orgánica) y gris (resto). Cada tipo de residuo sigue un proceso distinto. El papel se descompone, se tritura y se reforma; el vidrio se funde a altas temperaturas y se moldea; los metales se funden para fabricar nuevas piezas; los plásticos, según su tipo, pueden convertirse en botellas, tejidos o piezas industriales.

Reciclar correctamente requiere colaboración ciudadana. Un solo envase mal tirado en el cubo equivocado puede contaminar todo el lote. Además del reciclaje, otras erres ayudan: reducir el consumo (no comprar lo innecesario), reutilizar (usar las cosas varias veces antes de tirarlas), reparar (prolongar la vida útil) y rechazar (decir no a los productos innecesarios). La educación ambiental en los centros escolares incluye estos hábitos porque son esenciales para un futuro sostenible.', '[{"pregunta":"¿Qué contenedor es para vidrio?","opciones":["Azul","Amarillo","Verde","Marrón"],"correcta":2},{"pregunta":"¿Qué va en el amarillo?","opciones":["Papel","Envases y plásticos","Vidrio","Restos orgánicos"],"correcta":1},{"pregunta":"¿Qué ventaja tiene reciclar?","opciones":["Nada","Ahorra recursos y reduce emisiones","Más trabajo","Es caro"],"correcta":1},{"pregunta":"¿Qué es la economía circular?","opciones":["Un banco","Recuperar materiales continuamente","Una tienda","Un método de dibujo"],"correcta":1}]'::jsonb);

