-- TECNOLOGÍA - 4º ESO (electrónica)
-- ============================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('tecnologia', 'eso', '{4}', 'El Transistor: Revolución Silenciosa', 'El transistor es uno de los componentes electrónicos más importantes de la historia. Fue inventado en 1947 por John Bardeen, Walter Brattain y William Shockley en los laboratorios Bell, un descubrimiento que les valió el Nobel de Física en 1956. Sustituyó a las voluminosas válvulas de vacío que se usaban antes, permitiendo construir aparatos electrónicos mucho más pequeños, ligeros y eficientes.

Un transistor tiene tres terminales y puede funcionar como interruptor o amplificador. Como interruptor, una pequeña corriente aplicada a su base controla el paso de una corriente mucho mayor entre colector y emisor. Como amplificador, una señal débil entrante se convierte en una réplica más potente. Esta doble función es la base de toda la electrónica moderna: los ordenadores usan transistores como interruptores digitales, y los equipos de audio los usan para amplificar sonido.

Los transistores modernos son diminutos y se integran en chips. Un chip de procesador actual puede contener miles de millones de transistores trabajando coordinadamente. La ley de Moore, formulada en 1965, predijo que el número de transistores en un chip se duplicaría cada dos años, y durante décadas la industria cumplió esta previsión. Hoy los transistores más avanzados miden unos pocos nanómetros, cerca del límite físico de la miniaturización.', '[{"pregunta":"¿Cuándo se inventó el transistor?","opciones":["1900","1947","1970","2000"],"correcta":1},{"pregunta":"¿Qué premio recibieron sus inventores?","opciones":["Oscar","Nobel de Física","Pulitzer","Turing"],"correcta":1},{"pregunta":"¿A qué sustituyeron?","opciones":["Resistencias","Válvulas de vacío","Pilas","LEDs"],"correcta":1},{"pregunta":"¿Qué dice la Ley de Moore?","opciones":["Los transistores se duplican cada dos años","Los precios suben","Todo se encoge","Nada"],"correcta":0}]'::jsonb),

('tecnologia', 'eso', '{4}', 'Puertas Lógicas', 'Las puertas lógicas son los elementos básicos de los circuitos digitales. Realizan operaciones simples de lógica booleana con entradas que solo pueden valer 0 o 1 (falso o verdadero). Combinando puertas lógicas se construyen circuitos más complejos capaces de hacer cualquier cálculo imaginable, desde sumar números hasta ejecutar todo un sistema operativo.

Las puertas fundamentales son siete. La puerta AND devuelve 1 solo si todas sus entradas son 1. La OR devuelve 1 si al menos una entrada es 1. La NOT invierte su única entrada (0 se convierte en 1 y viceversa). La NAND es la negación de AND; la NOR, la negación de OR; la XOR (o exclusiva) devuelve 1 si las entradas son distintas. Combinando estas operaciones se construyen circuitos aritméticos, memorias, contadores y temporizadores.

Internamente, cada puerta lógica se fabrica con unos cuantos transistores. Miles de millones de puertas forman los chips modernos. Aunque los programadores trabajamos con código de alto nivel, en el fondo todo nuestro software acaba siendo ejecutado por circuitos que manipulan bits mediante puertas lógicas. Entender este nivel es fascinante: las cosas más complejas del mundo digital se construyen apilando operaciones increíblemente simples.', '[{"pregunta":"¿Con qué valores trabajan las puertas lógicas?","opciones":["De 0 a 10","0 y 1","De -100 a 100","Solo 1"],"correcta":1},{"pregunta":"¿Cuándo da 1 la puerta AND?","opciones":["Si alguna entrada es 1","Solo si todas son 1","Siempre","Nunca"],"correcta":1},{"pregunta":"¿Qué hace NOT?","opciones":["Suma","Invierte su entrada","Duplica","Divide"],"correcta":1},{"pregunta":"¿Cuál devuelve 1 si las entradas son distintas?","opciones":["AND","OR","XOR","NOT"],"correcta":2}]'::jsonb),

('tecnologia', 'eso', '{4}', 'Sistemas de Numeración', 'Los ordenadores trabajan internamente con el sistema binario, que solo usa dos dígitos: 0 y 1. Cada dígito se llama bit (binary digit) y representa el estado de un transistor: encendido o apagado. Los humanos, en cambio, usamos el sistema decimal, con diez dígitos (0 al 9). Convertir entre ambos sistemas es una habilidad básica en tecnología, porque nos ayuda a entender cómo guardan la información los dispositivos digitales.

Para representar cantidades grandes, agrupamos bits. Ocho bits forman un byte, que puede representar 256 valores distintos (de 0 a 255), suficientes para almacenar un carácter en el código ASCII. Mil bytes (más exactamente 1024) forman un kilobyte (KB), un millón un megabyte (MB), mil millones un gigabyte (GB), y un billón un terabyte (TB). Estos múltiplos son los que vemos en las especificaciones de discos duros y memorias.

Además del binario y el decimal, los programadores usan a menudo el sistema hexadecimal (base 16), que utiliza los dígitos del 0 al 9 más las letras A-F. Este sistema es útil porque cada dígito hexadecimal representa exactamente cuatro bits, simplificando la escritura de valores binarios largos. Por ejemplo, el color rojo en formato RGB se escribe #FF0000, donde cada par hexadecimal representa la intensidad de rojo, verde y azul (FF en hex equivale a 255 en decimal).', '[{"pregunta":"¿Qué dígitos usa el binario?","opciones":["0 y 1","0, 1 y 2","0 al 9","A-F"],"correcta":0},{"pregunta":"¿Cuántos bits forman un byte?","opciones":["4","8","16","32"],"correcta":1},{"pregunta":"¿Cuántos valores puede representar un byte?","opciones":["8","16","256","1000"],"correcta":2},{"pregunta":"¿Qué base tiene el hexadecimal?","opciones":["2","10","16","32"],"correcta":2}]'::jsonb),

('tecnologia', 'eso', '{4}', 'El Circuito Integrado', 'Un circuito integrado (IC), también llamado chip, es un dispositivo electrónico que contiene miles, millones o incluso miles de millones de transistores y otros componentes miniaturizados en una sola pieza de silicio. Fue inventado casi simultáneamente por Jack Kilby (Texas Instruments) y Robert Noyce (Fairchild) en 1958-1959. Su aparición marcó el inicio de la era de la microelectrónica y permitió la revolución informática posterior.

Los circuitos integrados se fabrican en "obleas" de silicio mediante un proceso llamado fotolitografía. Primero se dibuja el circuito en un ordenador, luego se proyecta la imagen sobre la oblea con luz ultravioleta, protegiendo ciertas zonas. Después se van aplicando capas de materiales conductores y aislantes, siguiendo los patrones diseñados. Cada oblea puede contener cientos de chips idénticos que se cortan y encapsulan individualmente.

Hay muchos tipos de IC. Los lógicos implementan funciones concretas, como un sumador o un contador. Los analógicos manejan señales continuas, como amplificadores operacionales. Los microprocesadores son los más complejos: contienen toda la lógica de un ordenador en un solo chip. La fabricación de chips avanzados requiere "fabs" (fábricas) de miles de millones de euros y solo unas pocas empresas en el mundo (TSMC, Samsung, Intel) pueden permitírselo. Son industrias estratégicas en la economía moderna.', '[{"pregunta":"¿Qué es un circuito integrado?","opciones":["Un cable","Chip con muchos transistores miniaturizados","Una pila","Un LED"],"correcta":1},{"pregunta":"¿En qué material se fabrica?","opciones":["Oro","Plástico","Silicio","Madera"],"correcta":2},{"pregunta":"¿Qué técnica se usa para fabricarlos?","opciones":["Impresión 3D","Fotolitografía","Soldadura","Pintura"],"correcta":1},{"pregunta":"¿Qué empresa NO fabrica chips avanzados?","opciones":["TSMC","Samsung","Intel","McDonalds"],"correcta":3}]'::jsonb),

('tecnologia', 'eso', '{4}', 'Señales Analógicas y Digitales', 'Las señales con las que trabajamos en electrónica se clasifican en dos grandes tipos: analógicas y digitales. Una señal analógica varía de forma continua en el tiempo y puede tomar infinitos valores intermedios. Por ejemplo, la voz humana captada por un micrófono es analógica: cambia suavemente en cada instante. Otras señales analógicas son la temperatura, la presión, el volumen sonoro.

Una señal digital, en cambio, solo toma valores discretos: habitualmente solo dos (0 y 1, bajo y alto), aunque también pueden existir señales digitales con más niveles. Las señales digitales no varían suavemente: saltan bruscamente entre sus valores. Los circuitos digitales procesan esta información mediante puertas lógicas y microprocesadores. Las ventajas de lo digital son: inmunidad al ruido (pequeñas perturbaciones no cambian el valor), facilidad de almacenamiento y copia exacta.

Para convertir entre ambos mundos se usan los ADC (Analog-to-Digital Converter) y los DAC (Digital-to-Analog Converter). Un micrófono capta sonido analógico, un ADC lo digitaliza, un ordenador lo procesa, un DAC lo reconvierte en analógico y un altavoz lo emite. Toda la música digital, las fotografías y los vídeos pasan por estas conversiones. Los conversores más rápidos y precisos permiten grabar audio en alta calidad e imágenes en resolución espectacular.', '[{"pregunta":"¿Qué caracteriza a una señal analógica?","opciones":["Solo dos valores","Varía continuamente","Es siempre digital","Es muy rápida"],"correcta":1},{"pregunta":"¿Qué significa ADC?","opciones":["Analog-to-Digital Converter","Audio Digital Control","Advanced Digital Chip","Any Data Code"],"correcta":0},{"pregunta":"¿Qué ventaja tiene lo digital?","opciones":["Ruido","Inmunidad al ruido y copia exacta","Baja calidad","Lento"],"correcta":1},{"pregunta":"¿Qué convierte digital a analógico?","opciones":["ADC","DAC","DAC","AAC"],"correcta":1}]'::jsonb),

('tecnologia', 'eso', '{4}', 'Neumática Básica', 'La neumática es la técnica que utiliza aire comprimido como fuente de energía para accionar mecanismos. Sus principios se conocen desde la antigüedad, pero su uso industrial masivo empezó en el siglo XIX. Hoy la neumática se emplea en miles de aplicaciones: desde los frenos de autobuses y camiones hasta los brazos robóticos de las cadenas de montaje, pasando por herramientas manuales como los martillos neumáticos.

Un sistema neumático básico consta de un compresor (genera el aire comprimido), un depósito donde se almacena, tubos y válvulas que lo distribuyen, y actuadores (cilindros, motores) que convierten el aire en movimiento. Las válvulas son el "cerebro" del sistema: controlan cuándo y hacia dónde fluye el aire. Los cilindros neumáticos son los actuadores más comunes: al recibir aire por un lado, empujan un émbolo hacia afuera, generando un movimiento lineal fuerte y rápido.

Las ventajas de la neumática son su seguridad (el aire no explota como los combustibles), su limpieza (no hay residuos líquidos), su velocidad y su facilidad de control. Los inconvenientes son el ruido que generan los compresores y las válvulas, y la menor precisión comparada con los sistemas eléctricos o hidráulicos. Para trabajos de gran fuerza, se prefiere la hidráulica (usando aceite en lugar de aire), que soporta presiones mucho más altas sin riesgo de fugas explosivas.', '[{"pregunta":"¿Qué usa la neumática como energía?","opciones":["Agua","Aire comprimido","Electricidad","Aceite"],"correcta":1},{"pregunta":"¿Qué genera el aire comprimido?","opciones":["Válvula","Compresor","Cilindro","Depósito"],"correcta":1},{"pregunta":"¿Qué actuador es el más común?","opciones":["Motor","Cilindro","Válvula","Ventilador"],"correcta":1},{"pregunta":"¿Qué ventaja destaca?","opciones":["Ruido","Limpieza y seguridad","Caro","Lento"],"correcta":1}]'::jsonb),

('tecnologia', 'eso', '{4}', 'La Fibra Óptica', 'La fibra óptica es un medio de transmisión de datos que utiliza haces de luz para llevar información a gran velocidad y larga distancia. Consiste en un hilo muy fino de vidrio purísimo (del grosor de un cabello humano) recubierto por varias capas protectoras. La luz viaja por el interior del hilo rebotando en sus paredes gracias al fenómeno de la reflexión total interna, sin apenas pérdidas.

Comparada con el cable de cobre, la fibra óptica tiene ventajas enormes. Puede transportar muchísimos más datos por segundo, es inmune a las interferencias eléctricas, pesa mucho menos y permite mayores distancias sin necesidad de amplificadores. Por eso, las redes de comunicaciones modernas (internet, telefonía, televisión) se apoyan en cables de fibra óptica submarinos y terrestres que cruzan continentes y océanos.

En España, la fibra óptica ha llegado ya a la mayoría de los hogares a través del llamado FTTH (Fiber To The Home). Una fibra óptica moderna puede transportar cientos de gigabits por segundo. Gracias a ella podemos ver Netflix en 4K, hacer videollamadas sin cortes y descargar archivos gigantes en segundos. La instalación requiere equipos especializados, pero una vez tendida dura décadas sin mantenimiento. Es una de las tecnologías clave de la era digital.', '[{"pregunta":"¿Qué transporta la fibra óptica?","opciones":["Agua","Luz con información","Sonido","Gas"],"correcta":1},{"pregunta":"¿Qué fenómeno físico usa?","opciones":["Refracción","Reflexión total interna","Difracción","Polarización"],"correcta":1},{"pregunta":"¿Cuál es una ventaja?","opciones":["Es pesada","Inmune a interferencias y muy rápida","Frágil","Dura poco"],"correcta":1},{"pregunta":"¿Qué significa FTTH?","opciones":["Full Tech Telecommunication Home","Fiber To The Home","Fast Tool","First Time"],"correcta":1}]'::jsonb),

('tecnologia', 'eso', '{4}', 'La Hidráulica', 'La hidráulica es similar a la neumática, pero usa líquidos (normalmente aceite) en lugar de aire comprimido. Gracias a que los líquidos son prácticamente incompresibles, los sistemas hidráulicos pueden transmitir fuerzas muy grandes de manera precisa y controlada. Por eso se usan en aplicaciones donde se requiere mover cargas pesadas: excavadoras, grúas, prensas industriales, frenos de coche, timones de aviones.

El principio de Pascal, formulado por Blaise Pascal en el siglo XVII, explica por qué funciona la hidráulica. Dice que la presión aplicada a un fluido encerrado se transmite por igual a todas las partes del fluido y a las paredes del recipiente. Gracias a este principio, una pequeña fuerza aplicada a un pistón pequeño puede generar una fuerza enorme en un pistón grande del mismo sistema. Es el fundamento del elevador hidráulico, capaz de levantar coches con solo una persona operándolo.

Los componentes de un sistema hidráulico son similares a los neumáticos: bomba (en lugar de compresor), depósito de aceite, válvulas, cilindros. La gran diferencia es que los sistemas hidráulicos soportan presiones de cientos de bar, frente a los 6-10 bar típicos de la neumática. Esto permite fuerzas muchísimo mayores pero también exige componentes más robustos y caros. Además, las fugas de aceite son problemáticas porque contaminan. Por eso se eligen entre neumática e hidráulica según el tipo de aplicación.', '[{"pregunta":"¿Qué usa la hidráulica?","opciones":["Aire","Líquidos como aceite","Electricidad","Vapor"],"correcta":1},{"pregunta":"¿Quién formuló su principio?","opciones":["Pascal","Newton","Galileo","Arquímedes"],"correcta":0},{"pregunta":"¿Cuál es su ventaja?","opciones":["Baja fuerza","Transmite grandes fuerzas con precisión","Es ruidosa","Contamina"],"correcta":1},{"pregunta":"¿Qué puede soportar?","opciones":["Poca presión","Cientos de bar","10 bar","Nada"],"correcta":1}]'::jsonb),

('tecnologia', 'eso', '{4}', 'Control Automático', 'El control automático es la rama de la ingeniería que estudia cómo mantener las variables de un sistema (temperatura, presión, velocidad, posición) en los valores deseados sin intervención humana constante. Su ejemplo más conocido es el termostato de la calefacción: detecta la temperatura ambiente y enciende o apaga la caldera para mantenerla cerca de la consigna. Es un sistema de control automático simple pero eficaz.

Los sistemas de control pueden ser de lazo abierto o lazo cerrado. En el lazo abierto, la salida no influye en la entrada: el sistema hace lo que se le ha dicho sin comprobar los resultados. Un temporizador que enciende una lavadora durante 30 minutos es de lazo abierto: no sabe si la ropa está limpia o no. En el lazo cerrado, hay un sensor que informa continuamente del estado del sistema, y un controlador ajusta las acciones en función de esa información. El termostato es de lazo cerrado.

Los sistemas de control modernos usan algoritmos sofisticados como el PID (Proporcional-Integral-Derivativo), que compensa el error actual, acumulado y predicho. El PID es muy popular en robótica, automoción, procesos químicos y aeronáutica. Aprender teoría de control requiere matemáticas avanzadas, pero los conceptos básicos (realimentación, consigna, error) se enseñan ya en Tecnología de 4º de ESO y son fundamentales para cualquier ingeniero.', '[{"pregunta":"¿Qué es un sistema de lazo cerrado?","opciones":["Sin sensor","Con sensor que ajusta la salida","Muy rápido","Sin controlador"],"correcta":1},{"pregunta":"¿Qué ejemplo es de lazo abierto?","opciones":["Termostato","Temporizador de lavadora","Croquera","Coche autónomo"],"correcta":1},{"pregunta":"¿Qué significa PID?","opciones":["Perfect Internet Device","Proporcional-Integral-Derivativo","Pipe Indoor Data","Post-Industrial Digital"],"correcta":1},{"pregunta":"¿Qué mantiene el termostato?","opciones":["Velocidad","Presión","Temperatura","Luz"],"correcta":2}]'::jsonb),

('tecnologia', 'eso', '{4}', 'Instalaciones en la Vivienda', 'Una vivienda moderna requiere varias instalaciones técnicas para funcionar correctamente: electricidad, agua, gas, telecomunicaciones, calefacción y saneamiento. Cada una sigue unas normas constructivas que garantizan seguridad y eficiencia. Conocerlas, aunque sea a nivel básico, es útil para cualquier ciudadano, porque en cualquier momento podemos necesitar hacer una reforma o detectar un problema.

La instalación eléctrica llega desde el contador general hasta cada enchufe y lámpara. Incluye un cuadro eléctrico con interruptores diferenciales (para detectar fugas) y magnetotérmicos (para cortar la corriente si se supera la carga máxima, evitando incendios). El tendido usa cables aislados que van por tubos empotrados en la pared. Existe una normativa estricta, el REBT, que todo electricista debe conocer y cumplir.

La instalación de fontanería suministra agua fría y caliente a baños, cocina y electrodomésticos, y recoge las aguas residuales con tuberías de desagüe. El saneamiento conecta con la red de alcantarillado municipal o con una fosa séptica en zonas rurales. Las instalaciones de gas son delicadas: las fugas pueden causar intoxicaciones o explosiones, por lo que deben ser realizadas y mantenidas por profesionales certificados. Las telecomunicaciones incluyen cables para internet, teléfono y antenas de TV. Todo este entramado, invisible tras las paredes, es lo que hace habitables nuestras casas.', '[{"pregunta":"¿Qué detecta el interruptor diferencial?","opciones":["Cortes","Fugas a tierra","Temperaturas","Ruidos"],"correcta":1},{"pregunta":"¿Qué es el REBT?","opciones":["Reglamento Eléctrico de Baja Tensión","Red Eléctrica Básica","Revisión Eléctrica Total","Registro Europeo"],"correcta":0},{"pregunta":"¿Quién debe instalar gas?","opciones":["Cualquiera","Profesionales certificados","Los bomberos","Los vecinos"],"correcta":1},{"pregunta":"¿Qué hace un magnetotérmico?","opciones":["Mide calor","Corta si hay sobrecarga","Filtra agua","Amplifica la señal"],"correcta":1}]'::jsonb);

